const s = (obj) => ({ style: obj });
const sx = (base, extra) => ({ style: { ...base, ...extra } });

function Badge({ children, color = T.muted, bg = T.subtle }) {
  return <span style={{ display:"inline-flex", alignItems:"center", padding:"2px 9px", borderRadius:20, fontSize:11, fontWeight:500, color, background:bg }}>{children}</span>;
}

function Btn({ children, onClick, variant="default", small, style:st }) {
  const base = { display:"inline-flex", alignItems:"center", justifyContent:"center", gap:5, padding: small?"5px 11px":"8px 16px", borderRadius:8, fontSize: small?11:13, fontWeight:500, cursor:"pointer", border:"none", transition:"all 0.15s" };
  const v = { default:{background:T.card,color:T.text,border:`1px solid ${T.border}`}, primary:{background:T.brand,color:"#fff",border:"none"}, danger:{background:T.dangerDim,color:T.danger,border:`1px solid rgba(239,68,68,0.2)`}, ghost:{background:"transparent",color:T.muted,border:`1px solid ${T.border}`} };
  return <button onClick={onClick} style={{ ...base, ...v[variant], ...st }}>{children}</button>;
}

function Inp({ label, value, onChange, type="text", placeholder }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
      {label && <label style={{ fontSize:11, color:T.muted, fontWeight:500 }}>{label}</label>}
      <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
        style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:13, outline:"none" }} />
    </div>
  );
}

function Sel({ label, value, onChange, options }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
      {label && <label style={{ fontSize:11, color:T.muted, fontWeight:500 }}>{label}</label>}
      <select value={value} onChange={e=>onChange(e.target.value)}
        style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:13, outline:"none" }}>
        {options.map(o=><option key={o.value||o} value={o.value||o}>{o.label||o}</option>)}
      </select>
    </div>
  );
}

function Card({ children, style:st }) {
  return <div style={{ background:T.card, border:`1px solid ${T.border}`, borderRadius:12, padding:"16px 20px", ...st }}>{children}</div>;
}

function InfoCard({ label, value, sub, color, bg, tip }) {
  const [show, setShow] = React.useState(false);
  return (
    <div style={{ background:bg, border:`1px solid ${color}33`, borderRadius:10, padding:"12px 14px", position:"relative" }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:4 }}>
        <div style={{ fontSize:10, color, fontWeight:700, flex:1, paddingRight:4 }}>{label.toUpperCase()}</div>
        <button onMouseEnter={()=>setShow(true)} onMouseLeave={()=>setShow(false)}
          style={{ background:"none", border:`1px solid ${color}44`, borderRadius:"50%", width:16, height:16, color, cursor:"pointer", fontSize:10, fontWeight:800, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>?</button>
      </div>
      <div style={{ fontSize:18, fontWeight:900, color:T.text }}>{value}</div>
      <div style={{ fontSize:11, color:T.muted, marginTop:2 }}>{sub}</div>
      {show && (
        <div style={{ position:"absolute", top:"calc(100% + 6px)", left:0, right:0, background:T.surface, border:`1px solid ${T.borderStrong}`, borderRadius:9, padding:"9px 12px", zIndex:200, boxShadow:"0 8px 24px rgba(0,0,0,0.5)", fontSize:11, color:T.text, lineHeight:1.5 }}>
          {tip}
          <div style={{ position:"absolute", top:-5, left:14, width:8, height:8, background:T.surface, border:`1px solid ${T.borderStrong}`, borderBottom:"none", borderRight:"none", transform:"rotate(45deg)" }} />
        </div>
      )}
    </div>
  );
}

function Modal({ open, onClose, title, children }) {
  if (!open) return null;
  return (
    <div style={{ position:"fixed", inset:0, zIndex:500, background:"rgba(0,0,0,0.75)", display:"flex", alignItems:"center", justifyContent:"center" }} onClick={onClose}>
      <div style={{ background:T.surface, border:`1px solid ${T.borderStrong}`, borderRadius:14, padding:24, width:440, maxWidth:"90vw", maxHeight:"85vh", overflowY:"auto" }} onClick={e=>e.stopPropagation()}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
          <h3 style={{ color:T.text, fontSize:15, fontWeight:700, margin:0 }}>{title}</h3>
          <button onClick={onClose} style={{ background:"none", border:"none", color:T.muted, cursor:"pointer", fontSize:22, lineHeight:1 }}>×</button>
        </div>
        {children}
      </div>
    </div>
  );
}

function THead({ cols }) {
  return <thead><tr style={{ borderBottom:`1px solid ${T.border}` }}>{cols.map(h=><th key={h} style={{ padding:"10px 14px", textAlign:"left", fontSize:11, color:T.muted, fontWeight:500, background:T.surface, whiteSpace:"nowrap" }}>{h}</th>)}</tr></thead>;
}

function SearchBar({ value, onChange, placeholder="Qidirish..." }) {
  return (
    <div style={{ display:"flex", alignItems:"center", gap:8, background:T.card, border:`1px solid ${T.border}`, borderRadius:8, padding:"7px 12px", width:200 }}>
      <svg width="12" height="12" viewBox="0 0 16 16" fill="none"><circle cx="6.5" cy="6.5" r="5" stroke={T.muted} strokeWidth="1.5"/><line x1="10.5" y1="10.5" x2="14" y2="14" stroke={T.muted} strokeWidth="1.5" strokeLinecap="round"/></svg>
      <input value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
        style={{ background:"none", border:"none", outline:"none", color:T.text, fontSize:13, width:"100%" }} />
    </div>
  );
}

// ── DASHBOARD ──────────────────────────────────────────────────────────────────


function Dashboard({ parts, setParts, repairs, setRepairs, accessories, setAccessories, sales, setSales, losses, setLosses, debts, setDebts, incomes, setIncomes, setPage }) {
  const [dPeriod, setDPeriod] = useState("oy");
  const [aiOpen, setAiOpen] = useState(false);

  const now = new Date();
  const hr = now.getHours();
  const greetingText = hr<12 ? "Xayrli ertalab" : hr<17 ? "Xayrli kun" : "Xayrli kech";

  const getBounds = function(p) {
    var n=new Date(); n.setHours(0,0,0,0);
    if(p==="bugun") return {s:new Date(n),e:new Date(n.getFullYear(),n.getMonth(),n.getDate(),23,59,59)};
    if(p==="hafta") {var s2=new Date(n);s2.setDate(s2.getDate()-7);return {s:s2,e:new Date()};}
    return {s:new Date(n.getFullYear(),n.getMonth(),1),e:new Date(n.getFullYear(),n.getMonth()+1,0,23,59,59)};
  };
  const getPrevBounds = function(p) {
    var n=new Date(); n.setHours(0,0,0,0);
    if(p==="bugun") {var s=new Date(n);s.setDate(s.getDate()-1);var e2=new Date(s);e2.setHours(23,59,59);return {s,e:e2};}
    if(p==="hafta") {var e3=new Date(n);e3.setDate(e3.getDate()-7);var s3=new Date(e3);s3.setDate(s3.getDate()-7);return {s:s3,e:e3};}
    return {s:new Date(n.getFullYear(),n.getMonth()-1,1),e:new Date(n.getFullYear(),n.getMonth(),0,23,59,59)};
  };
  const inB = function(d,b) {var dt=new Date(d||today());return dt>=b.s&&dt<=b.e;};
  var bnd=getBounds(dPeriod), pbnd=getPrevBounds(dPeriod);

  const calc = function(b) {
    var rInc=repairs.filter(function(r){return (r.status==="Tayyor"||r.status==="Berildi")&&inB(r.date,b);}).reduce(function(a,r){return a+(r.laborPrice||0);},0);
    var sP=sales.filter(function(s){return s.qty>0&&inB(s.date,b);}).reduce(function(a,x){return a+(x.profit||0);},0);
    var mI=incomes.filter(function(x){return inB(x.date,b);}).reduce(function(a,x){return a+(x.amount||0);},0);
    var tot=rInc+sP+mI;
    var loss=losses.filter(function(l){return inB(l.date,b);}).reduce(function(a,l){return a+(l.amount||0);},0);
    var sc=sales.filter(function(s){return s.qty>0&&inB(s.date,b);}).length;
    var rc=repairs.filter(function(r){return inB(r.date,b);}).length;
    return {rInc,sP,mI,tot,loss,net:tot-loss,sc,rc};
  };
  var cur=calc(bnd), prev=calc(pbnd);
  var pLabel=dPeriod==="bugun"?"Bugun":dPeriod==="hafta"?"Hafta":"Bu oy";

  var pct=function(c,p){return p!==0?Math.round(((c-p)/Math.abs(p))*100):null;};

  // 30-day trend
  var trend30=[];
  for(var ti=0;ti<30;ti++){
    var td=new Date(); td.setDate(td.getDate()-(29-ti)); td.setHours(0,0,0,0);
    var te=new Date(td); te.setHours(23,59,59);
    var tb={s:td,e:te};
    var trI=repairs.filter(function(r){return (r.status==="Tayyor"||r.status==="Berildi")&&inB(r.date,tb);}).reduce(function(a,r){return a+(r.laborPrice||0);},0);
    var tsP=sales.filter(function(s){return s.qty>0&&inB(s.date,tb);}).reduce(function(a,x){return a+(x.profit||0);},0);
    var tmI=incomes.filter(function(x){return inB(x.date,tb);}).reduce(function(a,x){return a+(x.amount||0);},0);
    var tl=losses.filter(function(x){return inB(x.date,tb);}).reduce(function(a,x){return a+(x.amount||0);},0);
    trend30.push({day:td.getDate(),net:Math.round((trI+tsP+tmI-tl)/1000)});
  }

  // Funnel
  var fQabul=repairs.filter(function(r){return r.status==="Qabul qilindi";}).length;
  var fRemontda=repairs.filter(function(r){return r.status==="Remontda";}).length;
  var fTayyor=repairs.filter(function(r){return r.status==="Tayyor";}).length;
  var fBerildi=repairs.filter(function(r){return r.status==="Berildi";}).length;
  var fTotal=repairs.length||1;
  var fConv=Math.round(fBerildi/fTotal*100);
  var fUzoq=repairs.filter(function(r){return r.status!=="Berildi"&&r.date&&Math.floor((Date.now()-new Date(r.date))/(1000*86400))>7;}).length;
  var activeRepairs=repairs.filter(function(r){return r.status!=="Berildi";}).sort(function(a,b){var ord=["Tayyor","Remontda","Qabul qilindi"];return ord.indexOf(a.status)-ord.indexOf(b.status);});

  // Inventory
  var allItems=[].concat(parts,accessories);
  var everSold=new Set(sales.filter(function(s){return s.qty>0;}).map(function(s){return s.name;}));
  var critItems=allItems.filter(function(p){return p.count===0;});
  var lowItems=allItems.filter(function(p){return p.count>0&&p.count<=5;}).sort(function(a,b){return a.count-b.count;});
  var deadItems=allItems.filter(function(p){return p.count>0&&!everSold.has(p.name);});

  // Ustalar
  var ustaRecs=[]; try{ustaRecs=JSON.parse(localStorage.getItem("shox_ustaRecords")||"[]");}catch(e){}
  var ustaMap={};
  ustaRecs.forEach(function(r){if(!ustaMap[r.ustaName])ustaMap[r.ustaName]=0;ustaMap[r.ustaName]+=(r.price*r.qty||0);});
  ustaRecs.forEach(function(r){if(r.partialPaid&&ustaMap[r.ustaName])ustaMap[r.ustaName]-=r.partialPaid;});
  var ustaKutuvda=Object.entries(ustaMap).filter(function(x){return x[1]>0;}).sort(function(a,b){return b[1]-a[1];});
  var totalUstaK=ustaKutuvda.reduce(function(a,x){return a+x[1];},0);

  // Debts
  var debtsMijoz=debts.filter(function(d){return d.type==="Mijoz";});
  var debtsYetk=debts.filter(function(d){return d.type!=="Mijoz";});
  var overdueDebts=debts.filter(function(d){return d.dueDate&&d.dueDate<today();});
  var netDebt=debtsMijoz.reduce(function(a,d){return a+(d.amount||0);},0)-debtsYetk.reduce(function(a,d){return a+(d.amount||0);},0);

  // To-Do
  var todos=[];
  critItems.forEach(function(p){
    var ms=sales.filter(function(s){return s.qty>0&&s.name===p.name&&new Date(s.date).getMonth()===now.getMonth();}).reduce(function(a,s){return a+s.qty;},0);
    if(ms>0) todos.push({level:"critical",icon:"1",text:p.name+" tugadi - bu oy "+ms+" ta sotilgan",action:"zapchastlar"});
  });
  var tayyor=repairs.filter(function(r){return r.status==="Tayyor";});
  if(tayyor.length>0) todos.push({level:"success",icon:"2",text:tayyor.length+" ta remont tayyor - mijozga xabar bering",action:"remont"});
  if(fUzoq>0) todos.push({level:"warning",icon:"3",text:fUzoq+" ta remont 7+ kun kutmoqda - tekshiring",action:"remont"});
  if(overdueDebts.length>0) todos.push({level:"critical",icon:"4",text:overdueDebts.length+" ta qarz muddati otdi - "+fmt(overdueDebts.reduce(function(a,d){return a+(d.amount||0);},0))+" som",action:"qarzlar"});
  if(deadItems.length>0){var dv=deadItems.reduce(function(a,p){return a+(p.buyPrice||0)*p.count;},0);if(dv>0)todos.push({level:"info",icon:"5",text:"Dead stock: "+fmt(dv)+" som boylab yotibdi",action:"zapchastlar"});}
  if(cur.net>prev.net&&prev.net>0){var pp=Math.round((cur.net-prev.net)/Math.abs(prev.net)*100);todos.push({level:"success",icon:"6",text:"Foyda otgan davrdan "+pp+"% yuqori - zor natija!",action:""});}
  todos=todos.slice(0,6);

  var stockColor=function(c){return c===0?T.danger:c<=5?T.warning:T.success;};
  var todayCalc=calc(getBounds("bugun"));

  return (
    <div style={{display:"flex",gap:16,height:"100%",position:"relative"}}>
      <div style={{flex:1,display:"flex",flexDirection:"column",gap:12,minWidth:0,overflowY:"auto",paddingBottom:20}}>

        {/* Salom + davr */}
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
          <div>
            <div style={{fontSize:18,fontWeight:900,color:T.text}}>{greetingText}</div>
            <div style={{fontSize:12,color:T.muted,marginTop:2}}>
              {now.toLocaleDateString("uz-UZ",{weekday:"long",year:"numeric",month:"long",day:"numeric"})}
            </div>
          </div>
          <div style={{display:"flex",gap:6,alignItems:"center"}}>
            {["bugun","hafta","oy"].map(function(p){return (
              <button key={p} onClick={function(){setDPeriod(p);}}
                style={{padding:"6px 14px",borderRadius:8,fontSize:11,cursor:"pointer",fontWeight:dPeriod===p?700:400,background:dPeriod===p?T.brand:T.card,color:dPeriod===p?"#fff":T.muted,border:"1px solid "+(dPeriod===p?T.brand:T.border)}}>
                {p==="bugun"?"Bugun":p==="hafta"?"Hafta":"Bu oy"}
              </button>
            );})}
            {todos.filter(function(t){return t.level==="critical";}).length>0&&(
              <div style={{padding:"6px 12px",borderRadius:8,background:T.dangerDim,border:"1px solid "+T.danger+"44",fontSize:11,color:T.danger,fontWeight:700}}>
                {todos.filter(function(t){return t.level==="critical";}).length+" ta kritik"}
              </div>
            )}
          </div>
        </div>

        {/* KPI */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10}}>
          {[
            {l:"Sof foyda",v:cur.net,pv:prev.net,c:cur.net>=0?T.success:T.danger,bg:cur.net>=0?T.successDim:T.dangerDim,fmt:true},
            {l:"Jami daromad",v:cur.tot,pv:prev.tot,c:T.brand,bg:T.brandDim,fmt:true},
            {l:"Savdo soni",v:cur.sc,pv:prev.sc,c:T.info,bg:T.infoDim,fmt:false,u:"ta"},
            {l:"Remont soni",v:cur.rc,pv:prev.rc,c:T.warning,bg:T.warningDim,fmt:false,u:"ta"},
          ].map(function(c,i){
            var chng=pct(c.v,c.pv);
            var up=chng!=null&&chng>=0;
            return (
              <div key={i} style={{background:c.bg,border:"1px solid "+c.c+"33",borderRadius:12,padding:"13px 16px"}}>
                <div style={{fontSize:9,color:c.c,fontWeight:700,marginBottom:3}}>{c.l.toUpperCase()+" - "+pLabel.toUpperCase()}</div>
                <div style={{fontSize:20,fontWeight:900,color:T.text,marginBottom:4}}>
                  {c.fmt?fmt(c.v):c.v}<span style={{fontSize:10,color:T.muted,marginLeft:3}}>{c.u||"som"}</span>
                </div>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  {chng!=null&&<span style={{fontSize:11,fontWeight:700,color:up?T.success:T.danger}}>{up?"+":""}{chng}% {up?"↑":"↓"}</span>}
                  <span style={{fontSize:10,color:T.muted}}>{"otgan: "+(c.fmt?fmt(c.pv):c.pv)+(c.u?" "+c.u:"")}</span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Remont Funnel + 30 kun trend */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <Card style={{padding:"14px 16px"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
              <div style={{fontSize:12,fontWeight:700,color:T.text}}>Remont jarayoni</div>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <span style={{fontSize:11,color:T.muted}}>Konversiya:</span>
                <span style={{fontSize:13,fontWeight:800,color:fConv>=70?T.success:fConv>=50?T.warning:T.danger}}>{fConv+"%"}</span>
                <button onClick={function(){setPage("remont");}} style={{background:"none",border:"none",color:T.brand,fontSize:11,cursor:"pointer",fontWeight:600}}>{"Ko'rish"}</button>
              </div>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:12}}>
              {[
                {l:"Qabul",v:fQabul,c:T.muted},
                {arr:true},
                {l:"Remontda",v:fRemontda,c:T.brand},
                {arr:true},
                {l:"Tayyor",v:fTayyor,c:T.success},
                {arr:true},
                {l:"Berildi",v:fBerildi,c:T.info},
              ].map(function(step,i){
                if(step.arr) return <div key={i} style={{color:T.border,fontSize:16}}>{">"}</div>;
                return (
                  <div key={i} style={{flex:1,textAlign:"center",padding:"8px 4px",background:step.v>0?step.c+"18":T.surface,borderRadius:9,border:"1px solid "+(step.v>0?step.c+"44":T.border)}}>
                    <div style={{fontSize:14,fontWeight:900,color:step.v>0?step.c:T.muted}}>{step.v}</div>
                    <div style={{fontSize:9,color:T.muted}}>{step.l}</div>
                  </div>
                );
              })}
            </div>
            {fUzoq>0&&<div style={{padding:"6px 10px",background:T.warningDim,border:"1px solid "+T.warning+"44",borderRadius:8,fontSize:11,color:T.warning,fontWeight:600,marginBottom:8}}>{fUzoq+" ta remont 7+ kun kutmoqda"}</div>}
            <div style={{display:"flex",flexDirection:"column",gap:5}}>
              {activeRepairs.slice(0,4).map(function(r){
                var sc2=r.status==="Tayyor"?T.success:r.status==="Remontda"?T.brand:T.muted;
                var days=r.date?Math.round((Date.now()-new Date(r.date))/(1000*86400)):0;
                return (
                  <div key={r.id} style={{display:"flex",alignItems:"center",gap:8,padding:"5px 8px",background:T.surface,borderRadius:7}}>
                    <div style={{width:6,height:6,borderRadius:"50%",background:sc2,flexShrink:0}}/>
                    <span style={{flex:1,fontSize:11,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.model}</span>
                    <span style={{fontSize:10,color:T.muted,flexShrink:0}}>{days+"k"}</span>
                    <span style={{fontSize:10,fontWeight:700,color:sc2,flexShrink:0}}>{fmt(r.laborPrice||0)}</span>
                  </div>
                );
              })}
              {activeRepairs.length===0&&<div style={{color:T.success,fontSize:11,textAlign:"center",padding:8}}>Barcha remontlar berildi!</div>}
            </div>
          </Card>

          <Card style={{padding:"14px 16px"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
              <div style={{fontSize:12,fontWeight:700,color:T.text}}>30 kunlik foyda trendi</div>
              <div style={{fontSize:12,fontWeight:900,color:todayCalc.net>=0?T.success:T.danger}}>{"Bugun: "+fmt(todayCalc.net)}</div>
            </div>
            <ResponsiveContainer width="100%" height={140}>
              <AreaChart data={trend30} margin={{top:4,right:0,left:-30,bottom:0}}>
                <defs>
                  <linearGradient id="tGrad" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor={T.success} stopOpacity={0.4}/>
                    <stop offset="95%" stopColor={T.success} stopOpacity={0.02}/>
                  </linearGradient>
                </defs>
                <XAxis dataKey="day" tick={{fill:T.muted,fontSize:9}} axisLine={false} tickLine={false} interval={9}/>
                <YAxis tick={{fill:T.muted,fontSize:8}} axisLine={false} tickLine={false}/>
                <Tooltip contentStyle={{background:T.card,border:"1px solid "+T.border,borderRadius:8,fontSize:10}} formatter={function(v){return [v+"K som","Foyda"];}}/>
                <Area type="monotone" dataKey="net" stroke={T.success} strokeWidth={2} fill="url(#tGrad)" dot={false}/>
              </AreaChart>
            </ResponsiveContainer>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6,marginTop:8}}>
              {[
                {l:"O'rtacha/kun",v:fmt(Math.round(trend30.reduce(function(a,d){return a+d.net;},0)/30))+"K",c:T.muted},
                {l:"Eng yaxshi",v:fmt(Math.max.apply(null,trend30.map(function(d){return d.net;})))+"K",c:T.success},
                {l:"Eng yomon",v:fmt(Math.min.apply(null,trend30.map(function(d){return d.net;})))+"K",c:T.danger},
              ].map(function(x,i){return (
                <div key={i} style={{background:T.surface,borderRadius:7,padding:"5px 8px",textAlign:"center"}}>
                  <div style={{fontSize:9,color:T.muted,marginBottom:2}}>{x.l}</div>
                  <div style={{fontSize:11,fontWeight:700,color:x.c}}>{x.v}</div>
                </div>
              );})}
            </div>
          </Card>
        </div>

        {/* To-Do + Qarzlar + Ustalar */}
        <div style={{display:"grid",gridTemplateColumns:"1.3fr 1fr 1fr",gap:12}}>
          <Card style={{padding:"14px 16px"}}>
            <div style={{fontSize:12,fontWeight:700,color:T.text,marginBottom:10}}>Bugun etiborga oling</div>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {todos.length===0&&<div style={{color:T.success,fontSize:12,textAlign:"center",padding:16}}>Hamma narsa joyida!</div>}
              {todos.map(function(t,i){
                var c=t.level==="critical"?T.danger:t.level==="warning"?T.warning:t.level==="success"?T.success:T.brand;
                var bg=t.level==="critical"?T.dangerDim:t.level==="warning"?T.warningDim:t.level==="success"?T.successDim:T.brandDim;
                return (
                  <div key={i} onClick={function(){if(t.action)setPage(t.action);}}
                    style={{display:"flex",alignItems:"flex-start",gap:8,padding:"8px 10px",background:bg,border:"1px solid "+c+"33",borderRadius:9,cursor:t.action?"pointer":"default"}}>
                    <span style={{flex:1,fontSize:11,color:T.muted,lineHeight:1.5}}>{t.text}</span>
                    {t.action&&<span style={{fontSize:10,color:c,flexShrink:0,fontWeight:700}}>{">"}</span>}
                  </div>
                );
              })}
            </div>
          </Card>

          <Card style={{padding:"14px 16px"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
              <div style={{fontSize:12,fontWeight:700,color:T.text}}>Qarzlar holati</div>
              <button onClick={function(){setPage("qarzlar");}} style={{background:"none",border:"none",color:T.brand,fontSize:11,cursor:"pointer",fontWeight:600}}>{">"}</button>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
              <div style={{background:T.successDim,borderRadius:9,padding:"8px 10px"}}>
                <div style={{fontSize:9,color:T.success,fontWeight:700,marginBottom:2}}>BIZDAN QARZ</div>
                <div style={{fontSize:14,fontWeight:900,color:T.text}}>{fmt(debtsMijoz.reduce(function(a,d){return a+(d.amount||0);},0))}</div>
                <div style={{fontSize:10,color:T.muted}}>{debtsMijoz.length+" ta"}</div>
              </div>
              <div style={{background:T.dangerDim,borderRadius:9,padding:"8px 10px"}}>
                <div style={{fontSize:9,color:T.danger,fontWeight:700,marginBottom:2}}>BIZ QARZ</div>
                <div style={{fontSize:14,fontWeight:900,color:T.text}}>{fmt(debtsYetk.reduce(function(a,d){return a+(d.amount||0);},0))}</div>
                <div style={{fontSize:10,color:T.muted}}>{debtsYetk.length+" ta"}</div>
              </div>
            </div>
            <div style={{padding:"7px 10px",background:netDebt>=0?T.successDim:T.dangerDim,borderRadius:8,marginBottom:8,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{fontSize:11,color:T.muted}}>Net balans</span>
              <span style={{fontSize:13,fontWeight:800,color:netDebt>=0?T.success:T.danger}}>{(netDebt>=0?"+":"")+fmt(netDebt)}</span>
            </div>
            {overdueDebts.length>0&&overdueDebts.slice(0,2).map(function(d){return (
              <div key={d.id} style={{display:"flex",justifyContent:"space-between",padding:"4px 0",borderBottom:"1px solid "+T.border,fontSize:11}}>
                <span style={{color:T.text}}>{d.name}</span>
                <span style={{color:T.danger,fontWeight:700}}>{fmt(d.amount)}</span>
              </div>
            );})}
            {overdueDebts.length===0&&<div style={{fontSize:11,color:T.success}}>Muddati otgan qarz yoq</div>}
          </Card>

          <Card style={{padding:"14px 16px"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
              <div style={{fontSize:12,fontWeight:700,color:T.text}}>Ustalar kutuvda</div>
              <button onClick={function(){setPage("ustalar");}} style={{background:"none",border:"none",color:T.brand,fontSize:11,cursor:"pointer",fontWeight:600}}>{">"}</button>
            </div>
            {ustaKutuvda.length===0?(
              <div style={{color:T.success,fontSize:11,textAlign:"center",padding:"12px 0"}}>Hamma hisob-kitob qilingan</div>
            ):(
              <div>
                <div style={{background:T.warningDim,borderRadius:9,padding:"8px 10px",marginBottom:10,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <span style={{fontSize:11,color:T.muted}}>Jami kutuvda</span>
                  <span style={{fontSize:15,fontWeight:900,color:T.warning}}>{fmt(totalUstaK)}</span>
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:5}}>
                  {ustaKutuvda.slice(0,4).map(function(uk){return (
                    <div key={uk[0]} style={{display:"flex",alignItems:"center",gap:8,padding:"5px 8px",background:T.surface,borderRadius:7}}>
                      <div style={{width:26,height:26,borderRadius:7,background:T.brand,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:800,color:"#fff",flexShrink:0}}>{(uk[0][0]||"?").toUpperCase()}</div>
                      <span style={{flex:1,fontSize:11,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{uk[0]}</span>
                      <span style={{fontSize:12,fontWeight:700,color:T.warning,flexShrink:0}}>{fmt(uk[1])}</span>
                    </div>
                  );})}
                </div>
              </div>
            )}
          </Card>
        </div>

        {/* Inventar + Tezkor harakatlar */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <Card style={{padding:"14px 16px"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
              <div style={{fontSize:12,fontWeight:700,color:T.text}}>Inventar holati</div>
              <button onClick={function(){setPage("zapchastlar");}} style={{background:"none",border:"none",color:T.brand,fontSize:11,cursor:"pointer",fontWeight:600}}>{">"}</button>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:6,marginBottom:10}}>
              {[
                {l:"Jami",v:(parts.length+accessories.length)+"xil",c:T.brand},
                {l:"Tugdi",v:critItems.length+" ta",c:critItems.length>0?T.danger:T.success},
                {l:"Kam",v:lowItems.length+" ta",c:lowItems.length>0?T.warning:T.success},
                {l:"Dead",v:deadItems.length+" ta",c:deadItems.length>0?T.warning:T.success},
              ].map(function(x,i){return (
                <div key={i} style={{background:T.surface,borderRadius:7,padding:"6px 8px",textAlign:"center"}}>
                  <div style={{fontSize:13,fontWeight:900,color:x.c}}>{x.v}</div>
                  <div style={{fontSize:9,color:T.muted}}>{x.l}</div>
                </div>
              );})}
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:4}}>
              {[].concat(critItems.slice(0,3),lowItems.slice(0,3)).slice(0,5).map(function(p){return (
                <div key={p.id} style={{display:"flex",alignItems:"center",gap:8,padding:"5px 8px",background:T.surface,borderRadius:7}}>
                  <div style={{width:7,height:7,borderRadius:"50%",background:stockColor(p.count),flexShrink:0}}/>
                  <span style={{flex:1,fontSize:11,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.name}</span>
                  <span style={{fontSize:11,fontWeight:800,color:stockColor(p.count)}}>{p.count+" ta"}</span>
                </div>
              );})}
              {critItems.length===0&&lowItems.length===0&&<div style={{color:T.success,fontSize:11,textAlign:"center",padding:8}}>Inventar optimal!</div>}
            </div>
          </Card>

          <Card style={{padding:"14px 16px"}}>
            <div style={{fontSize:12,fontWeight:700,color:T.text,marginBottom:10}}>Tezkor harakatlar</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
              {[
                {icon:"Remont",l:"Remont qabul",desc:"Yangi remont",page:"remont",c:T.brand,bg:T.brandDim},
                {icon:"Tovar",l:"Tovar qoshish",desc:"Inventarga",page:"zapchastlar",c:T.success,bg:T.successDim},
                {icon:"Qarz",l:"Qarz qoshish",desc:"Yangi qarz",page:"qarzlar",c:T.warning,bg:T.warningDim},
                {icon:"Usta",l:"Usta tovar",desc:"Ustaga berish",page:"ustalar",c:T.info,bg:T.infoDim},
                {icon:"Daromad",l:"Daromad",desc:"Daromad qoshish",page:"moliya",c:T.success,bg:T.successDim},
                {icon:"Stat",l:"Statistika",desc:"Batafsil tahlil",page:"statistika",c:"#8B5CF6",bg:"rgba(139,92,246,0.12)"},
              ].map(function(a){return (
                <button key={a.page} onClick={function(){setPage(a.page);}}
                  style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px",background:a.bg,border:"1px solid "+a.c+"33",borderRadius:10,cursor:"pointer",textAlign:"left"}}>
                  <div>
                    <div style={{fontSize:11,fontWeight:700,color:a.c}}>{a.l}</div>
                    <div style={{fontSize:9,color:T.muted}}>{a.desc}</div>
                  </div>
                </button>
              );})}
            </div>
          </Card>
        </div>

      </div>

      {aiOpen?(
        <div style={{width:400,flexShrink:0,height:"100%",overflow:"hidden",borderLeft:"1px solid "+T.border}}>
          <ShoxAI parts={parts} setParts={setParts} repairs={repairs} setRepairs={setRepairs}
            accessories={accessories} setAccessories={setAccessories}
            sales={sales} setSales={setSales} losses={losses} setLosses={setLosses}
            debts={debts} setDebts={setDebts} incomes={incomes} setIncomes={setIncomes}
            onClose={function(){setAiOpen(false);}} setPage={setPage}/>
        </div>
      ):(
        <button onClick={function(){setAiOpen(true);}}
          style={{position:"fixed",right:0,top:"50%",transform:"translateY(-50%)",
            background:T.brand,border:"none",color:"#fff",padding:"12px 6px",
            borderRadius:"10px 0 0 10px",cursor:"pointer",display:"flex",flexDirection:"column",
            alignItems:"center",gap:4,zIndex:100,boxShadow:"-2px 0 12px rgba(26,111,212,0.4)"}}>
          <span style={{fontSize:18,fontWeight:900}}>{"AI"}</span>
        </button>
      )}
    </div>
  );
}

function ConfirmDelete({ open, onClose, onConfirm, itemName }) {
  if (!open) return null;
  return (
    <div style={{ position:"fixed", inset:0, zIndex:600, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center" }}>
      <div style={{ background:T.surface, border:`1px solid rgba(239,68,68,0.3)`, borderRadius:16, padding:28, width:360, textAlign:"center" }}>
        <div style={{ width:52, height:52, borderRadius:"50%", background:T.dangerDim, border:`1.5px solid rgba(239,68,68,0.35)`, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 16px" }}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={T.danger} strokeWidth="2" strokeLinecap="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4h6v2"/></svg>
        </div>
        <div style={{ fontSize:15, fontWeight:700, color:T.text, marginBottom:8 }}>O’chirishni tasdiqlang</div>
        <div style={{ fontSize:13, color:T.muted, marginBottom:6 }}>Quyidagi zapchast o’chiriladi:</div>
        <div style={{ fontSize:14, fontWeight:600, color:T.danger, background:T.dangerDim, padding:"8px 16px", borderRadius:8, marginBottom:20 }}>«{itemName}»</div>
        <div style={{ fontSize:12, color:T.muted, marginBottom:22 }}>Bu amalni qaytarib bo’lmaydi!</div>
        <div style={{ display:"flex", gap:10 }}>
          <button onClick={onClose} style={{ flex:1, padding:"10px", borderRadius:9, background:T.card, border:`1px solid ${T.border}`, color:T.text, fontSize:13, fontWeight:500, cursor:"pointer" }}>Bekor qilish</button>
          <button onClick={onConfirm} style={{ flex:1, padding:"10px", borderRadius:9, background:T.danger, border:"none", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer" }}>Ha, o’chirish</button>
        </div>
      </div>
    </div>
  );
}

// ── ZAPCHASTLAR ────────────────────────────────────────────────────────────────

function TovarlarPage({ parts, setParts, accessories, setAccessories, setSales, partHistory, setPartHistory, accHistory, setAccHistory }) {
  const {config} = useShoxConfig();
  const [tab, setTab] = React.useState("zapchast"); // zapchast | aksessuar
  const [search, setSearch] = React.useState("");
  const [filterType, setFilterType] = React.useState("Hammasi");
  const [filterCat, setFilterCat] = React.useState("Hammasi");
  const [modal, setModal] = React.useState(false);
  const [editId, setEditId] = React.useState(null);
  const [deleteConfirm, setDeleteConfirm] = React.useState(null);
  const [form, setForm] = React.useState({name:"",brand:"Boshqa",model:"",type:"Boshqa",sellPrice:"",count:"",category:"Boshqa",buyPrice:""});
  const [bulkModal, setBulkModal] = React.useState(false);
  const [sortCol, setSortCol] = React.useState("");
  const [sortDir, setSortDir] = React.useState("asc");

  const partTypes = ["Hammasi",...(config.partTypes||["Ekran","Batareya","Kamera","Orqa qopqoq","Boshqa"])];
  const partBrands = config.partBrands||["Apple","Samsung","Xiaomi","Huawei","Oppo","Vivo","Realme","Boshqa"];
  const accCats = ["Hammasi",...(config.accCategories||["Chexol","Kabel","Quloqchin","Zaryadlovchi","Boshqa"])];

  const isZap = tab === "zapchast";
  const items = isZap ? parts : accessories;

  const filtered = React.useMemo(() => {
    const q = search.toLowerCase();
    let list = items.filter(p => {
      const matchSearch = !q || (p.name||"").toLowerCase().includes(q) || (p.brand||"").toLowerCase().includes(q) || (p.model||"").toLowerCase().includes(q);
      const matchFilter = isZap ? (filterType==="Hammasi" || p.type===filterType) : (filterCat==="Hammasi" || p.category===filterCat);
      return matchSearch && matchFilter;
    });
    if(sortCol) {
      list = [...list].sort((a,b) => {
        const av = sortCol==="count"?+(a.count||0):sortCol==="sellPrice"?+(a.sellPrice||0):(a.name||"").toLowerCase();
        const bv = sortCol==="count"?+(b.count||0):sortCol==="sellPrice"?+(b.sellPrice||0):(b.name||"").toLowerCase();
        return sortDir==="asc"?(av<bv?-1:av>bv?1:0):(av>bv?-1:av<bv?1:0);
      });
    }
    return list;
  }, [items, search, filterType, filterCat, sortCol, sortDir, tab]);

  const stockColor = c => c===0?T.danger:c<=5?T.warning:T.success;
  const stockLabel = c => c===0?"Tugdi":c<=5?"Kam":"Yetarli";

  const openAdd = () => {
    setEditId(null);
    setForm({name:"",brand:partBrands[0]||"Boshqa",model:"",type:isZap?(config.partTypes||["Ekran"])[0]:"",sellPrice:"",count:"",category:isZap?"":(config.accCategories||["Chexol"])[0],buyPrice:""});
    setModal(true);
  };

  const openEdit = (item) => {
    setEditId(item.id);
    setForm({
      name:item.name||"",brand:item.brand||"Boshqa",model:item.model||"",
      type:item.type||"Boshqa",sellPrice:String(item.sellPrice||""),
      count:String(item.count||""),category:item.category||"Boshqa",buyPrice:String(item.buyPrice||"")
    });
    setModal(true);
  };

  const saveItem = () => {
    if(!form.name.trim() && !form.model.trim()) return;
    const name = form.name.trim() || [form.brand, form.model, isZap?form.type:form.category].filter(Boolean).join(" ");
    if(isZap) {
      if(editId) {
        setParts(p => p.map(x => x.id===editId ? {...x,name,brand:form.brand,model:form.model,type:form.type,sellPrice:+form.sellPrice||0,count:+form.count||0,buyPrice:+form.buyPrice||0} : x));
      } else {
        const newP = {id:uid(),name,brand:form.brand,model:form.model,type:form.type,buyPrice:+form.buyPrice||0,sellPrice:+form.sellPrice||0,count:+form.count||1,date:today()};
        setParts(p => [...p, newP]);
        if(setPartHistory) setPartHistory(h => [...h, {id:uid(),partId:newP.id,type:"kirdi",qty:newP.count,date:today(),note:"Qo'shildi"}]);
      }
    } else {
      if(editId) {
        setAccessories(a => a.map(x => x.id===editId ? {...x,name,category:form.category,sellPrice:+form.sellPrice||0,count:+form.count||0,buyPrice:+form.buyPrice||0} : x));
      } else {
        const newA = {id:uid(),name,category:form.category,buyPrice:+form.buyPrice||0,sellPrice:+form.sellPrice||0,count:+form.count||1,date:today()};
        setAccessories(a => [...a, newA]);
        if(setAccHistory) setAccHistory(h => [...h, {id:uid(),accId:newA.id,type:"kirdi",qty:newA.count,date:today(),note:"Qo'shildi"}]);
      }
    }
    setModal(false);
  };

  const deleteItem = (id) => {
    if(isZap) setParts(p => p.filter(x => x.id !== id));
    else setAccessories(a => a.filter(x => x.id !== id));
    setDeleteConfirm(null);
  };

  const SortBtn = ({col, label}) => (
    <span onClick={() => {if(sortCol===col)setSortDir(d=>d==="asc"?"desc":"asc");else{setSortCol(col);setSortDir("asc");}}}
      style={{cursor:"pointer",userSelect:"none",color:sortCol===col?T.brand:T.muted}}>
      {label}{sortCol===col?(sortDir==="asc"?" ↑":" ↓"):""}
    </span>
  );

  const totalItems = filtered.length;
  const critCount = filtered.filter(p=>p.count===0).length;
  const lowCount = filtered.filter(p=>p.count>0&&p.count<=5).length;

  return (
    <div style={{display:"flex",flexDirection:"column",gap:12,height:"100%"}}>

      {/* Delete confirm modal */}
      {deleteConfirm&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.75)",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center"}}
          onClick={()=>setDeleteConfirm(null)}>
          <div style={{background:T.card,border:"1px solid "+T.danger+"44",borderRadius:16,padding:28,maxWidth:320,width:"100%",textAlign:"center"}} onClick={e=>e.stopPropagation()}>
            <div style={{fontSize:36,marginBottom:10}}>🗑️</div>
            <div style={{fontSize:14,fontWeight:700,color:T.text,marginBottom:6}}>{"\""+deleteConfirm.name+"\" o'chiriladi"}</div>
            <div style={{fontSize:12,color:T.muted,marginBottom:20}}>Bu amalni bekor qilib bo’lmaydi.</div>
            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>setDeleteConfirm(null)} style={{flex:1,padding:"10px",borderRadius:9,background:T.surface,border:"1px solid "+T.border,color:T.text,cursor:"pointer",fontSize:13}}>Bekor</button>
              <button onClick={()=>deleteItem(deleteConfirm.id)} style={{flex:1,padding:"10px",borderRadius:9,background:T.danger,border:"none",color:"#fff",cursor:"pointer",fontSize:13,fontWeight:700}}>O’chir</button>
            </div>
          </div>
        </div>
      )}

      {/* Add/Edit modal */}
      {modal&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.75)",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}
          onClick={()=>setModal(false)}>
          <div style={{background:T.card,border:"1px solid "+T.border,borderRadius:16,padding:24,width:"100%",maxWidth:400}} onClick={e=>e.stopPropagation()}>
            <div style={{fontSize:15,fontWeight:800,color:T.text,marginBottom:20}}>
              {editId?"Tahrirlash":"Yangi "+(isZap?"zapchast":"aksessuar")}
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:10}}>
              {isZap&&(
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                  <div>
                    <div style={{fontSize:11,color:T.muted,marginBottom:4}}>Brend</div>
                    <select value={form.brand} onChange={e=>setForm(f=>({...f,brand:e.target.value}))}
                      style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:8,padding:"8px 10px",color:T.text,fontSize:12,outline:"none"}}>
                      {partBrands.map(b=><option key={b}>{b}</option>)}
                    </select>
                  </div>
                  <div>
                    <div style={{fontSize:11,color:T.muted,marginBottom:4}}>Model</div>
                    <input value={form.model} onChange={e=>setForm(f=>({...f,model:e.target.value}))} placeholder="S23, 14 Pro..."
                      style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:8,padding:"8px 10px",color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}/>
                  </div>
                </div>
              )}
              <div>
                <div style={{fontSize:11,color:T.muted,marginBottom:4}}>Nomi (ixtiyoriy)</div>
                <input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder={isZap?"iPhone 14 Pro Ekran":"Chexol Samsung S23"}
                  style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:8,padding:"8px 10px",color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}/>
              </div>
              <div>
                <div style={{fontSize:11,color:T.muted,marginBottom:4}}>{isZap?"Turi":"Kategoriya"}</div>
                <select value={isZap?form.type:form.category} onChange={e=>setForm(f=>isZap?({...f,type:e.target.value}):({...f,category:e.target.value}))}
                  style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:8,padding:"8px 10px",color:T.text,fontSize:12,outline:"none"}}>
                  {(isZap?(config.partTypes||["Ekran","Batareya","Kamera","Boshqa"]):(config.accCategories||["Chexol","Kabel","Boshqa"])).map(t=><option key={t}>{t}</option>)}
                </select>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
                <div>
                  <div style={{fontSize:11,color:T.muted,marginBottom:4}}>Xarid narx</div>
                  <input type="number" value={form.buyPrice} onChange={e=>setForm(f=>({...f,buyPrice:e.target.value}))} placeholder="0"
                    style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:8,padding:"8px 10px",color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}/>
                </div>
                <div>
                  <div style={{fontSize:11,color:T.muted,marginBottom:4}}>Sotuv narx</div>
                  <input type="number" value={form.sellPrice} onChange={e=>setForm(f=>({...f,sellPrice:e.target.value}))} placeholder="0"
                    style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:8,padding:"8px 10px",color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}/>
                </div>
                <div>
                  <div style={{fontSize:11,color:T.muted,marginBottom:4}}>Soni</div>
                  <input type="number" value={form.count} onChange={e=>setForm(f=>({...f,count:e.target.value}))} placeholder="1"
                    style={{width:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:8,padding:"8px 10px",color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}/>
                </div>
              </div>
              {form.buyPrice&&form.sellPrice&&(
                <div style={{padding:"8px 12px",background:T.brandDim,borderRadius:8,fontSize:11,color:T.brand}}>
                  Margin: {Math.round(((+form.sellPrice-+form.buyPrice)/Math.max(+form.sellPrice,1))*100)}% 
                  {" | Foyda/dona: "+fmt((+form.sellPrice||0)-(+form.buyPrice||0))+" so'm"}
                </div>
              )}
            </div>
            <div style={{display:"flex",gap:10,marginTop:20}}>
              <button onClick={()=>setModal(false)} style={{flex:1,padding:"11px",borderRadius:10,background:T.surface,border:"1px solid "+T.border,color:T.muted,cursor:"pointer",fontSize:13}}>Bekor</button>
              <button onClick={saveItem} style={{flex:2,padding:"11px",borderRadius:10,background:T.brand,border:"none",color:"#fff",cursor:"pointer",fontSize:13,fontWeight:700}}>
                {editId?"Saqlash":"Qo'shish"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        {/* Tab switcher */}
        <div style={{display:"flex",background:T.card,border:"1px solid "+T.border,borderRadius:10,padding:3,gap:2}}>
          {[{k:"zapchast",l:"📦 Zapchastlar",n:parts.length},{k:"aksessuar",l:"🎒 Aksessuarlar",n:accessories.length}].map(t=>(
            <button key={t.k} onClick={()=>{setTab(t.k);setSearch("");setFilterType("Hammasi");setFilterCat("Hammasi");}}
              style={{padding:"7px 16px",borderRadius:8,border:"none",cursor:"pointer",fontSize:12,fontWeight:tab===t.k?700:400,
                background:tab===t.k?T.brand:"transparent",color:tab===t.k?"#fff":T.muted,transition:"all 0.15s"}}>
              {t.l} <span style={{fontSize:10,opacity:0.7}}>({t.n})</span>
            </button>
          ))}
        </div>
        <button onClick={openAdd}
          style={{padding:"9px 20px",borderRadius:10,background:T.brand,border:"none",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",flexShrink:0}}>
          + {isZap?"Zapchast":"Aksessuar"} qo'shish
        </button>
      </div>

      {/* Stats row */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8}}>
        {[
          {l:"Jami tur",v:totalItems+" ta",c:T.brand,bg:T.brandDim},
          {l:"Jami dona",v:filtered.reduce((a,p)=>a+p.count,0)+" ta",c:T.info,bg:T.infoDim},
          {l:"Tugadi",v:critCount+" ta",c:critCount>0?T.danger:T.success,bg:critCount>0?T.dangerDim:T.successDim},
          {l:"Kam (≤5)",v:lowCount+" ta",c:lowCount>0?T.warning:T.success,bg:lowCount>0?T.warningDim:T.successDim},
        ].map((s,i)=>(
          <div key={i} style={{background:s.bg,border:"1px solid "+s.c+"33",borderRadius:10,padding:"10px 14px"}}>
            <div style={{fontSize:10,color:s.c,fontWeight:700,marginBottom:2}}>{s.l}</div>
            <div style={{fontSize:16,fontWeight:900,color:T.text}}>{s.v}</div>
          </div>
        ))}
      </div>

      {/* Filter + Search */}
      <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
        <div style={{flex:1,minWidth:200,display:"flex",alignItems:"center",gap:8,background:T.card,border:"1px solid "+T.border,borderRadius:9,padding:"7px 12px"}}>
          <svg width="13" height="13" viewBox="0 0 16 16" fill="none"><circle cx="6.5" cy="6.5" r="5" stroke={T.muted} strokeWidth="1.5"/><line x1="10.5" y1="10.5" x2="14" y2="14" stroke={T.muted} strokeWidth="1.5" strokeLinecap="round"/></svg>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder={isZap?"Tovar qidirish...":"Aksessuar qidirish..."}
            style={{background:"none",border:"none",outline:"none",color:T.text,fontSize:12,width:"100%"}}/>
          {search&&<button onClick={()=>setSearch("")} style={{background:"none",border:"none",color:T.muted,cursor:"pointer",fontSize:14,padding:0}}>×</button>}
        </div>
        {isZap?(
          <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
            {partTypes.map(t=>(
              <button key={t} onClick={()=>setFilterType(t)}
                style={{padding:"6px 11px",borderRadius:7,border:"1px solid "+(filterType===t?T.brand:T.border),background:filterType===t?T.brandDim:T.card,color:filterType===t?T.brand:T.muted,fontSize:11,cursor:"pointer",fontWeight:filterType===t?700:400}}>
                {t}
              </button>
            ))}
          </div>
        ):(
          <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
            {accCats.map(c=>(
              <button key={c} onClick={()=>setFilterCat(c)}
                style={{padding:"6px 11px",borderRadius:7,border:"1px solid "+(filterCat===c?T.brand:T.border),background:filterCat===c?T.brandDim:T.card,color:filterCat===c?T.brand:T.muted,fontSize:11,cursor:"pointer",fontWeight:filterCat===c?700:400}}>
                {c}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Table */}
      <div style={{background:T.card,border:"1px solid "+T.border,borderRadius:12,overflow:"hidden",flex:1}}>
        {/* Table header */}
        <div style={{display:"grid",gridTemplateColumns:isZap?"2.5fr 1fr 1fr 1fr 90px":"2.5fr 1fr 1fr 90px",gap:0,padding:"10px 16px",borderBottom:"1px solid "+T.border,background:T.surface}}>
          <div style={{fontSize:10,color:T.muted,fontWeight:700}}><SortBtn col="name" label="NOMI"/></div>
          {isZap&&<div style={{fontSize:10,color:T.muted,fontWeight:700}}>TURI / BREND</div>}
          <div style={{fontSize:10,color:T.muted,fontWeight:700,textAlign:"right"}}><SortBtn col="sellPrice" label="SOTUV NARXI"/></div>
          <div style={{fontSize:10,color:T.muted,fontWeight:700,textAlign:"center"}}><SortBtn col="count" label="SONI"/></div>
          <div style={{fontSize:10,color:T.muted,fontWeight:700,textAlign:"center"}}>AMALLAR</div>
        </div>

        {/* Rows */}
        <div style={{overflowY:"auto",maxHeight:"calc(100vh - 340px)"}}>
          {filtered.length===0&&(
            <div style={{textAlign:"center",padding:"40px 0",color:T.muted,fontSize:13}}>
              {search||filterType!=="Hammasi"||filterCat!=="Hammasi"?"Topilmadi":"Hali tovar yo'q"}
            </div>
          )}
          {filtered.map((item,i)=>{
            const sc = stockColor(item.count);
            return (
              <div key={item.id} style={{display:"grid",gridTemplateColumns:isZap?"2.5fr 1fr 1fr 1fr 90px":"2.5fr 1fr 1fr 90px",gap:0,padding:"11px 16px",borderBottom:"1px solid "+T.border,background:i%2===0?T.card:T.surface+"88",transition:"background 0.1s"}}>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <div style={{width:8,height:8,borderRadius:"50%",background:sc,flexShrink:0}}/>
                  <div>
                    <div style={{fontSize:13,fontWeight:600,color:T.text}}>{item.name}</div>
                    {item.count===0&&<div style={{fontSize:10,color:T.danger,fontWeight:600}}>Tugadi — buyurtma bering!</div>}
                    {item.count>0&&item.count<=5&&<div style={{fontSize:10,color:T.warning,fontWeight:600}}>Kam qoldi ({item.count} ta)</div>}
                  </div>
                </div>
                {isZap&&(
                  <div style={{display:"flex",flexDirection:"column",justifyContent:"center"}}>
                    <div style={{fontSize:11,color:T.text}}>{item.type||"—"}</div>
                    <div style={{fontSize:10,color:T.muted}}>{item.brand||"—"}</div>
                  </div>
                )}
                {!isZap&&(
                  <div style={{display:"flex",alignItems:"center"}}>
                    <span style={{fontSize:11,padding:"2px 8px",borderRadius:5,background:T.brandDim,color:T.brand}}>{item.category||"—"}</span>
                  </div>
                )}
                <div style={{display:"flex",alignItems:"center",justifyContent:"flex-end"}}>
                  <span style={{fontSize:13,fontWeight:700,color:T.text}}>{fmt(item.sellPrice||0)}</span>
                  <span style={{fontSize:10,color:T.muted,marginLeft:3}}>so’m</span>
                </div>
                <div style={{display:"flex",alignItems:"center",justifyContent:"center"}}>
                  <span style={{fontSize:14,fontWeight:800,color:sc,padding:"3px 10px",borderRadius:7,background:sc+"18"}}>{item.count}</span>
                </div>
                <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:4}}>
                  <button onClick={()=>openEdit(item)} title="Tahrirlash"
                    style={{width:30,height:30,borderRadius:7,background:T.brandDim,border:"none",cursor:"pointer",fontSize:13,color:T.brand}}>✏️</button>
                  <button onClick={()=>setDeleteConfirm(item)} title="O'chirish"
                    style={{width:30,height:30,borderRadius:7,background:T.dangerDim,border:"none",cursor:"pointer",fontSize:13,color:T.danger}}>🗑</button>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}


// ── MODAL: Katalogdan zapchast qo'shish ──────────────────────────────────────
function ModalZapchast({ editItem, form, setForm, onSave, onClose, SUPA_URL, SUPA_KEY, initialBrand, initialModel, initialType }) {
  const [mBrand,  setMBrand]  = useState(form.brand  || initialBrand  || "");
  const [mModel,  setMModel]  = useState(form.model  || initialModel  || "");
  const [mType,   setMType]   = useState(form.type   || initialType   || "");
  const [mBrands, setMBrands] = useState([]);
  const [mModels, setMModels] = useState([]);
  const [mTypes,  setMTypes]  = useState([]);
  const [loadingM, setLoadingM] = useState(false);
  const [loadingT, setLoadingT] = useState(false);

  // Brendlarni yuklash
  useEffect(()=>{
    if(!SUPA_URL) return;
    fetch(`${SUPA_URL}/rest/v1/parts_catalog?select=brand&order=brand.asc&limit=10000`,{
      headers:{"apikey":SUPA_KEY,"Authorization":`Bearer ${SUPA_KEY}`}
    }).then(r=>r.json()).then(rows=>{
      setMBrands([...new Set(rows.map(r=>r.brand).filter(Boolean))].sort());
    }).catch(()=>{});
  },[]);

  // Modellarni yuklash (brend tanlanganda)
  useEffect(()=>{
    if(!mBrand||!SUPA_URL) { setMModels([]); setMModel(""); setMType(""); return; }
    setLoadingM(true);
    fetch(`${SUPA_URL}/rest/v1/parts_catalog?select=model&brand=eq.${encodeURIComponent(mBrand)}&order=model.asc&limit=10000`,{
      headers:{"apikey":SUPA_KEY,"Authorization":`Bearer ${SUPA_KEY}`}
    }).then(r=>r.json()).then(rows=>{
      setMModels([...new Set(rows.map(r=>r.model).filter(Boolean))].sort());
      setLoadingM(false);
    }).catch(()=>setLoadingM(false));
    if(!editItem) { setMModel(""); setMType(""); }
  },[mBrand]);

  // Turlarni yuklash (model tanlanganda)
  useEffect(()=>{
    if(!mModel||!SUPA_URL) { setMTypes([]); setMType(""); return; }
    setLoadingT(true);
    fetch(`${SUPA_URL}/rest/v1/parts_catalog?select=type,buy_price,sell_price&model=eq.${encodeURIComponent(mModel)}&order=type.asc&limit=10000`,{
      headers:{"apikey":SUPA_KEY,"Authorization":`Bearer ${SUPA_KEY}`}
    }).then(r=>r.json()).then(rows=>{
      setMTypes(rows||[]);
      setLoadingT(false);
    }).catch(()=>setLoadingT(false));
    if(!editItem) setMType("");
  },[mModel]);

  // Tur tanlanganda narxlarni avtomatik to'ldirish
  useEffect(()=>{
    if(!mType||editItem) return;
    const found = mTypes.find(t=>t.type===mType);
    if(found) {
      setForm(prev=>({
        ...prev,
        brand: mBrand,
        model: mModel,
        type: mType,
        name: `${mModel} ${mType}`,
        buyPrice: found.buy_price||0,
        sellPrice: found.sell_price||0,
      }));
    }
  },[mType]);

  const sel = {width:"100%",background:T.surface,border:"1px solid "+T.border,
    borderRadius:8,padding:"8px 12px",color:T.text,fontSize:13,outline:"none",boxSizing:"border-box"};
  const inp = {...sel};
  const lbl = {fontSize:11,color:T.muted,marginBottom:4};

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.65)",
      display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
      <div style={{background:T.card,borderRadius:16,padding:24,width:380,
        border:"1px solid "+T.border,maxHeight:"92vh",overflow:"auto"}}>
        <h3 style={{margin:"0 0 16px",fontSize:15,color:T.text}}>
          {editItem?"✏️ Tahrirlash":"➕ Yangi zapchast"}
        </h3>

        {!editItem && (<>
          {/* Brend */}
          <div style={{marginBottom:10}}>
            <div style={lbl}>📱 Brend</div>
            <select value={mBrand} onChange={e=>{setMBrand(e.target.value);setForm(prev=>({...prev,brand:e.target.value}));}} style={sel}>
              <option value="">— tanlang</option>
              {mBrands.map(b=><option key={b} value={b}>{b}</option>)}
            </select>
          </div>

          {/* Model */}
          {mBrand && (
            <div style={{marginBottom:10}}>
              <div style={lbl}>📋 Model {loadingM&&"⏳"}</div>
              <select value={mModel} onChange={e=>{setMModel(e.target.value);setForm(prev=>({...prev,model:e.target.value}));}} style={sel}>
                <option value="">— tanlang</option>
                {mModels.map(m=><option key={m} value={m}>{m}</option>)}
              </select>
            </div>
          )}

          {/* Tur */}
          {mModel && (
            <div style={{marginBottom:10}}>
              <div style={lbl}>🔩 Tur {loadingT&&"⏳"}</div>
              <select value={mType} onChange={e=>setMType(e.target.value)} style={sel}>
                <option value="">— tanlang</option>
                {mTypes.map(t=><option key={t.type} value={t.type}>{t.type}</option>)}
              </select>
            </div>
          )}

          {mType && <div style={{height:1,background:T.border,margin:"12px 0"}}/>}
        </>)}

        {/* Nomi */}
        <div style={{marginBottom:10}}>
          <div style={lbl}>Nomi</div>
          <input value={form.name} onChange={e=>setForm(p=>({...p,name:e.target.value}))}
            placeholder="Samsung A12 Ekran" style={inp}/>
        </div>

        {/* Narxlar */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
          <div>
            <div style={lbl}>Xarid narxi (so'm)</div>
            <input type="number" value={form.buyPrice} onChange={e=>setForm(p=>({...p,buyPrice:e.target.value}))}
              placeholder="120000" style={inp}/>
          </div>
          <div>
            <div style={lbl}>Sotuv narxi (so'm)</div>
            <input type="number" value={form.sellPrice} onChange={e=>setForm(p=>({...p,sellPrice:e.target.value}))}
              placeholder="220000" style={inp}/>
          </div>
        </div>

        {/* Soni */}
        <div style={{marginBottom:16}}>
          <div style={lbl}>Soni</div>
          <input type="number" value={form.count} onChange={e=>setForm(p=>({...p,count:e.target.value}))}
            placeholder="0" style={inp}/>
        </div>

        <div style={{display:"flex",gap:10}}>
          <button onClick={onClose}
            style={{flex:1,padding:"10px",borderRadius:8,background:T.surface,
              border:"1px solid "+T.border,color:T.muted,cursor:"pointer",fontSize:13}}>Bekor</button>
          <button onClick={onSave}
            style={{flex:1,padding:"10px",borderRadius:8,background:T.brand,
              border:"none",color:"#fff",fontWeight:600,cursor:"pointer",fontSize:13}}>
            {editItem?"Saqlash":"Qo'shish"}
          </button>
        </div>
      </div>
    </div>
  );
}

function ZapchastlarPage({ parts, setParts, partHistory, setPartHistory, setSales }) {
  const SUPA_URL = import.meta.env.VITE_SUPABASE_URL || "";
  const SUPA_KEY = import.meta.env.VITE_SUPABASE_ANON_KEY || "";

  // UI state
  const [selBrand,  setSelBrand]  = useState("");
  const [selModel,  setSelModel]  = useState("");
  const [selType,   setSelType]   = useState("");
  const [search,    setSearch]    = useState("");
  const [results,   setResults]   = useState([]);
  const [loading,   setLoading]   = useState(false);
  const [brands,    setBrands]    = useState([]);
  const [models,    setModels]    = useState([]);
  const [types,     setTypes]     = useState([]);

  // Modal
  const [modal,     setModal]     = useState(false);
  const [editItem,  setEditItem]  = useState(null);
  const [form,      setForm]      = useState({name:"",model:"",type:"",brand:"",buyPrice:0,sellPrice:0,count:0});
  const [delConfirm,setDelConfirm]= useState(null);
  const [toast,     setToast]     = useState(null);

  const showToast = (msg, ok=true) => { setToast({msg,ok}); setTimeout(()=>setToast(null),2500); };

  // Brendlarni yuklash
  useEffect(()=>{
    if(!SUPA_URL) {
      // localStorage dan brendlar
      const brs = [...new Set(parts.map(p=>p.brand||"Boshqa").filter(Boolean))].sort();
      setBrands(brs);
      return;
    }
    fetch(`${SUPA_URL}/rest/v1/parts_catalog?select=brand&order=brand.asc`, {
      headers:{"apikey":SUPA_KEY,"Authorization":`Bearer ${SUPA_KEY}`}
    }).then(r=>r.json()).then(rows=>{
      const brs = [...new Set(rows.map(r=>r.brand).filter(Boolean))].sort();
      setBrands(brs);
    }).catch(()=>{
      const brs = [...new Set(parts.map(p=>p.brand||"Boshqa").filter(Boolean))].sort();
      setBrands(brs);
    });
  },[]);

  // Modellarni yuklash (brend tanlanganda)
  useEffect(()=>{
    if(!selBrand) { setModels([]); setSelModel(""); setSelType(""); setResults([]); return; }
    if(!SUPA_URL) {
      const ms = [...new Set(parts.filter(p=>p.brand===selBrand).map(p=>p.model).filter(Boolean))].sort();
      setModels(ms);
      return;
    }
    fetch(`${SUPA_URL}/rest/v1/parts_catalog?select=model&brand=eq.${encodeURIComponent(selBrand)}&order=model.asc`, {
      headers:{"apikey":SUPA_KEY,"Authorization":`Bearer ${SUPA_KEY}`}
    }).then(r=>r.json()).then(rows=>{
      const ms = [...new Set(rows.map(r=>r.model).filter(Boolean))].sort();
      setModels(ms);
    });
    setSelModel(""); setSelType(""); setResults([]);
  },[selBrand]);

  // Turlarni yuklash (model tanlanganda)
  useEffect(()=>{
    if(!selModel) { setTypes([]); setSelType(""); setResults([]); return; }
    if(!SUPA_URL) {
      const ts = [...new Set(parts.filter(p=>p.model===selModel).map(p=>p.type).filter(Boolean))].sort();
      setTypes(ts);
      return;
    }
    fetch(`${SUPA_URL}/rest/v1/parts_catalog?select=type&model=eq.${encodeURIComponent(selModel)}&order=type.asc`, {
      headers:{"apikey":SUPA_KEY,"Authorization":`Bearer ${SUPA_KEY}`}
    }).then(r=>r.json()).then(rows=>{
      const ts = [...new Set(rows.map(r=>r.type).filter(Boolean))].sort();
      setTypes(ts);
    });
    setSelType(""); setResults([]);
  },[selModel]);

  // Natijalarni yuklash
  useEffect(()=>{
    if(!selModel && !search) { setResults([]); return; }
    setLoading(true);

    // Do'kon inventaridan (parts) ko'rsatamiz
    let filtered = parts;
    if(selBrand)  filtered = filtered.filter(p=>p.brand===selBrand);
    if(selModel)  filtered = filtered.filter(p=>p.model===selModel);
    if(selType)   filtered = filtered.filter(p=>p.type===selType);
    if(search)    filtered = filtered.filter(p=>
      p.name?.toLowerCase().includes(search.toLowerCase()) ||
      p.model?.toLowerCase().includes(search.toLowerCase())
    );
    setResults(filtered.slice(0,200));
    setLoading(false);
  },[selBrand, selModel, selType, search, parts]);

  // Qo'shish / tahrirlash
  const openAdd = () => {
    setEditItem(null);
    setForm({name:selModel&&selType?`${selModel} ${selType}`:"",
      model:selModel||"",type:selType||"",brand:selBrand||"",
      buyPrice:0,sellPrice:0,count:0});
    setModal(true);
  };
  const openEdit = (p) => {
    setEditItem(p);
    setForm({name:p.name,model:p.model||"",type:p.type||"",brand:p.brand||"",
      buyPrice:p.buyPrice||0,sellPrice:p.sellPrice||0,count:p.count||0});
    setModal(true);
  };
  const saveItem = () => {
    if(!form.name) return;
    if(editItem) {
      const updated = parts.map(p=>p.id===editItem.id?{...p,...form,
        buyPrice:+form.buyPrice,sellPrice:+form.sellPrice,count:+form.count}:p);
      setParts(updated);
      showToast("Yangilandi ✅");
    } else {
      const newItem = {...form,id:uid(),buyPrice:+form.buyPrice,
        sellPrice:+form.sellPrice,count:+form.count,category:"zapchast"};
      setParts([...parts, newItem]);
      showToast("Qo'shildi ✅");
    }
    setModal(false);
  };
  const deleteItem = (id) => {
    setParts(parts.filter(p=>p.id!==id));
    setDelConfirm(null);
    showToast("O'chirildi", false);
  };

  // Katalogdan tanlash (mavjud bo'lmasa qo'shish)
  const addFromCatalog = async (catalogItem) => {
    const exists = parts.find(p=>p.model===catalogItem.model && p.type===catalogItem.type);
    if(exists) { showToast("Allaqachon mavjud"); return; }
    const newItem = {
      id: uid(), name: catalogItem.name, model: catalogItem.model,
      type: catalogItem.type, brand: catalogItem.brand||selBrand,
      buyPrice: catalogItem.buy_price||0, sellPrice: catalogItem.sell_price||0,
      count: 0, category: "zapchast"
    };
    setParts(prev=>[...prev, newItem]);
    showToast(`${catalogItem.name} qo'shildi ✅`);
  };

  // Katalog natijalari (parts_catalog dan)
  const [catalogResults, setCatalogResults] = useState([]);
  useEffect(()=>{
    if(!selModel) { setCatalogResults([]); return; }
    if(!SUPA_URL) return;
    let url = `${SUPA_URL}/rest/v1/parts_catalog?model=eq.${encodeURIComponent(selModel)}&order=type.asc`;
    if(selType) url += `&type=eq.${encodeURIComponent(selType)}`;
    fetch(url, {headers:{"apikey":SUPA_KEY,"Authorization":`Bearer ${SUPA_KEY}`}})
      .then(r=>r.json()).then(rows=>setCatalogResults(rows||[]))
      .catch(()=>setCatalogResults([]));
  },[selModel, selType]);

  const inStock = (ci) => parts.some(p=>p.model===ci.model&&p.type===ci.type);

  return (
    <div style={{padding:"16px 20px",maxWidth:1200,margin:"0 auto"}}>
      {/* Header */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
        <div>
          <h2 style={{margin:0,fontSize:18,fontWeight:700,color:T.text}}>📦 Zapchastlar</h2>
          <div style={{fontSize:11,color:T.muted,marginTop:2}}>
            Zaxira: {parts.filter(p=>p.category!=="aksessuар").length} ta | 
            Katalog: 20,256 ta
          </div>
        </div>
        <button onClick={openAdd}
          style={{padding:"8px 16px",borderRadius:8,background:T.brand,border:"none",
            color:"#fff",fontSize:13,fontWeight:600,cursor:"pointer"}}>
          + Zapchast qo'shish
        </button>
      </div>

      {/* Qidiruv */}
      <div style={{background:T.card,borderRadius:12,padding:16,marginBottom:16,
        border:"1px solid "+T.border}}>
        <div style={{display:"flex",gap:10,flexWrap:"wrap",alignItems:"center",marginBottom:12}}>
          <input value={search} onChange={e=>{setSearch(e.target.value);setSelBrand("");setSelModel("");setSelType("");}}
            placeholder="🔍 Tovar nomi yoki model..."
            style={{flex:1,minWidth:200,background:T.surface,border:"1px solid "+T.border,
              borderRadius:8,padding:"8px 12px",color:T.text,fontSize:13,outline:"none"}}/>
        </div>

        {/* Brend → Model → Tur */}
        <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
          {/* Brendlar */}
          <div style={{flex:1,minWidth:140}}>
            <div style={{fontSize:10,color:T.muted,marginBottom:4}}>BREND</div>
            <select value={selBrand} onChange={e=>setSelBrand(e.target.value)}
              style={{width:"100%",background:T.surface,border:"1px solid "+T.border,
                borderRadius:8,padding:"8px 10px",color:T.text,fontSize:13,outline:"none"}}>
              <option value="">— tanlang</option>
              {brands.map(b=><option key={b} value={b}>{b}</option>)}
            </select>
          </div>

          {/* Modellar */}
          {selBrand && (
            <div style={{flex:2,minWidth:160}}>
              <div style={{fontSize:10,color:T.muted,marginBottom:4}}>MODEL</div>
              <select value={selModel} onChange={e=>setSelModel(e.target.value)}
                style={{width:"100%",background:T.surface,border:"1px solid "+T.border,
                  borderRadius:8,padding:"8px 10px",color:T.text,fontSize:13,outline:"none"}}>
                <option value="">— tanlang</option>
                {models.map(m=><option key={m} value={m}>{m}</option>)}
              </select>
            </div>
          )}

          {/* Turlar */}
          {selModel && (
            <div style={{flex:1,minWidth:140}}>
              <div style={{fontSize:10,color:T.muted,marginBottom:4}}>TUR</div>
              <select value={selType} onChange={e=>setSelType(e.target.value)}
                style={{width:"100%",background:T.surface,border:"1px solid "+T.border,
                  borderRadius:8,padding:"8px 10px",color:T.text,fontSize:13,outline:"none"}}>
                <option value="">— hammasi</option>
                {types.map(t=><option key={t} value={t}>{t}</option>)}
              </select>
            </div>
          )}
        </div>
      </div>

      {/* Katalog natijalari */}
      {selModel && catalogResults.length>0 && (
        <div style={{marginBottom:16}}>
          <div style={{fontSize:11,color:T.muted,marginBottom:8,fontWeight:600}}>
            📋 KATALOG — {selModel} {selType||"(barcha turlar)"}
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:8}}>
            {catalogResults.map((ci,i)=>{
              const has = inStock(ci);
              const stockItem = parts.find(p=>p.model===ci.model&&p.type===ci.type);
              return (
                <div key={i} style={{background:T.card,border:"1px solid "+(has?T.success+"44":T.border),
                  borderRadius:10,padding:"12px 14px",display:"flex",
                  justifyContent:"space-between",alignItems:"center",gap:8}}>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:12,fontWeight:600,color:T.text,
                      whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
                      {ci.type}
                    </div>
                    <div style={{fontSize:11,color:T.muted,marginTop:2}}>
                      {ci.sell_price>0 ? `${fmt(ci.sell_price)} so'm` : "Narx belgilanmagan"}
                    </div>
                    {has && <div style={{fontSize:10,color:T.success,marginTop:2}}>
                      ✅ Zaxira: {stockItem?.count||0} ta
                    </div>}
                  </div>
                  {!has ? (
                    <button onClick={()=>addFromCatalog(ci)}
                      style={{padding:"5px 10px",borderRadius:6,background:T.brand,
                        border:"none",color:"#fff",fontSize:11,cursor:"pointer",
                        whiteSpace:"nowrap",flexShrink:0}}>
                      + Qo'shish
                    </button>
                  ) : (
                    <button onClick={()=>openEdit(stockItem)}
                      style={{padding:"5px 10px",borderRadius:6,background:T.surface,
                        border:"1px solid "+T.border,color:T.text,fontSize:11,cursor:"pointer",
                        whiteSpace:"nowrap",flexShrink:0}}>
                      ✏️ Tahrir
                    </button>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Do'kon zaxirasi */}
      {(results.length>0 || search) && (
        <div>
          <div style={{fontSize:11,color:T.muted,marginBottom:8,fontWeight:600}}>
            🏪 DO'KON ZAXIRASI — {results.length} ta
          </div>
          <div style={{background:T.card,borderRadius:12,border:"1px solid "+T.border,overflow:"hidden"}}>
            <table style={{width:"100%",borderCollapse:"collapse"}}>
              <thead>
                <tr style={{background:T.surface}}>
                  {["Nomi","Tur","Soni","Sotuv narxi","Xarid narxi",""].map(h=>(
                    <th key={h} style={{padding:"10px 14px",textAlign:"left",
                      fontSize:11,color:T.muted,fontWeight:500,whiteSpace:"nowrap"}}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {results.map(p=>(
                  <tr key={p.id} style={{borderTop:"1px solid "+T.border}}>
                    <td style={{padding:"10px 14px",fontSize:12,color:T.text,maxWidth:200}}>
                      <div style={{fontWeight:500}}>{p.name}</div>
                      {p.count<=0 && <div style={{fontSize:10,color:T.danger}}>Tugadi</div>}
                    </td>
                    <td style={{padding:"10px 14px",fontSize:11,color:T.muted}}>{p.type||"—"}</td>
                    <td style={{padding:"10px 14px"}}>
                      <span style={{fontSize:13,fontWeight:700,
                        color:p.count<=0?T.danger:p.count<=5?T.warning:T.success}}>
                        {p.count}
                      </span>
                    </td>
                    <td style={{padding:"10px 14px",fontSize:12,color:T.text,fontWeight:600}}>
                      {fmt(p.sellPrice)} so'm
                    </td>
                    <td style={{padding:"10px 14px",fontSize:12,color:T.muted}}>
                      {fmt(p.buyPrice)} so'm
                    </td>
                    <td style={{padding:"10px 14px"}}>
                      <div style={{display:"flex",gap:6}}>
                        <button onClick={()=>openEdit(p)}
                          style={{padding:"4px 8px",borderRadius:6,background:T.surface,
                            border:"1px solid "+T.border,color:T.text,fontSize:11,cursor:"pointer"}}>✏️</button>
                        <button onClick={()=>setDelConfirm(p.id)}
                          style={{padding:"4px 8px",borderRadius:6,background:T.dangerDim,
                            border:"none",color:T.danger,fontSize:11,cursor:"pointer"}}>🗑</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Bo'sh holat */}
      {!selBrand && !search && results.length===0 && (
        <div style={{textAlign:"center",padding:"60px 20px",color:T.muted}}>
          <div style={{fontSize:48,marginBottom:12}}>📦</div>
          <div style={{fontSize:15,fontWeight:600,color:T.text,marginBottom:8}}>
            Brend tanlang yoki qidiring
          </div>
          <div style={{fontSize:12}}>
            Yuqoridan brend → model → tur tanlab zapchastlarni ko'ring
          </div>
        </div>
      )}

      {/* Add/Edit Modal */}
      {modal && (
        <ModalZapchast
          editItem={editItem}
          form={form} setForm={setForm}
          onSave={saveItem}
          onClose={()=>setModal(false)}
          SUPA_URL={SUPA_URL} SUPA_KEY={SUPA_KEY}
          initialBrand={selBrand} initialModel={selModel} initialType={selType}
        />
      )}

      {/* Delete confirm */}
      {delConfirm && (
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",
          display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
          <div style={{background:T.card,borderRadius:16,padding:24,width:300,
            border:"1px solid "+T.border,textAlign:"center"}}>
            <div style={{fontSize:32,marginBottom:12}}>🗑️</div>
            <div style={{fontSize:14,color:T.text,marginBottom:16}}>O'chirishni tasdiqlaysizmi?</div>
            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>setDelConfirm(null)}
                style={{flex:1,padding:"10px",borderRadius:8,background:T.surface,
                  border:"1px solid "+T.border,color:T.muted,cursor:"pointer"}}>Bekor</button>
              <button onClick={()=>deleteItem(delConfirm)}
                style={{flex:1,padding:"10px",borderRadius:8,background:T.danger,
                  border:"none",color:"#fff",fontWeight:600,cursor:"pointer"}}>O'chirish</button>
            </div>
          </div>
        </div>
      )}

      {/* Toast */}
      {toast && (
        <div style={{position:"fixed",bottom:20,right:20,background:toast.ok?T.success:T.danger,
          color:"#fff",padding:"10px 18px",borderRadius:10,fontSize:13,
          fontWeight:600,zIndex:2000,boxShadow:"0 4px 20px rgba(0,0,0,0.3)"}}>
          {toast.msg}
        </div>
      )}
    </div>
  );
}

function AksessuarlarPage({ accessories, setAccessories, setSales, accHistory, setAccHistory }) {
  const [modal, setModal] = useState(false);
  const [bulkModal, setBulkModal] = useState(false);
  const [saleModal, setSaleModal] = useState(false);
  const [returnModal, setReturnModal] = useState(false);
  const [returnItem, setReturnItem] = useState(null);
  const [returnQty, setReturnQty] = useState("1");
  const [returnNote, setReturnNote] = useState("");
  const [cardAcc, setCardAcc] = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [saleItem, setSaleItem] = useState(null);
  const [saleQty, setSaleQty] = useState("1");
  const [salePrice, setSalePrice] = useState("");
  const [editId, setEditId] = useState(null);
  const [search, setSearch] = useState("");
  const [filterCat, setFilterCat] = useState("Hammasi");
  const [catDropOpen, setCatDropOpen] = useState(false);
  const [revealedPrices, setRevealedPrices] = useState({});
  const [sortCol, setSortCol] = useState(null);
  const [sortDir, setSortDir] = useState("asc");
  const [form, setForm] = useState({ name:"", category:"Chexol", buyPrice:"", sellPrice:"", count:"", newArrivalCount:"", newArrivalDate:today() });
  const sf = k => v => setForm(f=>({...f,[k]:v}));

  // Bulk
  const emptyRow = () => ({ id:uid(), name:"", category:"Chexol", buyPrice:"", sellPrice:"", count:"", date:today() });
  const [bulkRows, setBulkRows] = useState([emptyRow(), emptyRow(), emptyRow()]);
  const setBR = (i,k,v) => setBulkRows(prev=>prev.map((r,idx)=>idx===i?{...r,[k]:v}:r));

  const allCats = ["Hammasi",...Array.from(new Set([...ACC_CATEGORIES,...accessories.map(a=>a.category).filter(Boolean)]))];
  const visibleCats = allCats.slice(0,6);
  const hiddenCats = allCats.slice(6);

  const handleSort = col => {
    if(sortCol===col) setSortDir(d=>d==="asc"?"desc":"asc");
    else { setSortCol(col); setSortDir("asc"); }
  };
  const sortVal = (a,col) => {
    if(col==="name") return (a.name||"").toLowerCase();
    if(col==="category") return (a.category||"").toLowerCase();
    if(col==="sellPrice") return a.sellPrice||0;
    if(col==="buyPrice") return a.buyPrice||0;
    if(col==="profit") return (a.sellPrice||0)-(a.buyPrice||0);
    if(col==="count") return a.count||0;
    return "";
  };
  const filtered = useMemo(()=>{
    const q = search.toLowerCase();
    let list = accessories.filter(a=>{
      const matchCat = filterCat==="Hammasi" || a.category===filterCat;
      const matchSearch = !q || (a.name||"").toLowerCase().includes(q) || (a.category||"").toLowerCase().includes(q);
      return matchCat && matchSearch;
    });
    if(sortCol) list = [...list].sort((a,b)=>{
      const av=sortVal(a,sortCol), bv=sortVal(b,sortCol);
      if(av<bv) return sortDir==="asc"?-1:1;
      if(av>bv) return sortDir==="asc"?1:-1;
      return 0;
    });
    return list;
  },[accessories,search,filterCat,sortCol,sortDir]);

  const PAGE_SIZE = 100;
  const [zPage, setZPage] = useState(0);
  // Search/filter o'zganda birinchi sahifaga qayt
  React.useEffect(()=>setZPage(0),[search,filterType,filterBrand,sortBy]);
  const pagedFiltered = filtered.slice(zPage*PAGE_SIZE, (zPage+1)*PAGE_SIZE);
  const totalPages = Math.ceil(filtered.length / PAGE_SIZE);

  const togglePrice = id => setRevealedPrices(prev=>({...prev,[id]:!prev[id]}));

  // Excel export
  const exportExcel = () => {
    const rows = [
      ["Nomi","Kategoriya","Kelgan narx","Sotish narx","Foyda","Soni","Holat"],
      ...accessories.map(a=>[a.name||"",a.category||"",a.buyPrice||0,a.sellPrice||0,(a.sellPrice||0)-(a.buyPrice||0),a.count||0,a.count<=5?"Kritik":a.count<=10?"Kam":"Yetarli"])
    ];
    const csv = rows.map(r=>r.map(c=>`"${c}"`).join(",")).join("\n");
    const blob = new Blob(["\uFEFF"+csv],{type:"text/csv;charset=utf-8;"});
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a"); a.href=url; a.download=`ShoxService_Aksessuarlar_${today()}.csv`; a.click();
    URL.revokeObjectURL(url);
  };

  const openAdd = () => { setEditId(null); setForm({name:"",category:"Chexol",buyPrice:"",sellPrice:"",count:"",newArrivalCount:"",newArrivalDate:today()}); setModal(true); };
  const openEdit = a => { setEditId(a.id); setForm({name:a.name,category:a.category||"Chexol",buyPrice:a.buyPrice,sellPrice:a.sellPrice,count:a.count,newArrivalCount:"",newArrivalDate:today()}); setModal(true); };

  const doSave = () => {
    if(!form.name) return;
    if(editId) {
      const oldAcc = accessories.find(a=>a.id===editId);
      if(form.newArrivalCount && +form.newArrivalCount>0) {
        const arrCount = +form.newArrivalCount;
        setAccHistory(prev=>[...prev,{id:uid(),accId:editId,accName:form.name,count:arrCount,buyPrice:+form.buyPrice,date:form.newArrivalDate,type:"kirim"}]);
        setAccessories(prev=>prev.map(a=>a.id===editId?{...a,...form,buyPrice:+form.buyPrice,sellPrice:+form.sellPrice,count:oldAcc.count+arrCount}:a));
      } else {
        setAccessories(prev=>prev.map(a=>a.id===editId?{...a,...form,buyPrice:+form.buyPrice,sellPrice:+form.sellPrice,count:+form.count}:a));
      }
    } else {
      const newId = uid();
      setAccessories(prev=>[...prev,{id:newId,name:form.name,category:form.category,buyPrice:+form.buyPrice,sellPrice:+form.sellPrice,count:+form.count}]);
      setAccHistory(prev=>[...prev,{id:uid(),accId:newId,accName:form.name,count:+form.count,buyPrice:+form.buyPrice,date:today(),type:"kirim"}]);
    }
    setModal(false);
  };

  const doDelete = () => { if(!deleteConfirm) return; setAccessories(prev=>prev.filter(x=>x.id!==deleteConfirm.id)); setDeleteConfirm(null); };
  const adj = (id,d) => setAccessories(prev=>prev.map(a=>a.id===id?{...a,count:Math.max(0,a.count+d)}:a));

  const openSale = a => { setSaleItem(a); setSaleQty("1"); setSalePrice(String(a.sellPrice)); setSaleModal(true); };
  const doSale = () => {
    if(!saleItem||+saleQty<=0) return;
    const qty=+saleQty; const price=+salePrice||saleItem.sellPrice;
    setAccessories(prev=>prev.map(a=>a.id===saleItem.id?{...a,count:Math.max(0,a.count-qty)}:a));
    setSales(prev=>[...prev,{id:uid(),date:today(),name:saleItem.name,qty,price:price*qty,profit:(price-saleItem.buyPrice)*qty,type:"aksessuar"}]);
    setSaleModal(false); setSaleItem(null);
  };
  const openReturn = a => { setReturnItem(a); setReturnQty("1"); setReturnNote(""); setReturnModal(true); };
  const doReturn = () => {
    if(!returnItem||+returnQty<=0) return;
    const qty=+returnQty;
    setAccessories(prev=>prev.map(a=>a.id===returnItem.id?{...a,count:a.count+qty}:a));
    setSales(prev=>[...prev,{id:uid(),date:today(),name:returnItem.name,qty:-qty,price:-(returnItem.sellPrice*qty),profit:-((returnItem.sellPrice-returnItem.buyPrice)*qty),type:"aksessuar_qaytdi",note:returnNote}]);
    setReturnModal(false); setReturnItem(null);
  };

  // Bulk save
  const doBulkSave = () => {
    const filled = bulkRows.filter(r=>r.name.trim()&&r.count);
    if(!filled.length) return;
    let updated = [...accessories]; const newHist=[];
    filled.forEach(r=>{
      const existIdx = updated.findIndex(a=>a.name.trim()===r.name.trim()&&a.category===r.category);
      if(existIdx>=0){
        updated[existIdx]={...updated[existIdx],count:updated[existIdx].count+(+r.count||0),buyPrice:+r.buyPrice||updated[existIdx].buyPrice,sellPrice:+r.sellPrice||updated[existIdx].sellPrice};
        newHist.push({id:uid(),accId:updated[existIdx].id,accName:r.name,count:+r.count||0,buyPrice:+r.buyPrice||0,date:r.date||today(),type:"kirim"});
      } else {
        const newId=uid();
        updated.push({id:newId,name:r.name.trim(),category:r.category,buyPrice:+r.buyPrice||0,sellPrice:+r.sellPrice||0,count:+r.count||0});
        newHist.push({id:uid(),accId:newId,accName:r.name,count:+r.count||0,buyPrice:+r.buyPrice||0,date:r.date||today(),type:"kirim"});
      }
    });
    setAccessories(updated); setAccHistory(prev=>[...prev,...newHist]);
    setBulkModal(false); setBulkRows([emptyRow(),emptyRow(),emptyRow()]);
  };

  const incompleteRows = bulkRows.filter(r=>r.name.trim()&&!r.count);
  const filledRows = bulkRows.filter(r=>r.name.trim()&&r.count);

  const SortArrow = ({col}) => {
    if(sortCol!==col) return <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke={T.muted} strokeWidth="2" opacity="0.35"><path d="M7 15l5 5 5-5M7 9l5-5 5 5"/></svg>;
    return sortDir==="asc"
      ? <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke={T.brand} strokeWidth="2.5"><path d="M7 15l5 5 5-5"/></svg>
      : <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke={T.brand} strokeWidth="2.5"><path d="M7 9l5-5 5 5"/></svg>;
  };
  const thS = col => ({ padding:"10px 14px", textAlign:"left", fontSize:11, fontWeight:500, background:T.surface, cursor:"pointer", userSelect:"none", whiteSpace:"nowrap", color:sortCol===col?T.brand:T.muted });

  return (
    <div>
      {/* TOOLBAR */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12, flexWrap:"wrap", gap:8 }}>
        <SearchBar value={search} onChange={setSearch} placeholder="Aksessuar, kategoriya..." />
        <div style={{ display:"flex", gap:8 }}>
          <Btn variant="ghost" onClick={exportExcel}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg>
            Excel
          </Btn>
          <Btn variant="default" onClick={()=>{setBulkRows([emptyRow(),emptyRow(),emptyRow()]);setBulkModal(true);}}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 5v14M5 12h14"/></svg>
            Tovar qo'shish
          </Btn>
          <Btn variant="primary" onClick={openAdd}>+ Tezkor qo’shish</Btn>
        </div>
      </div>

      {/* CATEGORY FILTER */}
      <div style={{ display:"flex", gap:6, flexWrap:"wrap", alignItems:"center", marginBottom:14, position:"relative" }}>
        {visibleCats.map(c=>(
          <button key={c} onClick={()=>setFilterCat(c)} style={{ padding:"6px 13px", borderRadius:8, fontSize:12, cursor:"pointer", background:filterCat===c?T.brand:T.card, color:filterCat===c?"#fff":T.muted, border:`1px solid ${filterCat===c?T.brand:T.border}`, fontWeight:filterCat===c?600:400 }}>{c}</button>
        ))}
        {hiddenCats.length>0 && (
          <div style={{ position:"relative" }}>
            <button onClick={()=>setCatDropOpen(v=>!v)} style={{ padding:"6px 13px", borderRadius:8, fontSize:12, cursor:"pointer", background:hiddenCats.includes(filterCat)?T.brand:T.card, color:hiddenCats.includes(filterCat)?"#fff":T.muted, border:`1px solid ${hiddenCats.includes(filterCat)?T.brand:T.border}`, display:"flex", alignItems:"center", gap:5 }}>
              {hiddenCats.includes(filterCat)?filterCat:`+${hiddenCats.length} ta`}
              <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M6 9l6 6 6-6"/></svg>
            </button>
            {catDropOpen && (
              <div style={{ position:"absolute", top:"calc(100% + 6px)", left:0, background:T.card, border:`1px solid ${T.borderStrong}`, borderRadius:10, padding:6, zIndex:100, minWidth:200, boxShadow:"0 8px 32px rgba(0,0,0,0.4)" }}>
                {hiddenCats.map(c=>(
                  <div key={c} onClick={()=>{setFilterCat(c);setCatDropOpen(false);}} style={{ padding:"7px 12px", borderRadius:7, fontSize:12, cursor:"pointer", color:filterCat===c?T.brand:T.text, background:filterCat===c?T.brandDim:"transparent" }}
                    onMouseEnter={e=>e.currentTarget.style.background=T.surface}
                    onMouseLeave={e=>e.currentTarget.style.background=filterCat===c?T.brandDim:"transparent"}>
                    {c}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
        {filterCat!=="Hammasi" && <button onClick={()=>setFilterCat("Hammasi")} style={{ padding:"6px 10px", borderRadius:8, fontSize:11, cursor:"pointer", background:"transparent", border:`1px solid ${T.border}`, color:T.muted }}>× Tozalash</button>}
      </div>

      {/* TABLE */}
      <Card style={{ padding:0, overflow:"hidden" }}>
        <table style={{ width:"100%", borderCollapse:"collapse" }}>
          <thead>
            <tr style={{ borderBottom:`1px solid ${T.border}` }}>
              <th onClick={()=>handleSort("name")} style={thS("name")}><span style={{ display:"flex", alignItems:"center", gap:5 }}>Nomi <SortArrow col="name"/></span></th>
              <th onClick={()=>handleSort("category")} style={thS("category")}><span style={{ display:"flex", alignItems:"center", gap:5 }}>Kategoriya <SortArrow col="category"/></span></th>
              <th onClick={()=>handleSort("buyPrice")} style={thS("buyPrice")}>
                <span style={{ display:"flex", alignItems:"center", gap:5 }}>Kelgan <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg><SortArrow col="buyPrice"/></span>
              </th>
              <th onClick={()=>handleSort("sellPrice")} style={thS("sellPrice")}><span style={{ display:"flex", alignItems:"center", gap:5 }}>Sotish <SortArrow col="sellPrice"/></span></th>
              <th onClick={()=>handleSort("profit")} style={thS("profit")}>
                <span style={{ display:"flex", alignItems:"center", gap:5 }}>Foyda <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg><SortArrow col="profit"/></span>
              </th>
              <th onClick={()=>handleSort("count")} style={thS("count")}><span style={{ display:"flex", alignItems:"center", gap:5 }}>Soni <SortArrow col="count"/></span></th>
              <th style={{ padding:"10px 14px", fontSize:11, color:T.muted, fontWeight:500, background:T.surface }}>Amallar</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map(a=>{
              const shown = !!revealedPrices[a.id];
              return (
                <tr key={a.id} style={{ borderBottom:`1px solid ${T.border}` }}>
                  <td style={{ padding:"10px 14px", fontSize:13, color:T.text, fontWeight:600 }}>{a.name}</td>
                  <td style={{ padding:"10px 14px" }}><Badge>{a.category||"—"}</Badge></td>
                  {/* KELGAN — yopiq */}
                  <td style={{ padding:"10px 14px" }}>
                    <div onClick={()=>togglePrice(a.id)} style={{ display:"inline-flex", alignItems:"center", gap:6, cursor:"pointer", userSelect:"none" }}>
                      {shown ? <span style={{ fontSize:13, color:T.muted }}>{fmt(a.buyPrice)}</span>
                             : <span style={{ fontSize:12, color:T.muted, background:T.subtle, padding:"3px 10px", borderRadius:6, letterSpacing:2 }}>••••••</span>}
                      <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={T.muted} strokeWidth="2" strokeLinecap="round">
                        {shown ? <><path d="M17.94 17.94A10.07 10.07 0 0112 20c-7 0-11-8-11-8a18.45 18.45 0 015.06-5.94"/><path d="M9.9 4.24A9.12 9.12 0 0112 4c7 0 11 8 11 8a18.5 18.5 0 01-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/></>
                               : <><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></>}
                      </svg>
                    </div>
                  </td>
                  <td style={{ padding:"10px 14px", fontSize:13, color:T.text }}>{fmt(a.sellPrice)}</td>
                  {/* FOYDA — yopiq */}
                  <td style={{ padding:"10px 14px" }}>
                    <div onClick={()=>togglePrice(a.id)} style={{ display:"inline-flex", alignItems:"center", gap:6, cursor:"pointer", userSelect:"none" }}>
                      {shown ? <span style={{ fontSize:13, color:T.success, fontWeight:700 }}>+{fmt((a.sellPrice||0)-(a.buyPrice||0))}</span>
                             : <span style={{ fontSize:12, color:T.success, background:T.successDim, padding:"3px 10px", borderRadius:6, letterSpacing:2, opacity:0.6 }}>••••••</span>}
                    </div>
                  </td>
                  <td style={{ padding:"10px 14px" }}>
                    <div style={{ display:"flex", alignItems:"center", gap:5 }}>
                      <button title="Sotildi (−)" onClick={()=>openSale(a)} style={{ width:26,height:26,borderRadius:6,background:T.brandDim,border:`1px solid ${T.brand}44`,color:T.brand,cursor:"pointer",fontSize:11,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center" }}>S</button>
                      <span style={{ fontSize:13, fontWeight:800, color:stockColor(a.count), minWidth:28, textAlign:"center", background:stockBg(a.count), padding:"2px 8px", borderRadius:6 }}>{a.count}</span>
                      <button title="Qaytdi (+)" onClick={()=>openReturn(a)} style={{ width:26,height:26,borderRadius:6,background:T.warningDim,border:`1px solid rgba(245,158,11,0.3)`,color:T.warning,cursor:"pointer",fontSize:11,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center" }}>Q</button>
                    </div>
                  </td>
                  <td style={{ padding:"10px 14px" }}>
                    <div style={{ display:"flex", gap:5 }}>
                      <Btn small onClick={()=>setCardAcc(a)}>
                        <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="2" y="3" width="20" height="14" rx="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>
                        Karta
                      </Btn>
                      <Btn small onClick={()=>openEdit(a)}>Tahrir</Btn>
                      <Btn small variant="danger" onClick={()=>setDeleteConfirm({id:a.id,name:a.name})}>O’chir</Btn>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filtered.length===0 && <div style={{ padding:32, textAlign:"center", color:T.muted, fontSize:13 }}>Aksessuarlar topilmadi</div>}
      </Card>

      {/* DELETE CONFIRM */}
      <ConfirmDelete open={!!deleteConfirm} onClose={()=>setDeleteConfirm(null)} onConfirm={doDelete} itemName={deleteConfirm?.name||""} />

      {/* TOVAR KARTASI */}
      {cardAcc && (()=>{
        const hist = [...accHistory].filter(h=>h.accId===cardAcc.id).reverse();
        const priceChanges=[]; let lastPrice=null;
        [...hist].reverse().forEach(h=>{
          if(h.buyPrice&&h.buyPrice!==lastPrice){priceChanges.push({date:h.date,price:h.buyPrice});lastPrice=h.buyPrice;}
        });
        const totalIn = hist.reduce((s,h)=>s+(h.count||0),0);
        return (
          <div style={{ position:"fixed", inset:0, zIndex:250, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
            <div style={{ background:T.surface, border:`1px solid ${T.borderStrong}`, borderRadius:18, width:"100%", maxWidth:560, maxHeight:"88vh", display:"flex", flexDirection:"column", overflow:"hidden" }}>
              <div style={{ padding:"20px 24px 16px", borderBottom:`1px solid ${T.border}`, display:"flex", alignItems:"flex-start", justifyContent:"space-between" }}>
                <div>
                  <div style={{ fontSize:11, color:T.muted, fontWeight:500, marginBottom:4, letterSpacing:0.5 }}>AKSESSUAR KARTASI</div>
                  <div style={{ fontSize:18, fontWeight:800, color:T.text }}>{cardAcc.name}</div>
                  <div style={{ marginTop:5 }}><Badge color={T.brand} bg={T.brandDim}>{cardAcc.category||"—"}</Badge></div>
                </div>
                <button onClick={()=>setCardAcc(null)} style={{ background:"none",border:`1px solid ${T.border}`,borderRadius:8,color:T.muted,cursor:"pointer",fontSize:20,width:32,height:32,display:"flex",alignItems:"center",justifyContent:"center" }}>×</button>
              </div>
              <div style={{ flex:1, overflowY:"auto", padding:"20px 24px" }}>
                <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:10, marginBottom:20 }}>
                  {[
                    {label:"Joriy zaxira",val:`${cardAcc.count} ta`,color:stockColor(cardAcc.count),bg:stockBg(cardAcc.count)},
                    {label:"Jami kirim",val:`${totalIn} ta`,color:T.brand,bg:T.brandDim},
                    {label:"Sotish narxi",val:`${fmt(cardAcc.sellPrice)}`,color:T.text,bg:T.subtle},
                    {label:"Foyda/dona",val:`+${fmt((cardAcc.sellPrice||0)-(cardAcc.buyPrice||0))}`,color:T.success,bg:T.successDim},
                  ].map(s=>(
                    <div key={s.label} style={{ background:s.bg, borderRadius:10, padding:"12px 14px" }}>
                      <div style={{ fontSize:10, color:s.color, fontWeight:600, marginBottom:4, opacity:0.8 }}>{s.label.toUpperCase()}</div>
                      <div style={{ fontSize:16, fontWeight:800, color:s.color }}>{s.val}</div>
                    </div>
                  ))}
                </div>
                {/* Narx tarixi */}
                <div style={{ marginBottom:20 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:T.text, marginBottom:10, display:"flex", alignItems:"center", gap:8 }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={T.brand} strokeWidth="2"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>
                    Narx o'zgartirish tarixi
                  </div>
                  {priceChanges.length===0 ? <div style={{ color:T.muted, fontSize:13 }}>Narx o’zgarishi yo’q</div> :
                    priceChanges.map((pc,i)=>{
                      const prev=priceChanges[i-1]; const diff=prev?pc.price-prev.price:0; const pct=prev?((diff/prev.price)*100).toFixed(1):0;
                      return (
                        <div key={i} style={{ display:"flex", alignItems:"center", gap:12, padding:"9px 0", borderBottom:`1px solid ${T.border}` }}>
                          <div style={{ fontSize:11, color:T.muted, minWidth:82 }}>{pc.date}</div>
                          <div style={{ fontSize:14, fontWeight:700, color:T.text }}>{fmt(pc.price)} so’m</div>
                          {diff!==0 && <div style={{ fontSize:12, fontWeight:600, color:diff>0?T.danger:T.success, background:diff>0?T.dangerDim:T.successDim, padding:"2px 8px", borderRadius:6 }}>{diff>0?"+":""}{fmt(diff)} ({diff>0?"+":""}{pct}%)</div>}
                          {i===priceChanges.length-1 && <Badge color={T.brand} bg={T.brandDim}>Joriy</Badge>}
                        </div>
                      );
                    })
                  }
                </div>
                {/* Kirim tarixi */}
                <div>
                  <div style={{ fontSize:12, fontWeight:700, color:T.text, marginBottom:10, display:"flex", alignItems:"center", gap:8 }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={T.success} strokeWidth="2"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>
                    Kirim tarixi
                  </div>
                  {hist.length===0 ? <div style={{ color:T.muted, fontSize:13 }}>Kirim yo’q</div> :
                    hist.map((h,i)=>(
                      <div key={i} style={{ display:"flex", alignItems:"center", gap:12, padding:"8px 0", borderBottom:`1px solid ${T.border}` }}>
                        <div style={{ fontSize:11, color:T.muted, minWidth:82 }}>{h.date}</div>
                        <div style={{ flex:1, fontSize:13, color:T.text, fontWeight:600 }}>+{h.count} ta</div>
                        <div style={{ fontSize:12, color:T.muted }}>{fmt(h.buyPrice)} so’m/dona</div>
                        <div style={{ fontSize:12, color:T.success, fontWeight:600 }}>Jami: {fmt(h.buyPrice*h.count)}</div>
                      </div>
                    ))
                  }
                </div>
              </div>
              <div style={{ padding:"14px 24px", borderTop:`1px solid ${T.border}`, display:"flex", gap:10 }}>
                <Btn variant="primary" onClick={()=>{setCardAcc(null);openEdit(cardAcc);}} style={{ flex:1 }}>Tahrirlash</Btn>
                <Btn onClick={()=>setCardAcc(null)} style={{ flex:1 }}>Yopish</Btn>
              </div>
            </div>
          </div>
        );
      })()}

      {/* SOTISH MODAL */}
      <Modal open={saleModal} onClose={()=>setSaleModal(false)} title="Aksessuar sotildi">
        {saleItem && (
          <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
            <div style={{ background:T.card, borderRadius:10, padding:"14px 16px", border:`1px solid ${T.border}` }}>
              <div style={{ fontSize:15, fontWeight:700, color:T.text }}>{saleItem.name}</div>
              <div style={{ fontSize:12, color:T.muted, marginTop:4 }}>
                <Badge>{saleItem.category||"—"}</Badge>
                <span style={{ marginLeft:8 }}>Mavjud: <strong style={{ color:stockColor(saleItem.count) }}>{saleItem.count} ta</strong></span>
              </div>
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
              <Inp label="Miqdor (dona)" value={saleQty} onChange={setSaleQty} type="number" />
              <Inp label="Sotish narxi (so'm)" value={salePrice} onChange={setSalePrice} type="number" />
            </div>
            {+saleQty>0 && +salePrice>0 && (
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
                <div style={{ background:T.successDim, borderRadius:8, padding:"10px 14px" }}>
                  <div style={{ fontSize:10, color:T.success, fontWeight:600, marginBottom:3 }}>JAMI SUMMA</div>
                  <div style={{ fontSize:16, fontWeight:800, color:T.success }}>{fmt(+salePrice * +saleQty)} so’m</div>
                </div>
                <div style={{ background:T.brandDim, borderRadius:8, padding:"10px 14px" }}>
                  <div style={{ fontSize:10, color:T.brand, fontWeight:600, marginBottom:3 }}>FOYDA</div>
                  <div style={{ fontSize:16, fontWeight:800, color:T.brand }}>+{fmt((+salePrice-saleItem.buyPrice) * +saleQty)} so’m</div>
                </div>
              </div>
            )}
            <div style={{ display:"flex", gap:10 }}>
              <Btn variant="primary" onClick={doSale} style={{ flex:1 }}>✓ Sotildi</Btn>
              <Btn onClick={()=>setSaleModal(false)} style={{ flex:1 }}>Bekor</Btn>
            </div>
          </div>
        )}
      </Modal>

      {/* QAYTDI MODAL */}
      <Modal open={returnModal} onClose={()=>setReturnModal(false)} title="Tovar qaytdi">
        {returnItem && (
          <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
            <div style={{ background:T.warningDim, border:`1px solid rgba(245,158,11,0.25)`, borderRadius:10, padding:"12px 14px" }}>
              <div style={{ fontSize:14, fontWeight:700, color:T.text }}>{returnItem.name}</div>
              <div style={{ fontSize:12, color:T.warning, marginTop:3 }}>Qaytgan tovar zaxiraga qaytariladi</div>
            </div>
            <Inp label="Qaytgan miqdor (dona) *" value={returnQty} onChange={setReturnQty} type="number" />
            <Inp label="Qaytish sababi (izoh)" value={returnNote} onChange={setReturnNote} placeholder="Sifatsiz, rang mos emas..." />
            <div style={{ display:"flex", gap:10 }}>
              <Btn style={{ flex:1, background:T.warningDim, color:T.warning, border:`1px solid rgba(245,158,11,0.3)` }} onClick={doReturn}>↩ Qaytarish</Btn>
              <Btn onClick={()=>setReturnModal(false)} style={{ flex:1 }}>Bekor</Btn>
            </div>
          </div>
        )}
      </Modal>

      {/* TEZKOR QO'SHISH MODAL */}
      <Modal open={modal} onClose={()=>setModal(false)} title={editId?"Aksessuarni tahrirlash":"Yangi aksessuar qo'shish"}>
        <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
          <Inp label="Nomi *" value={form.name} onChange={sf("name")} placeholder="iPhone 14 chexoli" />
          <div>
            <div style={{ fontSize:11, color:T.muted, marginBottom:5, fontWeight:500 }}>KATEGORIYA</div>
            <select value={form.category} onChange={e=>sf("category")(e.target.value)}
              style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:13, outline:"none" }}>
              {ACC_CATEGORIES.map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
            <Inp label="Kelgan narxi (so'm)" value={form.buyPrice} onChange={sf("buyPrice")} type="number" />
            <Inp label="Sotish narxi (so'm)" value={form.sellPrice} onChange={sf("sellPrice")} type="number" />
          </div>
          {+form.buyPrice>0 && +form.sellPrice>0 && (
            <div style={{ background:T.successDim, border:`1px solid ${T.success}33`, borderRadius:8, padding:"7px 14px", fontSize:12, color:T.success }}>
              Foyda: +{fmt((+form.sellPrice||0)-(+form.buyPrice||0))} so’m
            </div>
          )}
          {editId ? (
            <div style={{ background:T.bg, borderRadius:10, padding:"12px 14px", border:`1px solid ${T.border}` }}>
              <div style={{ fontSize:11, color:T.brand, fontWeight:600, marginBottom:10 }}>📦 Yangi tovar keldi (kirim)</div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
                <Inp label="Kelgan soni" value={form.newArrivalCount} onChange={sf("newArrivalCount")} type="number" placeholder="0" />
                <Inp label="Sana" value={form.newArrivalDate} onChange={sf("newArrivalDate")} type="date" />
              </div>
              {form.newArrivalCount && +form.newArrivalCount>0 && (
                <div style={{ marginTop:10, fontSize:12, color:T.success, background:T.successDim, padding:"6px 10px", borderRadius:7 }}>
                  ✓ +{form.newArrivalCount} ta qo'shiladi → jami: {(accessories.find(a=>a.id===editId)?.count||0)+(+form.newArrivalCount)} ta
                </div>
              )}
            </div>
          ) : (
            <Inp label="Boshlang'ich soni *" value={form.count} onChange={sf("count")} type="number" />
          )}
          <div style={{ display:"flex", gap:10, marginTop:4 }}>
            <Btn variant="primary" onClick={doSave} style={{ flex:1 }}>{editId?"Saqlash":"Qo'shish"}</Btn>
            <Btn onClick={()=>setModal(false)} style={{ flex:1 }}>Bekor</Btn>
          </div>
        </div>
      </Modal>

      {/* OMMAVIY KIRIM */}
      {bulkModal && (
        <div style={{ position:"fixed", inset:0, zIndex:200, background:"rgba(0,0,0,0.88)", display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
          <div style={{ background:T.surface, border:`1px solid ${T.borderStrong}`, borderRadius:18, width:"100%", maxWidth:820, maxHeight:"92vh", display:"flex", flexDirection:"column", overflow:"hidden" }}>
            <div style={{ padding:"20px 28px", borderBottom:`1px solid ${T.border}`, display:"flex", alignItems:"center", justifyContent:"space-between", flexShrink:0 }}>
              <div>
                <div style={{ fontSize:17, fontWeight:800, color:T.text }}>Yangi aksessuarlar qo’shish</div>
                <div style={{ fontSize:12, color:T.muted, marginTop:3 }}>Bir nechta aksessuar bir vaqtda qo’shing</div>
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                <div style={{ fontSize:12, color:T.muted, background:T.card, padding:"5px 12px", borderRadius:8, border:`1px solid ${T.border}` }}>{filledRows.length} / {bulkRows.length} tayyor</div>
                <button onClick={()=>setBulkModal(false)} style={{ width:32,height:32,borderRadius:8,background:T.card,border:`1px solid ${T.border}`,color:T.muted,cursor:"pointer",fontSize:18,display:"flex",alignItems:"center",justifyContent:"center" }}>×</button>
              </div>
            </div>
            <div style={{ flex:1, overflowY:"auto", padding:"20px 28px", display:"flex", flexDirection:"column", gap:12 }}>
              {bulkRows.map((row,i)=>{
                const filled = row.name.trim()&&row.count;
                const incomplete = row.name.trim()&&!row.count;
                const profit = (+row.sellPrice||0)-(+row.buyPrice||0);
                return (
                  <div key={row.id} style={{ background:T.card, border:`1px solid ${filled?"rgba(34,197,94,0.25)":incomplete?"rgba(245,158,11,0.25)":T.border}`, borderRadius:12, padding:"16px 20px", transition:"border 0.2s" }}>
                    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:14 }}>
                      <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                        <div style={{ width:26,height:26,borderRadius:7,background:filled?T.successDim:incomplete?T.warningDim:T.subtle,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:800,color:filled?T.success:incomplete?T.warning:T.muted }}>{filled?"✓":i+1}</div>
                        <span style={{ fontSize:13, fontWeight:600, color:filled?T.success:incomplete?T.warning:T.muted }}>{filled?`${row.name}  -  ${row.category}`:incomplete?"Soni kiritilmagan!":`${i+1}-tovar`}</span>
                      </div>
                      <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                        {filled&&profit>0 && <span style={{ fontSize:12, color:T.success, background:T.successDim, padding:"3px 10px", borderRadius:6, fontWeight:600 }}>Foyda: +{fmt(profit)} so’m</span>}
                        <button onClick={()=>setBulkRows(prev=>prev.filter((_,idx)=>idx!==i))} style={{ width:26,height:26,borderRadius:6,background:"transparent",border:`1px solid ${T.border}`,color:T.muted,cursor:"pointer",fontSize:14,display:"flex",alignItems:"center",justifyContent:"center" }}>×</button>
                      </div>
                    </div>
                    <div style={{ display:"grid", gridTemplateColumns:"2fr 1.5fr", gap:10, marginBottom:10 }}>
                      <div>
                        <div style={{ fontSize:10, color:T.muted, marginBottom:5, fontWeight:600 }}>NOMI *</div>
                        <input value={row.name} onChange={e=>setBR(i,"name",e.target.value)} placeholder="iPhone 14 chexoli"
                          style={{ width:"100%", background:T.surface, border:`1px solid ${row.name.trim()?T.brand+"44":T.border}`, borderRadius:8, padding:"9px 11px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box" }} />
                      </div>
                      <div>
                        <div style={{ fontSize:10, color:T.muted, marginBottom:5, fontWeight:600 }}>KATEGORIYA</div>
                        <select value={row.category} onChange={e=>setBR(i,"category",e.target.value)}
                          style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"9px 11px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box" }}>
                          {ACC_CATEGORIES.map(c=><option key={c}>{c}</option>)}
                        </select>
                      </div>
                    </div>
                    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 0.7fr 1fr", gap:10 }}>
                      <div>
                        <div style={{ fontSize:10, color:T.muted, marginBottom:5, fontWeight:600 }}>KELGAN NARX</div>
                        <input type="number" value={row.buyPrice} onChange={e=>setBR(i,"buyPrice",e.target.value)} placeholder="0"
                          style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"9px 11px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box" }} />
                      </div>
                      <div>
                        <div style={{ fontSize:10, color:T.muted, marginBottom:5, fontWeight:600 }}>SOTISH NARX</div>
                        <input type="number" value={row.sellPrice} onChange={e=>setBR(i,"sellPrice",e.target.value)} placeholder="0"
                          style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"9px 11px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box" }} />
                      </div>
                      <div>
                        <div style={{ fontSize:10, color:incomplete?T.warning:T.muted, marginBottom:5, fontWeight:600 }}>SONI *</div>
                        <input type="number" value={row.count} onChange={e=>setBR(i,"count",e.target.value)} placeholder="0"
                          style={{ width:"100%", background:T.surface, border:`1px solid ${incomplete?"rgba(245,158,11,0.5)":row.count?T.success+"55":T.border}`, borderRadius:8, padding:"9px 11px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box", fontWeight:row.count?"700":"400" }} />
                      </div>
                      <div>
                        <div style={{ fontSize:10, color:T.muted, marginBottom:5, fontWeight:600 }}>KELGAN SANA</div>
                        <input type="date" value={row.date} onChange={e=>setBR(i,"date",e.target.value)}
                          style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"9px 11px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box" }} />
                      </div>
                    </div>
                  </div>
                );
              })}
              <button onClick={()=>setBulkRows(prev=>[...prev,emptyRow()])}
                style={{ width:"100%", padding:"13px", borderRadius:12, background:"transparent", border:`1.5px dashed ${T.border}`, color:T.muted, fontSize:13, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:7 }}
                onMouseEnter={e=>{e.currentTarget.style.borderColor=T.brand;e.currentTarget.style.color=T.brand;}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.muted;}}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 5v14M5 12h14"/></svg>
                Yangi qator qo'shish
              </button>
            </div>
            <div style={{ padding:"16px 28px", borderTop:`1px solid ${T.border}`, flexShrink:0, background:T.bg }}>
              {incompleteRows.length>0 && (
                <div style={{ background:T.warningDim, border:`1px solid rgba(245,158,11,0.2)`, borderRadius:9, padding:"9px 16px", fontSize:12, color:T.warning, marginBottom:12, display:"flex", alignItems:"center", gap:8 }}>
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
                  <span><strong>{incompleteRows.length} ta</strong> to’ldirilmagan: {incompleteRows.map(r=>`«${r.name}»`).join(", ")}</span>
                </div>
              )}
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                <div style={{ fontSize:13, color:T.muted }}>{filledRows.length>0?<span style={{ color:T.success, fontWeight:600 }}>✓ {filledRows.length} ta tayyor</span>:"Hech narsa to'ldirilmagan"}</div>
                <div style={{ display:"flex", gap:10 }}>
                  <Btn onClick={()=>setBulkModal(false)}>Bekor</Btn>
                  <Btn variant="primary" onClick={doBulkSave} style={{ minWidth:160, opacity:filledRows.length===0?0.5:1 }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="20 6 9 17 4 12"/></svg>
                    {filledRows.length>0?`${filledRows.length} tovarni saqlash`:"Saqlash"}
                  </Btn>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── REMONT ─────────────────────────────────────────────────────────────────────
function RemontPage({ repairs, setRepairs }) {
  const [modal, setModal] = useState(false);
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("Hammasi");
  const [form, setForm] = useState({ model:"", issue:"", laborPrice:"", status:"Qabul qilindi", note:"", date:today() });
  const sf = k => v => setForm(f=>({...f,[k]:v}));

  const statuses = ["Hammasi","Qabul qilindi","Kutilmoqda","Remontda","Tayyor","Berildi"];
  const filtered = [...repairs].reverse().filter(r=>{
    const q=search.toLowerCase();
    return (filterStatus==="Hammasi"||r.status===filterStatus)&&(r.model.toLowerCase().includes(q)||r.issue.toLowerCase().includes(q));
  });

  const add = () => {
    if(!form.model) return;
    setRepairs(prev=>[...prev,{id:uid(),...form,laborPrice:+form.laborPrice}]);
    setForm({model:"",issue:"",laborPrice:"",status:"Qabul qilindi",note:"",date:today()});
    setModal(false);
  };
  const updateStatus = (id,status) => setRepairs(prev=>prev.map(r=>r.id===id?{...r,status}:r));

  const statusStyle = s => ({
    "Qabul qilindi":[T.info,T.infoDim],
    "Kutilmoqda":[T.warning,T.warningDim],
    "Remontda":[T.brand,T.brandDim],
    "Tayyor":[T.success,T.successDim],
    "Berildi":[T.muted,T.subtle],
  }[s]||[T.muted,T.subtle]);

  return (
    <div>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16, flexWrap:"wrap", gap:8 }}>
        <div style={{ display:"flex", gap:8, flexWrap:"wrap", alignItems:"center" }}>
          <SearchBar value={search} onChange={setSearch} />
          {statuses.map(s=>(
            <button key={s} onClick={()=>setFilterStatus(s)} style={{ padding:"6px 11px", borderRadius:8, fontSize:11, cursor:"pointer", background:filterStatus===s?T.brand:T.card, color:filterStatus===s?"#fff":T.muted, border:`1px solid ${filterStatus===s?T.brand:T.border}`, fontWeight:filterStatus===s?600:400 }}>{s}</button>
          ))}
        </div>
        <Btn variant="primary" onClick={()=>setModal(true)}>+ Yangi remont</Btn>
      </div>

      <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
        {filtered.map(r=>{
          const [sc,sbg]=statusStyle(r.status);
          return (
            <Card key={r.id} style={{ padding:"13px 18px" }}>
              <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                <div style={{ flex:1 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:3 }}>
                    <span style={{ fontSize:14, fontWeight:700, color:T.text }}>{r.model}</span>
                    <Badge color={sc} bg={sbg}>{r.status}</Badge>
                  </div>
                  <div style={{ fontSize:12, color:T.muted }}>{r.issue} · {r.date}</div>
                  {r.note && <div style={{ fontSize:12, color:T.muted, marginTop:2, fontStyle:"italic" }}>{r.note}</div>}
                </div>
                <div style={{ fontSize:16, fontWeight:800, color:T.brand, minWidth:120, textAlign:"right" }}>{fmt(r.laborPrice)} so’m</div>
                <select value={r.status} onChange={e=>updateStatus(r.id,e.target.value)}
                  style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"6px 10px", color:T.text, fontSize:12, outline:"none", cursor:"pointer" }}>
                  {["Qabul qilindi","Kutilmoqda","Remontda","Tayyor","Berildi"].map(s=><option key={s}>{s}</option>)}
                </select>
                <Btn small variant="danger" onClick={()=>setRepairs(prev=>prev.filter(x=>x.id!==r.id))}>O’chir</Btn>
              </div>
            </Card>
          );
        })}
        {filtered.length===0 && <div style={{ textAlign:"center", color:T.muted, padding:48, fontSize:14 }}>Remontlar topilmadi</div>}
      </div>

      <Modal open={modal} onClose={()=>setModal(false)} title="Yangi remont qabul qilish">
        <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
          <Inp label="Telefon modeli *" value={form.model} onChange={sf("model")} placeholder="iPhone 13 Pro" />
          <Inp label="Muammo / Xizmat turi" value={form.issue} onChange={sf("issue")} placeholder="Ekran almashtirish" />
          <Inp label="Narxi (so'm)" value={form.laborPrice} onChange={sf("laborPrice")} type="number" />
          <Inp label="Sana" value={form.date} onChange={sf("date")} type="date" />
          <Sel label="Holat" value={form.status} onChange={sf("status")} options={["Qabul qilindi","Kutilmoqda","Remontda","Tayyor","Berildi"]} />
          <Inp label="Izoh" value={form.note} onChange={sf("note")} placeholder="Ixtiyoriy..." />
          <div style={{ display:"flex", gap:10, marginTop:4 }}>
            <Btn variant="primary" onClick={add} style={{ flex:1 }}>Qabul qilish</Btn>
            <Btn onClick={()=>setModal(false)} style={{ flex:1 }}>Bekor</Btn>
          </div>
        </div>
      </Modal>
    </div>
  );
}

// ── MOLIYA ─────────────────────────────────────────────────────────────────────
const INCOME_CATS = ["Remont xizmati","Zapchast savdosi","Aksessuar savdosi","Boshqa daromad"];
const LOSS_CATS   = ["Shikast / Singan","Yo'qolgan tovar","Qaytarilgan tovar","Ish haqi xarajat","Ijara / kommunal","Tovar xarajati","Jarima / jarimalar","Boshqa zarar"];

function MoliyaPage({ repairs, losses, setLosses, sales, incomes, setIncomes }) {
  const [tab, setTab] = useState("barchasi");
  const [incomeModal, setIncomeModal] = useState(false);
  const [lossModal, setLossModal] = useState(false);
  const [period, setPeriod] = useState("oy");
  const [calMode, setCalMode] = useState(false); // custom range
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo]   = useState("");
  const [iForm, setIForm] = useState({ description:"", amount:"", category:"Remont xizmati", date:today(), note:"" });
  const [lForm, setLForm] = useState({ description:"", amount:"", category:"Shikast / Singan", date:today(), note:"" });
  const sf = k => v => setIForm(f=>({...f,[k]:v}));
  const lf = k => v => setLForm(f=>({...f,[k]:v}));

  // ── hisob-kitob ──────────────────────────────────────────────────────────────
  const repairIncome = repairs.filter(r=>r.status==="Tayyor"||r.status==="Berildi").reduce((s,r)=>s+(r.laborPrice||0),0);
  const saleProfit   = sales.filter(s=>s.qty>0).reduce((s,x)=>s+(x.profit||x.price||0),0); // sof foyda (narx - tannarx)
  const saleIncome   = sales.filter(s=>s.qty>0).reduce((s,x)=>s+(x.price||0),0);           // umumiy savdo
  const returnTotal  = sales.filter(s=>s.qty<0).reduce((s,x)=>s+Math.abs(x.price||0),0);
  const manualIncome = incomes.reduce((s,x)=>s+(x.amount||0),0);
  const totalIncome  = repairIncome + saleProfit + manualIncome; // sof hisob
  const totalLoss    = losses.reduce((s,l)=>s+(l.amount||0),0) + returnTotal;
  const net          = totalIncome - totalLoss;

  // Period filter helper — custom range yoki belgilangan davr
  const inPeriod = (dateStr) => {
    const d = new Date(dateStr||today());
    const now = new Date(); now.setHours(0,0,0,0);
    // Custom calendar range
    if(calMode) {
      if(dateFrom && dateTo) return d >= new Date(dateFrom) && d <= new Date(dateTo+"T23:59:59");
      if(dateFrom) return d >= new Date(dateFrom);
      if(dateTo)   return d <= new Date(dateTo+"T23:59:59");
      return true;
    }
    if(period==="hammasi") return true;
    if(period==="kun")  return dateStr===today();
    if(period==="hafta") { const w=new Date(now); w.setDate(w.getDate()-7); return d>=w; }
    if(period==="oy")    return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();
    if(period==="chorak") {
      const q = Math.floor(now.getMonth()/3);
      const qStart = new Date(now.getFullYear(), q*3, 1);
      const qEnd   = new Date(now.getFullYear(), q*3+3, 0);
      return d>=qStart && d<=qEnd;
    }
    if(period==="yarim") {
      const half = now.getMonth()<6 ? 0 : 6;
      const hStart = new Date(now.getFullYear(), half, 1);
      const hEnd   = new Date(now.getFullYear(), half+6, 0);
      return d>=hStart && d<=hEnd;
    }
    if(period==="yil") return d.getFullYear()===now.getFullYear();
    return true;
  };

  // period label for display
  const periodLabel = () => {
    if(calMode) {
      if(dateFrom&&dateTo) return `${dateFrom}  -  ${dateTo}`;
      if(dateFrom) return `${dateFrom} dan`;
      if(dateTo)   return `${dateTo} gacha`;
      return "Sana tanlang";
    }
    return PERIODS.find(p=>p.k===period)?.l||period;
  };

  // Build unified transaction list
  const allTx = useMemo(()=>{
    const list = [];
    // Repairs
    repairs.filter(r=>(r.status==="Tayyor"||r.status==="Berildi")&&inPeriod(r.date)).forEach(r=>
      list.push({id:r.id,date:r.date,type:"daromad",category:"Remont xizmati",description:`${r.model}  -  ${r.issue||"Remont"}`,amount:r.laborPrice||0,note:r.note||"",source:"remont"})
    );
    // Sales
    sales.filter(s=>inPeriod(s.date)).forEach(s=>
      s.qty>0
        ? list.push({id:s.id,date:s.date,type:"daromad",category:s.type==="aksessuar"?"Aksessuar savdosi":"Zapchast savdosi",description:`${s.name} × ${s.qty} ta`,amount:s.profit||s.price||0,note:`Savdo: ${fmt(s.price)} · Foyda: ${fmt(s.profit||0)}`,source:"savdo"})
        : list.push({id:s.id,date:s.date,type:"zarar",category:"Qaytarilgan tovar",description:`Qaytdi: ${s.name} × ${Math.abs(s.qty)} ta`,amount:Math.abs(s.price||0),note:s.note||"",source:"qaytdi"})
    );
    // Manual incomes
    incomes.filter(x=>inPeriod(x.date)).forEach(x=>
      list.push({id:x.id,date:x.date,type:"daromad",category:x.category,description:x.description,amount:x.amount||0,note:x.note||"",source:"qolda",_id:x.id})
    );
    // Losses
    losses.filter(l=>inPeriod(l.date)).forEach(l=>
      list.push({id:l.id,date:l.date,type:"zarar",category:l.category,description:l.description,amount:l.amount||0,note:l.note||"",source:"zarar",_id:l.id})
    );
    return list.sort((a,b)=>b.date.localeCompare(a.date));
  },[repairs,sales,incomes,losses,period,calMode,dateFrom,dateTo]);

  const filtered = tab==="barchasi" ? allTx : allTx.filter(x=>x.type===tab);
  const periodIncome = allTx.filter(x=>x.type==="daromad").reduce((s,x)=>s+x.amount,0);
  const periodLoss   = allTx.filter(x=>x.type==="zarar").reduce((s,x)=>s+x.amount,0);
  const periodNet    = periodIncome - periodLoss;

  // Category breakdown for period
  const catBreakdown = useMemo(()=>{
    const map = {};
    allTx.forEach(x=>{ map[x.category]=(map[x.category]||0)+x.amount; });
    return Object.entries(map).sort((a,b)=>b[1]-a[1]);
  },[allTx]);

  const addIncome = () => {
    if(!iForm.description||!iForm.amount) return;
    setIncomes(prev=>[...prev,{id:uid(),...iForm,amount:+iForm.amount}]);
    setIForm({description:"",amount:"",category:"Remont xizmati",date:today(),note:""});
    setIncomeModal(false);
  };
  const addLoss = () => {
    if(!lForm.description||!lForm.amount) return;
    setLosses(prev=>[...prev,{id:uid(),...lForm,amount:+lForm.amount}]);
    setLForm({description:"",amount:"",category:"Shikast / Singan",date:today(),note:""});
    setLossModal(false);
  };
  const deleteTx = (tx) => {
    if(tx.source==="zarar"||tx.source==="qaytdi") setLosses(prev=>prev.filter(x=>x.id!==tx.id));
    else if(tx.source==="qolda") setIncomes(prev=>prev.filter(x=>x.id!==tx.id));
  };

  const PERIODS = [
    {k:"kun",l:"Bugun"},{k:"hafta",l:"Hafta"},{k:"oy",l:"Bu oy"},
    {k:"chorak",l:"Chorak"},{k:"yarim",l:"Yarim yil"},{k:"yil",l:"Bu yil"},{k:"hammasi",l:"Hammasi"}
  ];

  const sourceColor = s => ({remont:T.brand,savdo:T.success,zarar:T.danger,qaytdi:T.warning,qolda:T.info}[s]||T.muted);
  const sourceBg    = s => ({remont:T.brandDim,savdo:T.successDim,zarar:T.dangerDim,qaytdi:T.warningDim,qolda:T.infoDim}[s]||T.subtle);

  return (
    <div>
      {/* ── TOP 3 STAT CARDS ─────────────────────────────────────────────────── */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:12, marginBottom:16 }}>
        <div style={{ background:T.successDim, border:`1px solid ${T.success}33`, borderRadius:14, padding:"18px 20px" }}>
          <div style={{ fontSize:11, color:T.success, fontWeight:700, marginBottom:8, letterSpacing:0.5 }}>JAMI SOF DAROMAD</div>
          <div style={{ fontSize:26, fontWeight:900, color:T.text, marginBottom:6 }}>{fmt(totalIncome)} so’m</div>
          <div style={{ display:"flex", gap:12, flexWrap:"wrap" }}>
            {[{l:"Remont",v:repairIncome},{l:"Savdo foydasi",v:saleProfit},{l:"Qo’lda",v:manualIncome}].map(x=>(
              <div key={x.l} style={{ fontSize:11, color:T.muted }}>{x.l}: <span style={{ color:T.success, fontWeight:600 }}>{fmt(x.v)}</span></div>
            ))}
            <div style={{ fontSize:11, color:T.muted }}>Savdo aylanmasi: <span style={{ color:T.muted, fontWeight:600 }}>{fmt(saleIncome)}</span></div>
          </div>
        </div>
        <div style={{ background:T.dangerDim, border:`1px solid ${T.danger}33`, borderRadius:14, padding:"18px 20px" }}>
          <div style={{ fontSize:11, color:T.danger, fontWeight:700, marginBottom:8, letterSpacing:0.5 }}>JAMI ZARAR</div>
          <div style={{ fontSize:26, fontWeight:900, color:T.text, marginBottom:6 }}>{fmt(totalLoss)} so’m</div>
          <div style={{ display:"flex", gap:12, flexWrap:"wrap" }}>
            {[{l:"Hodisalar",v:losses.length+" ta"},{l:"Qaytdilar",v:fmt(returnTotal)+" so'm"}].map(x=>(
              <div key={x.l} style={{ fontSize:11, color:T.muted }}>{x.l}: <span style={{ color:T.danger, fontWeight:600 }}>{x.v}</span></div>
            ))}
          </div>
        </div>
        <div style={{ background:net>=0?T.successDim:T.dangerDim, border:`1px solid ${net>=0?T.success:T.danger}33`, borderRadius:14, padding:"18px 20px" }}>
          <div style={{ fontSize:11, color:net>=0?T.success:T.danger, fontWeight:700, marginBottom:8, letterSpacing:0.5 }}>SOF FOYDA</div>
          <div style={{ fontSize:26, fontWeight:900, color:T.text, marginBottom:6 }}>{fmt(net)} so’m</div>
          <div style={{ fontSize:12, color:net>=0?T.success:T.danger, fontWeight:600 }}>{net>=0?"✓ Foydada":"✗ Zararda"}</div>
        </div>
      </div>

      {/* ── PERIOD FILTER + CALENDAR + ACTION BUTTONS ───────────────────────── */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:14, flexWrap:"wrap", gap:10 }}>
        <div style={{ display:"flex", gap:5, flexWrap:"wrap", alignItems:"center" }}>
          {PERIODS.map(p=>(
            <button key={p.k} onClick={()=>{setPeriod(p.k);setCalMode(false);}} style={{
              padding:"6px 12px", borderRadius:8, fontSize:12, cursor:"pointer",
              background:!calMode&&period===p.k?T.brand:T.card,
              color:!calMode&&period===p.k?"#fff":T.muted,
              border:`1px solid ${!calMode&&period===p.k?T.brand:T.border}`,
              fontWeight:!calMode&&period===p.k?600:400
            }}>{p.l}</button>
          ))}
          <button onClick={()=>setCalMode(v=>!v)} style={{
            padding:"6px 12px", borderRadius:8, fontSize:12, cursor:"pointer", display:"flex", alignItems:"center", gap:5,
            background:calMode?T.infoDim:T.card, color:calMode?T.info:T.muted,
            border:`1px solid ${calMode?T.info:T.border}`, fontWeight:calMode?600:400
          }}>
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
            Sana tanlash
          </button>
        </div>
        <div style={{ display:"flex", gap:8 }}>
          <Btn style={{ background:T.successDim, color:T.success, border:`1px solid ${T.success}44` }} onClick={()=>setIncomeModal(true)}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 5v14M5 12h14"/></svg>
            Daromad qo'shish
          </Btn>
          <Btn variant="danger" onClick={()=>setLossModal(true)}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14"/></svg>
            Zarar qo'shish
          </Btn>
        </div>
      </div>

      {/* ── PERIOD MINI STATS ────────────────────────────────────────────────── */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:10, marginBottom:20 }}>
        {[
          {label:`${periodLabel()}  -  daromad`, val:fmt(periodIncome)+" so'm", color:T.success, bg:T.successDim},
          {label:`${periodLabel()}  -  zarar`,   val:fmt(periodLoss)+" so'm",   color:T.danger,  bg:T.dangerDim},
          {label:"Davr sof foydasi", val:fmt(periodNet)+" so'm", color:periodNet>=0?T.success:T.danger, bg:periodNet>=0?T.successDim:T.dangerDim},
          {label:"Tranzaksiyalar",   val:allTx.length+" ta",     color:T.brand,   bg:T.brandDim},
        ].map((c,i)=>(
          <div key={i} style={{ background:c.bg, borderRadius:10, padding:"12px 16px" }}>
            <div style={{ fontSize:10, color:c.color, fontWeight:700, marginBottom:4, opacity:0.85 }}>{c.label.toUpperCase()}</div>
            <div style={{ fontSize:17, fontWeight:800, color:T.text }}>{c.val}</div>
          </div>
        ))}
      </div>

      {/* ── FULL WIDTH HISTORY ───────────────────────────────────────────────── */}
      <Card style={{ padding:0, overflow:"hidden" }}>
        {/* History table: alohida period filter */}
        <div style={{ padding:"12px 16px", borderBottom:`1px solid ${T.border}`, background:T.surface }}>
          {/* Row 1: type tabs + count */}
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10 }}>
            <div style={{ display:"flex", gap:6, alignItems:"center" }}>
              {[{k:"barchasi",l:"Barchasi"},{k:"daromad",l:"Daromadlar"},{k:"zarar",l:"Zararlar"}].map(t=>(
                <button key={t.k} onClick={()=>setTab(t.k)} style={{ padding:"5px 13px", borderRadius:7, fontSize:12, cursor:"pointer", background:tab===t.k?T.brand:T.card, color:tab===t.k?"#fff":T.muted, border:`1px solid ${tab===t.k?T.brand:T.border}`, fontWeight:tab===t.k?600:400 }}>{t.l}</button>
              ))}
            </div>
            <div style={{ fontSize:12, color:T.muted }}>{filtered.length} ta yozuv</div>
          </div>

          {/* Row 2: period filter tugmalari */}
          <div style={{ display:"flex", gap:5, flexWrap:"wrap", alignItems:"center" }}>
            {PERIODS.map(p=>(
              <button key={p.k} onClick={()=>{setPeriod(p.k);setCalMode(false);}} style={{
                padding:"5px 11px", borderRadius:7, fontSize:11, cursor:"pointer",
                background:!calMode&&period===p.k?T.brand:T.surface,
                color:!calMode&&period===p.k?"#fff":T.muted,
                border:`1px solid ${!calMode&&period===p.k?T.brand:T.border}`,
                fontWeight:!calMode&&period===p.k?600:400
              }}>{p.l}</button>
            ))}
            {/* Calendar toggle */}
            <button onClick={()=>setCalMode(v=>!v)} style={{
              padding:"5px 11px", borderRadius:7, fontSize:11, cursor:"pointer",
              display:"flex", alignItems:"center", gap:5,
              background:calMode?T.infoDim:T.surface,
              color:calMode?T.info:T.muted,
              border:`1px solid ${calMode?T.info:T.border}`,
              fontWeight:calMode?600:400
            }}>
              <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
              Sana tanlash
            </button>
            {/* Active label */}
            <span style={{ fontSize:11, color:T.brand, fontWeight:600, marginLeft:4 }}>
              {calMode ? "📅 " : "· "}{periodLabel()}
            </span>
          </div>

          {/* Row 3: calendar range — faqat calMode da */}
          {calMode && (
            <div style={{ display:"flex", alignItems:"center", gap:8, marginTop:10, background:T.card, border:`1px solid ${T.info}44`, borderRadius:9, padding:"9px 14px", flexWrap:"wrap" }}>
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={T.info} strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
              <span style={{ fontSize:12, color:T.muted }}>Dan:</span>
              <input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)}
                style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"5px 10px", color:T.text, fontSize:12, outline:"none" }} />
              <span style={{ color:T.muted }}>—</span>
              <span style={{ fontSize:12, color:T.muted }}>Gacha:</span>
              <input type="date" value={dateTo} onChange={e=>setDateTo(e.target.value)}
                style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"5px 10px", color:T.text, fontSize:12, outline:"none" }} />
              {(dateFrom||dateTo) && (
                <button onClick={()=>{setDateFrom("");setDateTo("");}} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:6, color:T.muted, cursor:"pointer", padding:"3px 8px", fontSize:11 }}>× Tozalash</button>
              )}
              {dateFrom && dateTo && (
                <div style={{ fontSize:11, color:T.info, background:T.infoDim, padding:"3px 10px", borderRadius:6, fontWeight:600 }}>
                  {Math.round((new Date(dateTo)-new Date(dateFrom))/(1000*60*60*24))+1} kun
                </div>
              )}
            </div>
          )}
        </div>

        {/* Table head */}
        <table style={{ width:"100%", borderCollapse:"collapse" }}>
          <thead>
            <tr style={{ borderBottom:`1px solid ${T.border}` }}>
              {["Tur","Sana","Tavsif","Kategoriya","Izoh","Summa",""].map((h,i)=>(
                <th key={i} style={{ padding:"9px 14px", textAlign:"left", fontSize:11, color:T.muted, fontWeight:500, background:T.surface, whiteSpace:"nowrap" }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.length===0 ? (
              <tr><td colSpan={7} style={{ padding:48, textAlign:"center", color:T.muted, fontSize:13 }}>Bu davrda yozuvlar yo’q</td></tr>
            ) : filtered.map((tx,i)=>(
              <tr key={tx.id||i} style={{ borderBottom:`1px solid ${T.border}` }}>
                {/* Tur icon */}
                <td style={{ padding:"10px 14px" }}>
                  <div style={{ width:32, height:32, borderRadius:8, background:tx.type==="daromad"?T.successDim:T.dangerDim, display:"flex", alignItems:"center", justifyContent:"center" }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={tx.type==="daromad"?T.success:T.danger} strokeWidth="2.5">
                      {tx.type==="daromad"
                        ? <><line x1="12" y1="19" x2="12" y2="5"/><polyline points="5 12 12 5 19 12"/></>
                        : <><line x1="12" y1="5" x2="12" y2="19"/><polyline points="19 12 12 19 5 12"/></>}
                    </svg>
                  </div>
                </td>
                {/* Sana */}
                <td style={{ padding:"10px 14px", fontSize:12, color:T.muted, whiteSpace:"nowrap" }}>{tx.date}</td>
                {/* Tavsif */}
                <td style={{ padding:"10px 14px", fontSize:13, color:T.text, fontWeight:500, maxWidth:220 }}>
                  <div style={{ overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{tx.description}</div>
                </td>
                {/* Kategoriya */}
                <td style={{ padding:"10px 14px" }}>
                  <Badge color={sourceColor(tx.source)} bg={sourceBg(tx.source)}>{tx.category}</Badge>
                </td>
                {/* Izoh */}
                <td style={{ padding:"10px 14px", fontSize:12, color:T.muted, maxWidth:160 }}>
                  <div style={{ overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{tx.note||"—"}</div>
                </td>
                {/* Summa */}
                <td style={{ padding:"10px 14px", fontSize:14, fontWeight:800, color:tx.type==="daromad"?T.success:T.danger, whiteSpace:"nowrap" }}>
                  {tx.type==="daromad"?"+":"-"}{fmt(tx.amount)} so’m
                </td>
                {/* O'chirish */}
                <td style={{ padding:"10px 14px" }}>
                  {(tx.source==="qolda"||tx.source==="zarar"||tx.source==="qaytdi") && (
                    <button onClick={()=>deleteTx(tx)} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:6, color:T.muted, cursor:"pointer", padding:"3px 8px", fontSize:12 }}
                      onMouseEnter={e=>{e.currentTarget.style.color=T.danger;e.currentTarget.style.borderColor=T.danger;}}
                      onMouseLeave={e=>{e.currentTarget.style.color=T.muted;e.currentTarget.style.borderColor=T.border;}}>
                      O'chir
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
          {/* JAMI footer */}
          {filtered.length>0 && (
            <tfoot>
              <tr style={{ borderTop:`2px solid ${T.border}`, background:T.surface }}>
                <td colSpan={5} style={{ padding:"11px 14px", fontSize:12, color:T.muted, fontWeight:600 }}>JAMI ({filtered.length} ta yozuv)</td>
                <td style={{ padding:"11px 14px", fontSize:14, fontWeight:900, color:periodNet>=0?T.success:T.danger }}>
                  {tab==="barchasi" ? (periodNet>=0?"+":"")+fmt(periodNet)+" so'm"
                   : tab==="daromad" ? "+"+fmt(periodIncome)+" so'm"
                   : "-"+fmt(periodLoss)+" so'm"}
                </td>
                <td />
              </tr>
            </tfoot>
          )}
        </table>
      </Card>

      {/* DAROMAD QO'SHISH MODAL */}
      <Modal open={incomeModal} onClose={()=>setIncomeModal(false)} title="Daromad qo'shish">
        <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
          <div style={{ background:T.successDim, border:`1px solid ${T.success}33`, borderRadius:8, padding:"8px 14px", fontSize:12, color:T.success }}>
            Remont va savdodan tashqari qo'shimcha daromadlar kiritiladi
          </div>
          <Inp label="Tavsif *" value={iForm.description} onChange={sf("description")} placeholder="Aksessuar yetkazib berdik..." />
          <Inp label="Miqdor (so'm) *" value={iForm.amount} onChange={sf("amount")} type="number" />
          <div>
            <div style={{ fontSize:11, color:T.muted, marginBottom:5, fontWeight:500 }}>KATEGORIYA</div>
            <select value={iForm.category} onChange={e=>sf("category")(e.target.value)} style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:13, outline:"none" }}>
              {INCOME_CATS.map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
          <Inp label="Izoh (ixtiyoriy)" value={iForm.note} onChange={sf("note")} placeholder="Qo'shimcha ma'lumot..." />
          <Inp label="Sana" value={iForm.date} onChange={sf("date")} type="date" />
          <div style={{ display:"flex", gap:10, marginTop:4 }}>
            <Btn style={{ flex:1, background:T.successDim, color:T.success, border:`1px solid ${T.success}44` }} onClick={addIncome}>+ Qo’shish</Btn>
            <Btn onClick={()=>setIncomeModal(false)} style={{ flex:1 }}>Bekor</Btn>
          </div>
        </div>
      </Modal>

      {/* ZARAR QO'SHISH MODAL */}
      <Modal open={lossModal} onClose={()=>setLossModal(false)} title="Zarar qo'shish">
        <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
          <div style={{ background:T.dangerDim, border:`1px solid ${T.danger}33`, borderRadius:8, padding:"8px 14px", fontSize:12, color:T.danger }}>
            Misol: ekran sindirdik, tovar yo'qoldi, qaytarildi...
          </div>
          <Inp label="Tavsif *" value={lForm.description} onChange={lf("description")} placeholder="Bugun ekran sindirdik..." />
          <Inp label="Miqdor (so'm) *" value={lForm.amount} onChange={lf("amount")} type="number" />
          <div>
            <div style={{ fontSize:11, color:T.muted, marginBottom:5, fontWeight:500 }}>KATEGORIYA</div>
            <select value={lForm.category} onChange={e=>lf("category")(e.target.value)} style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:13, outline:"none" }}>
              {LOSS_CATS.map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
          <Inp label="Izoh (ixtiyoriy)" value={lForm.note} onChange={lf("note")} placeholder="Qo'shimcha tafsilotlar..." />
          <Inp label="Sana" value={lForm.date} onChange={lf("date")} type="date" />
          <div style={{ display:"flex", gap:10, marginTop:4 }}>
            <Btn variant="danger" onClick={addLoss} style={{ flex:1 }}>+ Qo’shish</Btn>
            <Btn onClick={()=>setLossModal(false)} style={{ flex:1 }}>Bekor</Btn>
          </div>
        </div>
      </Modal>
    </div>
  );
}

// ── QARZLAR ────────────────────────────────────────────────────────────────────
const DEBT_PERIODS = [
  {k:"hafta",l:"Hafta"},{k:"oy",l:"Bu oy"},{k:"chorak",l:"Chorak"},
  {k:"yarim",l:"Yarim yil"},{k:"yil",l:"Bu yil"},{k:"hammasi",l:"Hammasi"}
];

function QarzlarPage({ debts, setDebts }) {
  const [modal, setModal] = useState(false);
  const [editModal, setEditModal] = useState(false);
  const [editDebt, setEditDebt] = useState(null);
  const [payConfirm, setPayConfirm] = useState(null); // {id, name, amount}
  const [partialModal, setPartialModal] = useState(false);
  const [selectedDebt, setSelectedDebt] = useState(null);
  const [partialAmt, setPartialAmt] = useState("");
  const [partialNote, setPartialNote] = useState("");
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [personCard, setPersonCard] = useState(null);
  const [expandedPerson, setExpandedPerson] = useState(null);
  const [pcPeriod, setPcPeriod] = useState("hammasi");
  const [pcCalMode, setPcCalMode] = useState(false);
  const [pcDateFrom, setPcDateFrom] = useState("");
  const [pcDateTo, setPcDateTo] = useState("");
  const [search, setSearch] = useState("");
  const [filterType, setFilterType] = useState("Hammasi");
  const [period, setPeriod] = useState("hammasi");
  const [calMode, setCalMode] = useState(false);
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [sortCol, setSortCol] = useState("date");
  const [sortDir, setSortDir] = useState("desc");
  const [form, setForm] = useState({ name:"", type:"Mijoz", amount:"", dueDate:"", date:today(), note:"", category:"Tovar qarzi" });
  const [editForm, setEditForm] = useState({});
  const sf  = k => v => setForm(f=>({...f,[k]:v}));
  const esf = k => v => setEditForm(f=>({...f,[k]:v}));

  // Debt payment history: [{id, debtId, personName, action, amount, date, note}]
  const [debtHistory, setDebtHistory] = useState(() => {
    try { const s=localStorage.getItem("shox_debtHistory"); return s?JSON.parse(s):[]; } catch{return [];}
  });
  const saveHist = (h) => { setDebtHistory(h); try{localStorage.setItem("shox_debtHistory",JSON.stringify(h));}catch{} };

  const [modalType, setModalType] = useState("Mijoz");

  const openModal = (type) => {
    setModalType(type);
    setForm({name:"",type,amount:"",dueDate:"",date:today(),note:"",category:"Tovar qarzi"});
    setModal(true);
  };

  const openEdit = (d) => {
    setEditDebt(d);
    setEditForm({name:d.name,type:d.type,amount:d.amount,dueDate:d.dueDate||"",date:d.date,note:d.note||""});
    setEditModal(true);
  };

  const saveEdit = () => {
    if(!editDebt) return;
    setDebts(prev=>prev.map(d=>d.id===editDebt.id?{...d,...editForm,amount:+editForm.amount}:d));
    setEditModal(false); setEditDebt(null);
  };

  // Period filter
  const inPeriod = (dateStr) => {
    const d = new Date(dateStr||today());
    const now = new Date(); now.setHours(0,0,0,0);
    if(calMode) {
      if(dateFrom&&dateTo) return d>=new Date(dateFrom)&&d<=new Date(dateTo+"T23:59:59");
      if(dateFrom) return d>=new Date(dateFrom);
      if(dateTo)   return d<=new Date(dateTo+"T23:59:59");
      return true;
    }
    if(period==="hammasi") return true;
    if(period==="hafta")   { const w=new Date(now); w.setDate(w.getDate()-7); return d>=w; }
    if(period==="oy")      return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();
    if(period==="chorak")  { const q=Math.floor(now.getMonth()/3); const qs=new Date(now.getFullYear(),q*3,1); const qe=new Date(now.getFullYear(),q*3+3,0); return d>=qs&&d<=qe; }
    if(period==="yarim")   { const h=now.getMonth()<6?0:6; const hs=new Date(now.getFullYear(),h,1); const he=new Date(now.getFullYear(),h+6,0); return d>=hs&&d<=he; }
    if(period==="yil")     return d.getFullYear()===now.getFullYear();
    return true;
  };

  const periodLabel = () => {
    if(calMode) { if(dateFrom&&dateTo) return `${dateFrom}  -  ${dateTo}`; if(dateFrom) return `${dateFrom} dan`; if(dateTo) return `${dateTo} gacha`; return "Sana"; }
    return DEBT_PERIODS.find(p=>p.k===period)?.l||period;
  };

  // Filtered & sorted
  const filtered = useMemo(()=>{
    const q = search.toLowerCase();
    let list = debts.filter(d=>{
      const matchType = filterType==="Hammasi" || d.type===filterType;
      const matchSearch = !q || (d.name||"").toLowerCase().includes(q) || (d.note||"").toLowerCase().includes(q);
      const matchPeriod = inPeriod(d.date);
      return matchType && matchSearch && matchPeriod;
    });
    return [...list].sort((a,b)=>{
      const av = sortCol==="amount"?a.amount:sortCol==="name"?(a.name||"").toLowerCase():a.date||"";
      const bv = sortCol==="amount"?b.amount:sortCol==="name"?(b.name||"").toLowerCase():b.date||"";
      if(av<bv) return sortDir==="asc"?-1:1;
      if(av>bv) return sortDir==="asc"?1:-1;
      return 0;
    });
  }, [debts, search, filterType, period, calMode, dateFrom, dateTo, sortCol, sortDir]);

  // Stats
  const allMijoz = debts.filter(d=>d.type==="Mijoz");
  const allYetk  = debts.filter(d=>d.type==="Yetkazuvchi");
  const mijozTotal = allMijoz.reduce((s,d)=>s+(d.amount||0),0);
  const yetkTotal  = allYetk.reduce((s,d)=>s+(d.amount||0),0);
  const balance    = mijozTotal - yetkTotal;

  // Overdue debts
  const now = today();
  const overdue = debts.filter(d=>d.dueDate && d.dueDate < now);

  // Grouped by person for personCard
  const personDebts = personCard ? debts.filter(d=>d.name===personCard) : [];
  const personTotal = personDebts.reduce((s,d)=>s+(d.amount||0),0);

  // Person card period filter
  const inPcPeriod = (dateStr) => {
    const d = new Date(dateStr||today());
    const n = new Date(); n.setHours(0,0,0,0);
    if(pcCalMode) {
      if(pcDateFrom&&pcDateTo) return d>=new Date(pcDateFrom)&&d<=new Date(pcDateTo+"T23:59:59");
      if(pcDateFrom) return d>=new Date(pcDateFrom);
      if(pcDateTo)   return d<=new Date(pcDateTo+"T23:59:59");
      return true;
    }
    if(pcPeriod==="hammasi") return true;
    if(pcPeriod==="hafta")   { const w=new Date(n); w.setDate(w.getDate()-7); return d>=w; }
    if(pcPeriod==="oy")      return d.getMonth()===n.getMonth()&&d.getFullYear()===n.getFullYear();
    if(pcPeriod==="chorak")  { const q=Math.floor(n.getMonth()/3); return d>=new Date(n.getFullYear(),q*3,1)&&d<=new Date(n.getFullYear(),q*3+3,0); }
    if(pcPeriod==="yarim")   { const h=n.getMonth()<6?0:6; return d>=new Date(n.getFullYear(),h,1)&&d<=new Date(n.getFullYear(),h+6,0); }
    if(pcPeriod==="yil")     return d.getFullYear()===n.getFullYear();
    return true;
  };
  const pcPeriods = [{k:"hafta",l:"Hafta"},{k:"oy",l:"Bu oy"},{k:"chorak",l:"Chorak"},{k:"yarim",l:"Yarim yil"},{k:"yil",l:"Bu yil"},{k:"hammasi",l:"Hammasi"}];
  const filteredPersonHistory = debtHistory.filter(h=>h.personName===personCard && inPcPeriod(h.date));

  const add = () => {
    if(!form.name||!form.amount) return;
    const newId = uid();
    setDebts(prev=>[...prev,{id:newId,...form,amount:+form.amount}]);
    const newHist = [...debtHistory, {id:uid(),debtId:newId,personName:form.name,action:"qo'shildi",amount:+form.amount,date:today(),note:form.note||""}];
    saveHist(newHist);
    setForm({name:"",type:"Mijoz",amount:"",dueDate:"",date:today(),note:"",category:"Tovar qarzi"});
    setModal(false);
  };

  const payFull = (id) => {
    const d = debts.find(x=>x.id===id);
    if(d) saveHist([...debtHistory,{id:uid(),debtId:id,personName:d.name,action:"to'liq to'landi",amount:d.amount,date:today(),note:""}]);
    setDebts(prev=>prev.filter(x=>x.id!==id));
    setPayConfirm(null);
  };
  const payPartial = () => {
    if(!selectedDebt||!+partialAmt) return;
    const rem = selectedDebt.amount - +partialAmt;
    const histEntry = {id:uid(),debtId:selectedDebt.id,personName:selectedDebt.name,action:"qisman to'landi",amount:+partialAmt,date:today(),note:partialNote||""};
    if(rem<=0) {
      saveHist([...debtHistory,histEntry]);
      setDebts(prev=>prev.filter(x=>x.id!==selectedDebt.id));
    } else {
      saveHist([...debtHistory,histEntry]);
      setDebts(prev=>prev.map(d=>d.id===selectedDebt.id?{...d,amount:rem}:d));
    }
    setPartialModal(false); setSelectedDebt(null); setPartialAmt(""); setPartialNote("");
  };

  const handleSort = col => { if(sortCol===col) setSortDir(d=>d==="asc"?"desc":"asc"); else {setSortCol(col);setSortDir("asc");}; };
  const SortArrow = ({col}) => sortCol!==col
    ? <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke={T.muted} strokeWidth="2" opacity="0.4"><path d="M7 15l5 5 5-5M7 9l5-5 5 5"/></svg>
    : sortDir==="asc" ? <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke={T.brand} strokeWidth="2.5"><path d="M7 15l5 5 5-5"/></svg>
                      : <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke={T.brand} strokeWidth="2.5"><path d="M7 9l5-5 5 5"/></svg>;
  const thS = col => ({ padding:"9px 14px", textAlign:"left", fontSize:11, fontWeight:500, background:T.surface, cursor:"pointer", userSelect:"none", color:sortCol===col?T.brand:T.muted, whiteSpace:"nowrap" });

  // Unique persons for grouping
  const uniquePersons = [...new Set(filtered.map(d=>d.name))];

  return (
    <div>
      {/* ── TOP STAT CARDS ── */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:12, marginBottom:16 }}>
        {[
          {label:"Bizga qarzdorlar",  val:fmt(mijozTotal)+" so'm", sub:`${allMijoz.length} ta mijoz`, color:T.warning, bg:T.warningDim},
          {label:"Bizning qarzimiz",  val:fmt(yetkTotal)+" so'm",  sub:`${allYetk.length} ta yetkazuvchi`, color:T.danger,  bg:T.dangerDim},
          {label:"Balans (olish−berish)", val:fmt(Math.abs(balance))+" so'm", sub:balance>=0?"Bizga ko'proq qarzdor":"Biz ko'proq qarzdormiz", color:balance>=0?T.success:T.danger, bg:balance>=0?T.successDim:T.dangerDim},
          {label:"Muddati o’tgan",    val:overdue.length+" ta",    sub:overdue.length>0?`${fmt(overdue.reduce((s,d)=>s+(d.amount||0),0))} so'm`:"Hammasi vaqtida", color:overdue.length>0?T.danger:T.success, bg:overdue.length>0?T.dangerDim:T.successDim},
        ].map((c,i)=>(
          <div key={i} style={{ background:c.bg, border:`1px solid ${c.color}33`, borderRadius:12, padding:"16px 18px" }}>
            <div style={{ fontSize:10, color:c.color, fontWeight:700, marginBottom:6, opacity:0.85 }}>{c.label.toUpperCase()}</div>
            <div style={{ fontSize:20, fontWeight:900, color:T.text }}>{c.val}</div>
            <div style={{ fontSize:11, color:T.muted, marginTop:4 }}>{c.sub}</div>
          </div>
        ))}
      </div>

      {/* ── TOOLBAR ── */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:12, flexWrap:"wrap", gap:8 }}>
        <SearchBar value={search} onChange={setSearch} placeholder="Ism, izoh bo'yicha..." />
        <div style={{ display:"flex", gap:8 }}>
          <Btn style={{ background:T.warningDim, color:T.warning, border:`1px solid rgba(245,158,11,0.35)`, fontWeight:600 }} onClick={()=>openModal("Mijoz")}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 5v14M5 12h14"/></svg>
            Bizdan qarz
          </Btn>
          <Btn style={{ background:T.dangerDim, color:T.danger, border:`1px solid rgba(239,68,68,0.35)`, fontWeight:600 }} onClick={()=>openModal("Yetkazuvchi")}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14"/></svg>
            Biz qarz
          </Btn>
        </div>
      </div>

      {/* ── TYPE FILTER ── */}
      <div style={{ display:"flex", gap:6, marginBottom:12, flexWrap:"wrap", alignItems:"center" }}>
        {[{k:"Hammasi",l:"Hammasi"},{k:"Mijoz",l:"Bizdan qarzlar"},{k:"Yetkazuvchi",l:"Bizning qarzlar"}].map(t=>(
          <button key={t.k} onClick={()=>setFilterType(t.k)} style={{ padding:"6px 13px", borderRadius:8, fontSize:12, cursor:"pointer", background:filterType===t.k?T.brand:T.card, color:filterType===t.k?"#fff":T.muted, border:`1px solid ${filterType===t.k?T.brand:T.border}`, fontWeight:filterType===t.k?600:400 }}>{t.l}</button>
        ))}
        <div style={{ width:1, height:20, background:T.border, margin:"0 4px" }} />
        {overdue.length>0 && (
          <div style={{ fontSize:12, color:T.danger, background:T.dangerDim, padding:"5px 12px", borderRadius:8, border:`1px solid ${T.danger}33`, display:"flex", alignItems:"center", gap:5 }}>
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/></svg>
            {overdue.length} ta muddati o'tgan
          </div>
        )}
      </div>

      {/* ── FULL WIDTH TABLE with period filter ── */}
      <Card style={{ padding:0, overflow:"hidden" }}>
        {/* Period filter header */}
        <div style={{ padding:"12px 16px", borderBottom:`1px solid ${T.border}`, background:T.surface }}>
          <div style={{ display:"flex", gap:5, flexWrap:"wrap", alignItems:"center" }}>
            {DEBT_PERIODS.map(p=>(
              <button key={p.k} onClick={()=>{setPeriod(p.k);setCalMode(false);}} style={{
                padding:"5px 11px", borderRadius:7, fontSize:11, cursor:"pointer",
                background:!calMode&&period===p.k?T.brand:T.card,
                color:!calMode&&period===p.k?"#fff":T.muted,
                border:`1px solid ${!calMode&&period===p.k?T.brand:T.border}`,
                fontWeight:!calMode&&period===p.k?600:400
              }}>{p.l}</button>
            ))}
            <button onClick={()=>setCalMode(v=>!v)} style={{
              padding:"5px 11px", borderRadius:7, fontSize:11, cursor:"pointer", display:"flex", alignItems:"center", gap:4,
              background:calMode?T.infoDim:T.card, color:calMode?T.info:T.muted, border:`1px solid ${calMode?T.info:T.border}`
            }}>
              <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
              Sana tanlash
            </button>
            <span style={{ fontSize:11, color:T.brand, fontWeight:600, marginLeft:4 }}>{calMode?"📅 ":"· "}{periodLabel()}</span>
            <span style={{ marginLeft:"auto", fontSize:12, color:T.muted }}>{[...new Set(filtered.map(d=>d.name))].length} ta shaxs · {filtered.length} ta yozuv</span>
          </div>
          {calMode && (
            <div style={{ display:"flex", alignItems:"center", gap:8, marginTop:10, background:T.card, border:`1px solid ${T.info}44`, borderRadius:9, padding:"9px 14px", flexWrap:"wrap" }}>
              <span style={{ fontSize:12, color:T.muted }}>Dan:</span>
              <input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"5px 10px", color:T.text, fontSize:12, outline:"none" }} />
              <span style={{ color:T.muted }}>—</span>
              <span style={{ fontSize:12, color:T.muted }}>Gacha:</span>
              <input type="date" value={dateTo} onChange={e=>setDateTo(e.target.value)} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"5px 10px", color:T.text, fontSize:12, outline:"none" }} />
              {(dateFrom||dateTo) && <button onClick={()=>{setDateFrom("");setDateTo("");}} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:6, color:T.muted, cursor:"pointer", padding:"3px 8px", fontSize:11 }}>× Tozalash</button>}
              {dateFrom&&dateTo && <div style={{ fontSize:11, color:T.info, background:T.infoDim, padding:"3px 10px", borderRadius:6, fontWeight:600 }}>{Math.round((new Date(dateTo)-new Date(dateFrom))/(1000*60*60*24))+1} kun</div>}
            </div>
          )}
        </div>

        {/* Grouped by person */}
        {(() => {
          const groups = {};
          filtered.forEach(d=>{
            if(!groups[d.name]) groups[d.name] = [];
            groups[d.name].push(d);
          });
          const groupEntries = Object.entries(groups).sort((a,b)=>b[1].reduce((s,d)=>s+d.amount,0)-a[1].reduce((s,d)=>s+d.amount,0));
          if(groupEntries.length===0) return <div style={{ padding:40, textAlign:"center", color:T.muted, fontSize:13 }}>Qarzlar topilmadi</div>;

          return groupEntries.map(([name, ds])=>{
            const isMijoz = ds[0]?.type==="Mijoz";
            const totalAmt = ds.reduce((s,d)=>s+(d.amount||0),0);
            const hasOverdue = ds.some(d=>d.dueDate&&d.dueDate<now);
            const expanded = expandedPerson===name;
            return (
              <div key={name} style={{ borderBottom:`1px solid ${T.border}` }}>
                {/* Person header row */}
                <div onClick={()=>setExpandedPerson(expanded?null:name)}
                  style={{ display:"flex", alignItems:"center", gap:12, padding:"13px 16px", cursor:"pointer", background:expanded?T.subtle:"transparent" }}
                  onMouseEnter={e=>{ if(!expanded) e.currentTarget.style.background=T.surface; }}
                  onMouseLeave={e=>{ if(!expanded) e.currentTarget.style.background="transparent"; }}>
                  {/* Avatar */}
                  <div style={{ width:36, height:36, borderRadius:10, background:isMijoz?T.warningDim:T.dangerDim, display:"flex", alignItems:"center", justifyContent:"center", fontSize:14, fontWeight:900, color:isMijoz?T.warning:T.danger, flexShrink:0 }}>
                    {name[0]?.toUpperCase()}
                  </div>
                  {/* Name + meta */}
                  <div style={{ flex:1 }}>
                    <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                      <span style={{ fontSize:14, fontWeight:800, color:T.text }}>{name}</span>
                      <Badge color={isMijoz?T.warning:T.danger} bg={isMijoz?T.warningDim:T.dangerDim}>{isMijoz?"Bizdan qarz":"Biz qarz"}</Badge>
                      {hasOverdue && <Badge color={T.danger} bg={T.dangerDim}>⚠ Muddati o’tgan</Badge>}
                    </div>
                    <div style={{ fontSize:11, color:T.muted, marginTop:2 }}>
                      {ds.length} ta yozuv
                      {ds.some(d=>d.dueDate) && ` · Muddat: ${ds.find(d=>d.dueDate)?.dueDate}`}
                    </div>
                  </div>
                  {/* Total + expand */}
                  <div style={{ display:"flex", alignItems:"center", gap:14 }}>
                    <div style={{ textAlign:"right" }}>
                      <div style={{ fontSize:16, fontWeight:900, color:isMijoz?T.warning:T.danger }}>{fmt(totalAmt)} so’m</div>
                      {ds.length>1 && <div style={{ fontSize:10, color:T.muted }}>{ds.length} ta yozuv jami</div>}
                    </div>
                    <div style={{ display:"flex", gap:5 }}>
                      <Btn small onClick={(e)=>{e.stopPropagation();setPersonCard(name);}}>Karta</Btn>
                    </div>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={T.muted} strokeWidth="2" style={{ transform:expanded?"rotate(180deg)":"rotate(0deg)", transition:"0.2s" }}><path d="M6 9l6 6 6-6"/></svg>
                  </div>
                </div>

                {/* Expanded sub-rows */}
                {expanded && ds.map((d,i)=>{
                  const isOvd = d.dueDate&&d.dueDate<now;
                  return (
                    <div key={d.id} style={{ display:"flex", alignItems:"center", gap:12, padding:"10px 16px 10px 68px", background:T.card, borderTop:`1px solid ${T.border}` }}>
                      <div style={{ width:6, height:6, borderRadius:"50%", background:isMijoz?T.warning:T.danger, flexShrink:0 }} />
                      <div style={{ flex:1 }}>
                        <div style={{ display:"flex", gap:8, alignItems:"center", flexWrap:"wrap" }}>
                          <span style={{ fontSize:13, fontWeight:600, color:T.text }}>{fmt(d.amount)} so’m</span>
                          {d.dueDate && <span style={{ fontSize:11, color:isOvd?T.danger:T.muted, background:isOvd?T.dangerDim:"transparent", padding:isOvd?"2px 7px":"0", borderRadius:5 }}>{isOvd?"⚠ ":""}Muddat: {d.dueDate}</span>}
                          <span style={{ fontSize:11, color:T.muted }}>Sana: {d.date}</span>
                          {d.note && <span style={{ fontSize:11, color:T.muted }}>· {d.note}</span>}
                        </div>
                      </div>
                      <div style={{ display:"flex", gap:5 }}>
                        <Btn small variant="primary" onClick={()=>setPayConfirm({id:d.id,name:d.name,amount:d.amount})}>To’landi ✓</Btn>
                        <Btn small onClick={()=>{setSelectedDebt(d);setPartialAmt("");setPartialNote("");setPartialModal(true);}}>Qisman</Btn>
                        <Btn small onClick={()=>openEdit(d)}>Tahrir</Btn>
                        <Btn small variant="danger" onClick={()=>setDeleteConfirm({id:d.id,name:d.name})}>O’chir</Btn>
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          });
        })()}

        {/* Footer jami */}
        {filtered.length>0 && (
          <div style={{ padding:"11px 16px", borderTop:`2px solid ${T.border}`, background:T.surface, display:"flex", gap:20 }}>
            <span style={{ fontSize:13, color:T.muted, fontWeight:600 }}>JAMI:</span>
            <span style={{ fontSize:13, color:T.warning, fontWeight:700 }}>Olish: {fmt(filtered.filter(d=>d.type==="Mijoz").reduce((s,d)=>s+(d.amount||0),0))} so’m</span>
            <span style={{ fontSize:13, color:T.danger, fontWeight:700 }}>Berish: {fmt(filtered.filter(d=>d.type==="Yetkazuvchi").reduce((s,d)=>s+(d.amount||0),0))} so’m</span>
          </div>
        )}
      </Card>

      {/* ── SHAXS KARTASI ── */}
      {personCard && (
        <div style={{ position:"fixed", inset:0, zIndex:250, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
          <div style={{ background:T.surface, border:`1px solid ${T.borderStrong}`, borderRadius:18, width:"100%", maxWidth:520, maxHeight:"85vh", display:"flex", flexDirection:"column", overflow:"hidden" }}>
            <div style={{ padding:"20px 24px 0", borderBottom:`1px solid ${T.border}` }}>
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:12 }}>
                <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                  <div style={{ width:44, height:44, borderRadius:12, background:personDebts[0]?.type==="Mijoz"?T.warningDim:T.dangerDim, display:"flex", alignItems:"center", justifyContent:"center", fontSize:18, fontWeight:900, color:personDebts[0]?.type==="Mijoz"?T.warning:T.danger }}>
                    {(personCard[0]||"?").toUpperCase()}
                  </div>
                  <div>
                    <div style={{ fontSize:16, fontWeight:800, color:T.text }}>{personCard}</div>
                    <div style={{ fontSize:12, color:T.muted }}>{personDebts.length} ta faol qarz</div>
                  </div>
                </div>
                <button onClick={()=>setPersonCard(null)} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:8, color:T.muted, cursor:"pointer", width:32, height:32, display:"flex", alignItems:"center", justifyContent:"center", fontSize:18 }}>×</button>
              </div>
              {/* Period filter */}
              <div style={{ display:"flex", gap:5, flexWrap:"wrap", alignItems:"center", paddingBottom:12 }}>
                {pcPeriods.map(p=>(
                  <button key={p.k} onClick={()=>{setPcPeriod(p.k);setPcCalMode(false);}} style={{ padding:"4px 10px", borderRadius:7, fontSize:11, cursor:"pointer", background:!pcCalMode&&pcPeriod===p.k?T.brand:T.card, color:!pcCalMode&&pcPeriod===p.k?"#fff":T.muted, border:`1px solid ${!pcCalMode&&pcPeriod===p.k?T.brand:T.border}`, fontWeight:!pcCalMode&&pcPeriod===p.k?600:400 }}>{p.l}</button>
                ))}
                <button onClick={()=>setPcCalMode(v=>!v)} style={{ padding:"4px 10px", borderRadius:7, fontSize:11, cursor:"pointer", display:"flex", alignItems:"center", gap:4, background:pcCalMode?T.infoDim:T.card, color:pcCalMode?T.info:T.muted, border:`1px solid ${pcCalMode?T.info:T.border}` }}>
                  <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
                  Sana
                </button>
              </div>
              {pcCalMode && (
                <div style={{ display:"flex", alignItems:"center", gap:6, paddingBottom:10, flexWrap:"wrap" }}>
                  <span style={{ fontSize:11, color:T.muted }}>Dan:</span>
                  <input type="date" value={pcDateFrom} onChange={e=>setPcDateFrom(e.target.value)} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"4px 8px", color:T.text, fontSize:11, outline:"none" }} />
                  <span style={{ color:T.muted }}>—</span>
                  <span style={{ fontSize:11, color:T.muted }}>Gacha:</span>
                  <input type="date" value={pcDateTo} onChange={e=>setPcDateTo(e.target.value)} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"4px 8px", color:T.text, fontSize:11, outline:"none" }} />
                  {(pcDateFrom||pcDateTo) && <button onClick={()=>{setPcDateFrom("");setPcDateTo("");}} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:5, color:T.muted, cursor:"pointer", padding:"2px 7px", fontSize:10 }}>× Tozalash</button>}
                </div>
              )}
            </div>
            <div style={{ flex:1, overflowY:"auto", padding:"16px 24px" }}>
              {/* Summary */}
              <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:10, marginBottom:16 }}>
                <div style={{ background:T.warningDim, borderRadius:10, padding:"12px 14px" }}>
                  <div style={{ fontSize:10, color:T.warning, fontWeight:700, marginBottom:4 }}>UMUMIY QARZ</div>
                  <div style={{ fontSize:18, fontWeight:900, color:T.text }}>{fmt(personTotal)} so’m</div>
                </div>
                <div style={{ background:T.card, borderRadius:10, padding:"12px 14px" }}>
                  <div style={{ fontSize:10, color:T.muted, fontWeight:700, marginBottom:4 }}>YOZUVLAR</div>
                  <div style={{ fontSize:18, fontWeight:900, color:T.text }}>{personDebts.length} ta</div>
                </div>
                <div style={{ background:T.successDim, borderRadius:10, padding:"12px 14px" }}>
                  <div style={{ fontSize:10, color:T.success, fontWeight:700, marginBottom:4 }}>TO’LANGAN</div>
                  <div style={{ fontSize:18, fontWeight:900, color:T.text }}>{filteredPersonHistory.filter(h=>h.action.includes("to'landi")).length} ta</div>
                </div>
              </div>

              {/* Active debts */}
              <div style={{ fontSize:12, fontWeight:700, color:T.text, marginBottom:8 }}>Faol qarzlar</div>
              {personDebts.map(d=>{
                const isOvd = d.dueDate && d.dueDate < now;
                return (
                  <div key={d.id} style={{ background:T.card, borderRadius:10, padding:"12px 14px", marginBottom:8, border:`1px solid ${isOvd?T.danger+"44":T.border}` }}>
                    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:6 }}>
                      <div style={{ display:"flex", gap:7, alignItems:"center" }}>
                        <Badge color={d.type==="Mijoz"?T.warning:T.danger} bg={d.type==="Mijoz"?T.warningDim:T.dangerDim}>{d.type==="Mijoz"?"Bizdan qarz":"Biz qarz"}</Badge>
                        {isOvd && <Badge color={T.danger} bg={T.dangerDim}>⚠ Muddati o’tgan</Badge>}
                      </div>
                      <div style={{ fontSize:15, fontWeight:800, color:d.type==="Mijoz"?T.warning:T.danger }}>{fmt(d.amount)} so’m</div>
                    </div>
                    <div style={{ display:"flex", gap:16, flexWrap:"wrap", marginBottom:8 }}>
                      <span style={{ fontSize:11, color:T.muted }}>Sana: {d.date}</span>
                      {d.dueDate && <span style={{ fontSize:11, color:isOvd?T.danger:T.muted }}>Muddat: {d.dueDate}</span>}
                      {d.note && <span style={{ fontSize:11, color:T.muted }}>Izoh: {d.note}</span>}
                    </div>
                    <div style={{ display:"flex", gap:6 }}>
                      <Btn small variant="primary" onClick={()=>setPayConfirm({id:d.id,name:d.name,amount:d.amount})}>To’landi ✓</Btn>
                      <Btn small onClick={()=>{setSelectedDebt(d);setPartialAmt("");setPartialNote("");setPartialModal(true);}}>Qisman</Btn>
                      <Btn small onClick={()=>openEdit(d)}>Tahrir</Btn>
                    </div>
                  </div>
                );
              })}

              {/* Payment history */}
              {filteredPersonHistory.length>0 && (
                <div style={{ marginTop:16 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:T.text, marginBottom:8 }}>To’lov va harakat tarixi</div>
                  {[...filteredPersonHistory].reverse().map((h,i)=>(
                    <div key={h.id||i} style={{ display:"flex", alignItems:"center", gap:10, padding:"8px 0", borderBottom:`1px solid ${T.border}` }}>
                      <div style={{ width:7, height:7, borderRadius:"50%", background:h.action==="to'liq to'landi"?T.success:h.action==="qisman to'landi"?T.warning:T.brand, flexShrink:0 }} />
                      <div style={{ flex:1, fontSize:12, color:T.muted }}>{h.date}</div>
                      <div style={{ fontSize:12, color:T.text, fontWeight:500 }}>{h.action}</div>
                      <div style={{ fontSize:13, fontWeight:700, color:h.action.includes("to'landi")?T.success:T.brand }}>{fmt(h.amount)} so’m</div>
                      {h.note && <div style={{ fontSize:11, color:T.muted, maxWidth:100, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{h.note}</div>}
                    </div>
                  ))}
                </div>
              )}
            </div>
            <div style={{ padding:"12px 24px", borderTop:`1px solid ${T.border}`, display:"flex", gap:10 }}>
              <Btn style={{ flex:1, background:T.warningDim, color:T.warning, border:`1px solid rgba(245,158,11,0.3)` }} onClick={()=>{setForm(f=>({...f,name:personCard,type:"Mijoz"}));setModalType("Mijoz");setModal(true);setPersonCard(null);}}>+ Bizdan qarz</Btn>
              <Btn style={{ flex:1, background:T.dangerDim, color:T.danger, border:`1px solid rgba(239,68,68,0.3)` }} onClick={()=>{setForm(f=>({...f,name:personCard,type:"Yetkazuvchi"}));setModalType("Yetkazuvchi");setModal(true);setPersonCard(null);}}>+ Biz qarz</Btn>
              <Btn onClick={()=>setPersonCard(null)} style={{ flex:1 }}>Yopish</Btn>
            </div>
          </div>
        </div>
      )}

      {/* ── DELETE CONFIRM ── */}
      <ConfirmDelete open={!!deleteConfirm} onClose={()=>setDeleteConfirm(null)} onConfirm={()=>{setDebts(prev=>prev.filter(x=>x.id!==deleteConfirm.id));setDeleteConfirm(null);}} itemName={deleteConfirm?.name||""} />

      {/* ── TO'LANDI TASDIQLASH ── */}
      {payConfirm && (
        <div style={{ position:"fixed", inset:0, zIndex:300, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <div style={{ background:T.surface, border:`1px solid ${T.success}44`, borderRadius:16, padding:28, width:360, textAlign:"center" }}>
            <div style={{ width:52, height:52, borderRadius:"50%", background:T.successDim, border:`1.5px solid ${T.success}55`, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 16px" }}>
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={T.success} strokeWidth="2.5" strokeLinecap="round"><polyline points="20 6 9 17 4 12"/></svg>
            </div>
            <div style={{ fontSize:15, fontWeight:700, color:T.text, marginBottom:8 }}>To’langanini tasdiqlang</div>
            <div style={{ fontSize:13, color:T.muted, marginBottom:6 }}>Quyidagi qarz to’liq yopiladi:</div>
            <div style={{ fontSize:14, fontWeight:600, color:T.success, background:T.successDim, padding:"8px 16px", borderRadius:8, marginBottom:6 }}>«{payConfirm.name}»</div>
            <div style={{ fontSize:18, fontWeight:900, color:T.text, marginBottom:20 }}>{fmt(payConfirm.amount)} so’m</div>
            <div style={{ display:"flex", gap:10 }}>
              <button onClick={()=>setPayConfirm(null)} style={{ flex:1, padding:"10px", borderRadius:9, background:T.card, border:`1px solid ${T.border}`, color:T.text, fontSize:13, fontWeight:500, cursor:"pointer" }}>Bekor</button>
              <button onClick={()=>payFull(payConfirm.id)} style={{ flex:1, padding:"10px", borderRadius:9, background:T.success, border:"none", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer" }}>Ha, to’landi ✓</button>
            </div>
          </div>
        </div>
      )}

      {/* ── TAHRIRLASH MODAL ── */}
      <Modal open={editModal} onClose={()=>setEditModal(false)} title="Qarzni tahrirlash">
        {editDebt && (
          <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
            <div style={{ background:editDebt.type==="Mijoz"?T.warningDim:T.dangerDim, border:`1px solid ${editDebt.type==="Mijoz"?"rgba(245,158,11,0.3)":"rgba(239,68,68,0.3)"}`, borderRadius:8, padding:"8px 14px", fontSize:12, color:editDebt.type==="Mijoz"?T.warning:T.danger, fontWeight:600 }}>
              {editDebt.type==="Mijoz" ? "Bizdan qarz — ular bizga pul beradi" : "Biz qarz — biz ularga pul beramiz"}
            </div>
            <Inp label="Ism / Tashkilot *" value={editForm.name} onChange={esf("name")} />
            <Inp label="Miqdor (so'm) *" value={editForm.amount} onChange={esf("amount")} type="number" />
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
              <Inp label="Qarz sanasi" value={editForm.date} onChange={esf("date")} type="date" />
              <Inp label="To'lash muddati" value={editForm.dueDate} onChange={esf("dueDate")} type="date" />
            </div>
            <Inp label="Izoh" value={editForm.note} onChange={esf("note")} placeholder="Qo'shimcha ma'lumot..." />
            <div style={{ display:"flex", gap:10, marginTop:4 }}>
              <Btn variant="primary" onClick={saveEdit} style={{ flex:1 }}>Saqlash</Btn>
              <Btn onClick={()=>setEditModal(false)} style={{ flex:1 }}>Bekor</Btn>
            </div>
          </div>
        )}
      </Modal>

      {/* ── QISMAN TO'LASH MODAL ── */}
      <Modal open={partialModal} onClose={()=>setPartialModal(false)} title="Qisman to'lash">
        {selectedDebt && (
          <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
            <div style={{ background:T.card, borderRadius:10, padding:"12px 14px", border:`1px solid ${T.border}` }}>
              <div style={{ fontSize:14, fontWeight:700, color:T.text }}>{selectedDebt.name}</div>
              <div style={{ fontSize:13, color:T.warning, fontWeight:600, marginTop:4 }}>Umumiy qarz: {fmt(selectedDebt.amount)} so’m</div>
            </div>
            <Inp label="To'langan miqdor (so'm) *" value={partialAmt} onChange={setPartialAmt} type="number" placeholder="0" />
            <Inp label="Izoh" value={partialNote} onChange={setPartialNote} placeholder="To'lash sababi..." />
            {+partialAmt>0 && (
              <div style={{ background:+partialAmt>=selectedDebt.amount?T.successDim:T.warningDim, borderRadius:8, padding:"10px 14px" }}>
                <div style={{ fontSize:12, color:+partialAmt>=selectedDebt.amount?T.success:T.warning, fontWeight:600 }}>
                  {+partialAmt>=selectedDebt.amount ? "✓ Qarz to'liq yopiladi" : `Qolgan qarz: ${fmt(selectedDebt.amount - +partialAmt)} so'm`}
                </div>
              </div>
            )}
            <div style={{ display:"flex", gap:10, marginTop:4 }}>
              <Btn variant="primary" onClick={payPartial} style={{ flex:1 }}>Saqlash</Btn>
              <Btn onClick={()=>setPartialModal(false)} style={{ flex:1 }}>Bekor</Btn>
            </div>
          </div>
        )}
      </Modal>

      {/* ── YANGI QARZ MODAL ── */}
      <Modal open={modal} onClose={()=>setModal(false)} title={modalType==="Mijoz" ? "Bizdan qarz — yangi yozuv" : "Biz qarz — yangi yozuv"}>
        <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
          {/* Type indicator */}
          <div style={{ background:modalType==="Mijoz"?T.warningDim:T.dangerDim, border:`1px solid ${modalType==="Mijoz"?"rgba(245,158,11,0.3)":"rgba(239,68,68,0.3)"}`, borderRadius:9, padding:"10px 14px", display:"flex", alignItems:"center", gap:8 }}>
            <div style={{ width:32, height:32, borderRadius:8, background:modalType==="Mijoz"?"rgba(245,158,11,0.2)":"rgba(239,68,68,0.2)", display:"flex", alignItems:"center", justifyContent:"center" }}>
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={modalType==="Mijoz"?T.warning:T.danger} strokeWidth="2"><path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
            </div>
            <div>
              <div style={{ fontSize:12, fontWeight:700, color:modalType==="Mijoz"?T.warning:T.danger }}>
                {modalType==="Mijoz" ? "Bizdan qarz — ular bizga pul beradi" : "Biz qarz — biz ularga pul beramiz"}
              </div>
            </div>
          </div>

          <Inp label="Ism / Tashkilot *" value={form.name} onChange={sf("name")} placeholder="Ali Valiyev..." />
          <Inp label="Miqdor (so'm) *" value={form.amount} onChange={sf("amount")} type="number" />
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
            <Inp label="Qarz sanasi" value={form.date} onChange={sf("date")} type="date" />
            <Inp label="To'lash muddati" value={form.dueDate} onChange={sf("dueDate")} type="date" />
          </div>
          <Inp label="Izoh (ixtiyoriy)" value={form.note} onChange={sf("note")} placeholder="Qo'shimcha ma'lumot..." />
          <div style={{ display:"flex", gap:10, marginTop:4 }}>
            <Btn style={{ flex:1, background:modalType==="Mijoz"?T.warningDim:T.dangerDim, color:modalType==="Mijoz"?T.warning:T.danger, border:`1px solid ${modalType==="Mijoz"?"rgba(245,158,11,0.4)":"rgba(239,68,68,0.4)"}`, fontWeight:600 }} onClick={add}>Qo’shish</Btn>
            <Btn onClick={()=>setModal(false)} style={{ flex:1 }}>Bekor</Btn>
          </div>
        </div>
      </Modal>
    </div>
  );
}

// ── USTA DETAIL CONTENT ────────────────────────────────────────────────────────
const UD_PERIODS = [{k:"bugun",l:"Bugun"},{k:"hafta",l:"Hafta"},{k:"oy",l:"Bu oy"},{k:"chorak",l:"Chorak"},{k:"yarim",l:"Yarim yil"},{k:"yil",l:"Bu yil"},{k:"hammasi",l:"Hammasi"}];

function UstaDetailContent({ ustaCard, allURec, records, saveRec, setParts, setAccessories, parts, accessories }) {
  const [period, setPeriod] = useState("hammasi");
  const [calMode, setCalMode] = useState(false);
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [editRec, setEditRec] = useState(null);
  const [editForm, setEditForm] = useState({});
  const [confirmBekor, setConfirmBekor] = useState(null);
  const [confirmTolandi, setConfirmTolandi] = useState(null);
  const [confirmQaytdi, setConfirmQaytdi] = useState(null);
  const [confirmRestore, setConfirmRestore] = useState(null);
  const [activeTab, setActiveTab] = useState("faol"); // "faol" | "korzina"
  const korzinaKey = `shox_korzina_${ustaCard}`;
  const [korzina, setKorzina] = useState(()=>{ try{const s=localStorage.getItem(korzinaKey);return s?JSON.parse(s):[]}catch{return [];} });
  const saveKorzina = k => { setKorzina(k); try{localStorage.setItem(korzinaKey,JSON.stringify(k));}catch{}; };

  const inP = (d) => {
    const dt = new Date(d||today()); const n=new Date(); n.setHours(0,0,0,0);
    if(calMode){if(dateFrom&&dateTo)return dt>=new Date(dateFrom)&&dt<=new Date(dateTo+"T23:59:59");if(dateFrom)return dt>=new Date(dateFrom);if(dateTo)return dt<=new Date(dateTo+"T23:59:59");return true;}
    if(period==="hammasi")return true;
    if(period==="bugun")return d===today();
    if(period==="hafta"){const w=new Date(n);w.setDate(w.getDate()-7);return dt>=w;}
    if(period==="oy")return dt.getMonth()===n.getMonth()&&dt.getFullYear()===n.getFullYear();
    if(period==="chorak"){const q=Math.floor(n.getMonth()/3);return dt>=new Date(n.getFullYear(),q*3,1)&&dt<=new Date(n.getFullYear(),q*3+3,0);}
    if(period==="yarim"){const h=n.getMonth()<6?0:6;return dt>=new Date(n.getFullYear(),h,1)&&dt<=new Date(n.getFullYear(),h+6,0);}
    if(period==="yil")return dt.getFullYear()===n.getFullYear();
    return true;
  };
  const pLabel = ()=>{if(calMode){if(dateFrom&&dateTo)return`${dateFrom} - ${dateTo}`;return"Sana";}return UD_PERIODS.find(p=>p.k===period)?.l||period;};

  const [partialModal, setPartialModal] = useState(null); // {rec}
  const [partialAmt, setPartialAmt] = useState("");

  const uRec   = allURec.filter(r=>inP(r.date));
  const uTotal = uRec.reduce((s,r)=>s+(r.price*r.qty||0),0);
  const uQty   = uRec.reduce((s,r)=>s+r.qty,0);
  // Partial payments stored on each record
  const totalPartialPaid = uRec.reduce((s,r)=>s+(r.partialPaid||0),0);
  const totalRemaining   = uTotal - totalPartialPaid;

  // All-time korzina stats
  const korzinaAll     = korzina;
  const korzinaQtyAll  = korzinaAll.reduce((s,r)=>s+r.qty,0);
  const korzinaTolandiRec = korzinaAll.filter(k=>k.korzinaReason==="tolandi");
  const korzinaQaytdiRec  = korzinaAll.filter(k=>k.korzinaReason==="qaytdi");

  const addPartialPayment = () => {
    if(!partialModal||!+partialAmt) return;
    const r = partialModal.rec;
    const prev = r.partialPaid||0;
    const newPaid = prev + +partialAmt;
    const fullAmt = r.price*r.qty;
    if(newPaid >= fullAmt) {
      // Fully paid — archive
      archiveToKorzina({...r, partialPaid:fullAmt}, "tolandi");
      saveRec(records.filter(x=>x.id!==r.id));
    } else {
      saveRec(records.map(x=>x.id===r.id?{...x,partialPaid:newPaid,partialHistory:[...(x.partialHistory||[]),{amt:+partialAmt,date:today()}]}:x));
    }
    setPartialModal(null); setPartialAmt("");
  };

  const itemMap = {};
  uRec.forEach(r=>{ if(!itemMap[r.itemName])itemMap[r.itemName]={qty:0,count:0}; itemMap[r.itemName].qty+=r.qty; itemMap[r.itemName].count+=1; });
  const topItems = Object.entries(itemMap).sort((a,b)=>b[1].qty-a[1].qty).slice(0,5);

  const monthMap = {};
  allURec.forEach(r=>{ const m=r.date?.slice(0,7)||""; if(!monthMap[m])monthMap[m]={qty:0,count:0}; monthMap[m].qty+=r.qty; monthMap[m].count+=1; });

  const saveEdit = () => {
    if(!editRec) return;
    const newQty = +editForm.qty;
    const diff = newQty - editRec.qty;
    saveRec(records.map(r=>r.id===editRec.id?{...r,qty:newQty,price:+editForm.price||r.price,note:editForm.note,date:editForm.date}:r));
    // Adjust inventory
    if(diff!==0){
      if(editRec.itemType==="zapchast") setParts(prev=>prev.map(p=>p.id===editRec.itemId?{...p,count:Math.max(0,p.count-diff)}:p));
      else setAccessories(prev=>prev.map(a=>a.id===editRec.itemId?{...a,count:Math.max(0,a.count-diff)}:a));
    }
    setEditRec(null);
  };

  const archiveToKorzina = (r, reason) => {
    saveKorzina([...korzina, {...r, korzinaReason:reason, korzinaDate:today()}]);
  };

  const restoreFromKorzina = (korzinaRec) => {
    // Remove from korzina
    saveKorzina(korzina.filter(k=>!(k.id===korzinaRec.id && k.korzinaDate===korzinaRec.korzinaDate)));
    // Restore to active records (clean of korzina fields, reset partialPaid)
    const { korzinaReason, korzinaDate, ...cleanRec } = korzinaRec;
    const restored = { ...cleanRec, id: uid(), status: undefined, partialPaid: 0, partialHistory: [], date: cleanRec.date || today() };
    saveRec([...records, restored]);
    // If qaytdi or ochildi — deduct from inventory again
    if(korzinaReason === "qaytdi" || korzinaReason === "ochildi") {
      if(cleanRec.itemType==="zapchast") setParts(prev=>prev.map(p=>p.id===cleanRec.itemId?{...p,count:Math.max(0,p.count-cleanRec.qty)}:p));
      else setAccessories(prev=>prev.map(a=>a.id===cleanRec.itemId?{...a,count:Math.max(0,a.count-cleanRec.qty)}:a));
    }
    setConfirmRestore(null);
  };

  const deleteR = (r) => {
    archiveToKorzina(r, "ochildi");
    saveRec(records.filter(x=>x.id!==r.id));
    if(r.itemType==="zapchast") setParts(prev=>prev.map(p=>p.id===r.itemId?{...p,count:p.count+r.qty}:p));
    else setAccessories(prev=>prev.map(a=>a.id===r.itemId?{...a,count:a.count+r.qty}:a));
    setConfirmBekor(null);
  };

  const doTolandi = (r) => {
    archiveToKorzina(r, "tolandi");
    saveRec(records.filter(x=>x.id!==r.id));
    setConfirmTolandi(null);
  };

  const doQaytdi = (r) => {
    archiveToKorzina(r, "qaytdi");
    saveRec(records.filter(x=>x.id!==r.id));
    if(r.itemType==="zapchast") setParts(prev=>prev.map(p=>p.id===r.itemId?{...p,count:p.count+r.qty}:p));
    else setAccessories(prev=>prev.map(a=>a.id===r.itemId?{...a,count:a.count+r.qty}:a));
    setConfirmQaytdi(null);
  };

  // Kutuvda = barcha active yozuvlar (status yo'q = kutilmoqda)
  const kutuvdaRec   = allURec;
  const kutuvdaTotal = kutuvdaRec.reduce((s,r)=>s+(r.price*r.qty||0),0);
  const kutuvdaQty   = kutuvdaRec.reduce((s,r)=>s+r.qty,0);
  // Qabul qilindi = korzinada to'langan + faol yozuvlardagi qisman to'lovlar
  const korzinaTolandiTotal = korzina.filter(k=>k.korzinaReason==="tolandi").reduce((s,r)=>s+(r.price*r.qty||0),0);
  const partialPaidTotal    = allURec.reduce((s,r)=>s+(r.partialPaid||0),0);
  const tolandiTotal        = korzinaTolandiTotal + partialPaidTotal;

  return (
    <div style={{ flex:1, overflowY:"auto", padding:20 }}>

      {/* ── KUTUVDA BANNER ── */}
      <div style={{ background:T.card, border:`1px solid ${T.brand}44`, borderRadius:14, padding:"18px 22px", marginBottom:18 }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", flexWrap:"wrap", gap:12 }}>
          <div style={{ display:"flex", alignItems:"center", gap:12 }}>
            <div style={{ width:44, height:44, borderRadius:12, background:T.brandDim, display:"flex", alignItems:"center", justifyContent:"center" }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={T.brand} strokeWidth="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
            </div>
            <div>
              <div style={{ fontSize:13, color:T.brand, fontWeight:700, marginBottom:2 }}>KUTUVDA — {ustaCard}</div>
              <div style={{ fontSize:11, color:T.muted }}>Hali to’lanmagan yoki qaytarilmagan tovarlar</div>
            </div>
          </div>
          <div style={{ display:"flex", gap:24, flexWrap:"wrap", alignItems:"center" }}>
            <div style={{ textAlign:"center" }}>
              <div style={{ fontSize:24, fontWeight:900, color:kutuvdaQty>0?T.warning:T.success }}>{kutuvdaQty} dona</div>
              <div style={{ fontSize:10, color:T.muted, marginTop:2 }}>TOVAR KUTUVDA</div>
            </div>
            <div style={{ width:1, height:36, background:T.border }} />
            <div style={{ textAlign:"center" }}>
              <div style={{ fontSize:24, fontWeight:900, color:kutuvdaTotal>0?T.warning:T.success }}>{fmt(kutuvdaTotal)} so’m</div>
              <div style={{ fontSize:10, color:T.muted, marginTop:2 }}>SUMMA KUTUVDA</div>
            </div>
            {tolandiTotal>0 && <>
              <div style={{ width:1, height:36, background:T.border }} />
              <div style={{ textAlign:"center" }}>
                <div style={{ fontSize:24, fontWeight:900, color:T.success }}>{fmt(tolandiTotal)} so’m</div>
                <div style={{ fontSize:10, color:T.muted, marginTop:2 }}>QABUL QILINDI</div>
                {partialPaidTotal>0 && korzinaTolandiTotal>0 && (
                  <div style={{ fontSize:10, color:T.success, opacity:0.7, marginTop:2 }}>
                    To'liq: {fmt(korzinaTolandiTotal)} · Qisman: {fmt(partialPaidTotal)}
                  </div>
                )}
                {partialPaidTotal>0 && korzinaTolandiTotal===0 && (
                  <div style={{ fontSize:10, color:T.success, opacity:0.7, marginTop:2 }}>Qisman to’lovlar</div>
                )}
              </div>
            </>}
            {kutuvdaQty===0 && (
              <div style={{ display:"flex", alignItems:"center", gap:6, fontSize:12, color:T.success, background:T.successDim, padding:"7px 14px", borderRadius:9 }}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><polyline points="20 6 9 17 4 12"/></svg>
                Kutuvda yo'q ✓
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Period filter */}
      <div style={{ display:"flex", gap:5, flexWrap:"wrap", alignItems:"center", marginBottom:16 }}>
        {UD_PERIODS.map(p=>(
          <button key={p.k} onClick={()=>{setPeriod(p.k);setCalMode(false);}} style={{ padding:"5px 11px", borderRadius:7, fontSize:11, cursor:"pointer", background:!calMode&&period===p.k?T.brand:T.card, color:!calMode&&period===p.k?"#fff":T.muted, border:`1px solid ${!calMode&&period===p.k?T.brand:T.border}`, fontWeight:!calMode&&period===p.k?600:400 }}>{p.l}</button>
        ))}
        <button onClick={()=>setCalMode(v=>!v)} style={{ padding:"5px 11px", borderRadius:7, fontSize:11, cursor:"pointer", display:"flex", alignItems:"center", gap:4, background:calMode?T.infoDim:T.card, color:calMode?T.info:T.muted, border:`1px solid ${calMode?T.info:T.border}` }}>
          <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
          Sana
        </button>
        {calMode && <>
          <input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"4px 9px", color:T.text, fontSize:11, outline:"none" }} />
          <span style={{ color:T.muted, fontSize:12 }}>—</span>
          <input type="date" value={dateTo} onChange={e=>setDateTo(e.target.value)} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"4px 9px", color:T.text, fontSize:11, outline:"none" }} />
          {(dateFrom||dateTo) && <button onClick={()=>{setDateFrom("");setDateTo("");}} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:5, color:T.muted, cursor:"pointer", padding:"2px 7px", fontSize:10 }}>× Tozalash</button>}
        </>}
        <span style={{ fontSize:11, color:T.brand, fontWeight:600, marginLeft:4 }}>· {pLabel()} · {uRec.length} ta yozuv</span>
      </div>

      {/* Stats: period-specific, meaningful */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:10, marginBottom:18 }}>
        {[
          {l:`${pLabel()}  -  berilgan`, v:uQty+" dona", sub:`${uRec.length} ta yozuv`, c:T.warning, bg:T.warningDim,
           tip:"Shu davrda usta olib ketgan tovarlar. Hali pul to'lamagan yoki qaytarmagan — kutuvda turibdi."},
          {l:"Arxivda to’landi", v:korzinaTolandiRec.length+" ta", sub:korzinaTolandiRec.reduce((s,r)=>s+r.qty,0)+" dona", c:T.success, bg:T.successDim,
           tip:"Usta pul to'lab, yopilgan bitimlar. Tovar sotildi va hisob-kitob amalga oshdi."},
          {l:"Arxivda qaytdi", v:korzinaQaytdiRec.length+" ta", sub:korzinaQaytdiRec.reduce((s,r)=>s+r.qty,0)+" dona", c:T.info, bg:T.infoDim,
           tip:"Usta tovarni qaytargan holatlar. Tovar omborga qaytdi — pul ham, daromad ham yo'q."},
          {l:"Jami arxiv", v:korzinaAll.length+" ta", sub:korzinaQtyAll+" dona", c:T.muted, bg:T.subtle,
           tip:"Bu usta bilan barcha vaqt davomidagi yakunlangan operatsiyalar. Ishonchlilik va faollik ko'rsatkichi."},
        ].map((s,i)=>(
          <InfoCard key={i} label={s.l} value={s.v} sub={s.sub} color={s.c} bg={s.bg} tip={s.tip} />
        ))}
      </div>

      {/* Two panel row */}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 260px", gap:14, marginBottom:18 }}>
        {/* Top items — qty only */}
        <Card>
          <div style={{ fontSize:13, fontWeight:700, color:T.text, marginBottom:12 }}>Eng ko’p olingan tovarlar</div>
          {topItems.length===0 ? <div style={{ color:T.muted, fontSize:12 }}>Bu davrda yozuv yo’q</div> :
            topItems.map(([name,s],i)=>(
              <div key={name} style={{ display:"flex", alignItems:"center", gap:10, marginBottom:9 }}>
                <div style={{ width:22, height:22, borderRadius:6, background:T.brandDim, display:"flex", alignItems:"center", justifyContent:"center", fontSize:10, fontWeight:800, color:T.brand }}>{i+1}</div>
                <div style={{ flex:1, fontSize:13, color:T.text }}>{name}</div>
                <div style={{ fontSize:12, color:T.warning, fontWeight:700 }}>{s.qty} ta</div>
                <div style={{ fontSize:11, color:T.muted }}>{s.count} marta</div>
              </div>
            ))
          }
        </Card>
        {/* Monthly — qty only */}
        <Card>
          <div style={{ fontSize:13, fontWeight:700, color:T.text, marginBottom:12 }}>Oylar bo’yicha</div>
          {Object.entries(monthMap).sort((a,b)=>b[0].localeCompare(a[0])).slice(0,8).map(([month,s])=>(
            <div key={month} style={{ display:"flex", justifyContent:"space-between", padding:"6px 0", borderBottom:`1px solid ${T.border}` }}>
              <span style={{ fontSize:12, color:T.muted }}>{month}</span>
              <div style={{ display:"flex", gap:10 }}>
                <span style={{ fontSize:12, color:T.warning, fontWeight:600 }}>{s.qty} ta</span>
                <span style={{ fontSize:11, color:T.muted }}>{s.count} yozuv</span>
              </div>
            </div>
          ))}
          {Object.keys(monthMap).length===0 && <div style={{ color:T.muted, fontSize:12 }}>Yozuv yo’q</div>}
        </Card>
      </div>

      {/* Records table with edit + Korzina tabs */}
      <Card style={{ padding:0, overflow:"hidden" }}>
        {/* Tab header */}
        <div style={{ padding:"11px 16px", borderBottom:`1px solid ${T.border}`, background:T.surface, display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <div style={{ display:"flex", gap:6 }}>
            {[
              {k:"faol", l:"Faol yozuvlar", count:uRec.length},
              {k:"korzina", l:"🗂 Arxiv", count:korzina.length},
            ].map(t=>(
              <button key={t.k} onClick={()=>setActiveTab(t.k)} style={{ padding:"5px 12px", borderRadius:7, fontSize:12, cursor:"pointer", background:activeTab===t.k?T.brand:T.card, color:activeTab===t.k?"#fff":T.muted, border:`1px solid ${activeTab===t.k?T.brand:T.border}`, fontWeight:activeTab===t.k?600:400 }}>
                {t.l} <span style={{ opacity:0.75 }}>({t.count})</span>
              </button>
            ))}
          </div>
          <div style={{ fontSize:12, color:T.muted }}>
            {activeTab==="faol" ? `${uRec.length} ta · ${uQty} dona kutuvda` : `${korzina.length} ta yozuv arxivda`}
          </div>
        </div>

        {activeTab==="faol" ? (
          <table style={{ width:"100%", borderCollapse:"collapse" }}>
            <THead cols={["Tovar","Turi","Soni","Sana","Izoh","Amallar"]} />
            <tbody>
              {uRec.length===0 ? (
                <tr><td colSpan={6} style={{ padding:32, textAlign:"center", color:T.muted, fontSize:13 }}>Bu davrda faol yozuv yo’q</td></tr>
              ) : uRec.map(r=>{
                const isEditing = editRec?.id===r.id;
                return (
                  <tr key={r.id} style={{ borderBottom:`1px solid ${T.border}`, background:isEditing?T.subtle:"transparent" }}>
                    <td style={{ padding:"10px 14px", fontSize:13, color:T.text, fontWeight:500 }}>
                    {r.itemName}
                    {r.partialPaid>0 && (
                      <div style={{ fontSize:10, color:T.success, marginTop:2 }}>
                        ✓ {fmt(r.partialPaid)} so’m to’landi · Qoldi: <span style={{ color:T.warning }}>{fmt((r.price*r.qty)-(r.partialPaid))}</span>
                      </div>
                    )}
                  </td>
                    <td style={{ padding:"10px 14px" }}><Badge>{r.itemType==="zapchast"?"Zapchast":"Aksessuar"}</Badge></td>
                    <td style={{ padding:"10px 14px" }}>
                      {isEditing
                        ? <input type="number" value={editForm.qty} onChange={e=>setEditForm(f=>({...f,qty:e.target.value}))} style={{ width:60, background:T.surface, border:`1px solid ${T.brand}`, borderRadius:6, padding:"4px 8px", color:T.text, fontSize:13, fontWeight:700, outline:"none" }} />
                        : <span style={{ fontSize:13, fontWeight:700, color:T.warning }}>{r.qty} ta</span>
                      }
                    </td>
                    <td style={{ padding:"10px 14px" }}>
                      {isEditing
                        ? <input type="date" value={editForm.date} onChange={e=>setEditForm(f=>({...f,date:e.target.value}))} style={{ background:T.surface, border:`1px solid ${T.brand}`, borderRadius:6, padding:"4px 8px", color:T.text, fontSize:12, outline:"none" }} />
                        : <span style={{ fontSize:12, color:T.muted }}>{r.date}</span>
                      }
                    </td>
                    <td style={{ padding:"10px 14px" }}>
                      {isEditing
                        ? <input value={editForm.note} onChange={e=>setEditForm(f=>({...f,note:e.target.value}))} placeholder="Izoh..." style={{ width:"100%", background:T.surface, border:`1px solid ${T.brand}`, borderRadius:6, padding:"4px 8px", color:T.text, fontSize:12, outline:"none" }} />
                        : <span style={{ fontSize:12, color:T.muted }}>{r.note||"—"}</span>
                      }
                    </td>
                    <td style={{ padding:"10px 14px" }}>
                      {isEditing ? (
                        <div style={{ display:"flex", gap:5 }}>
                          <Btn small variant="primary" onClick={saveEdit}>Saqlash</Btn>
                          <Btn small onClick={()=>setEditRec(null)}>Bekor</Btn>
                        </div>
                      ) : (
                        <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
                          <Btn small style={{ background:T.successDim, color:T.success, border:`1px solid ${T.success}44` }} onClick={()=>setConfirmTolandi({rec:r})}>To’landi ✓</Btn>
                          <Btn small style={{ background:T.infoDim, color:T.info, border:`1px solid ${T.info}44` }} onClick={()=>{setPartialModal({rec:r});setPartialAmt("");}}>Qisman</Btn>
                          <Btn small style={{ background:T.warningDim, color:T.warning, border:`1px solid rgba(245,158,11,0.3)` }} onClick={()=>setConfirmQaytdi({rec:r})}>Qaytdi ↩</Btn>
                          <Btn small onClick={()=>{setEditRec(r);setEditForm({qty:r.qty,price:r.price,date:r.date,note:r.note||""});}}>Tahrir</Btn>
                          <Btn small variant="danger" onClick={()=>setConfirmBekor({rec:r})}>O’chir</Btn>
                        </div>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
            {uRec.length>0 && (
              <tfoot>
                <tr style={{ borderTop:`2px solid ${T.border}`, background:T.surface }}>
                  <td colSpan={2} style={{ padding:"10px 14px", fontSize:12, color:T.muted, fontWeight:600 }}>KUTUVDA JAMI</td>
                  <td style={{ padding:"10px 14px", fontSize:14, fontWeight:900, color:T.warning }}>{uQty} dona</td>
                  {totalPartialPaid>0 && (
                    <td colSpan={3} style={{ padding:"10px 14px", fontSize:12 }}>
                      <span style={{ color:T.success, fontWeight:600 }}>To’landi: {fmt(totalPartialPaid)} so’m</span>
                      <span style={{ color:T.muted, margin:"0 8px" }}>·</span>
                      <span style={{ color:T.warning, fontWeight:700 }}>Qoldi: {fmt(totalRemaining)} so’m</span>
                    </td>
                  )}
                  {totalPartialPaid===0 && <td colSpan={3} />}
                </tr>
              </tfoot>
            )}
          </table>
        ) : (
          // ── KORZINA (ARXIV) ──
          <div>
            {/* Korzina stats */}
            {korzina.length>0 && (
              <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:10, padding:14, borderBottom:`1px solid ${T.border}`, background:T.subtle }}>
                {[
                  {l:"To’landi", v:korzina.filter(k=>k.korzinaReason==="tolandi").length+" ta", c:T.success, bg:T.successDim},
                  {l:"Qaytdi", v:korzina.filter(k=>k.korzinaReason==="qaytdi").length+" ta", c:T.warning, bg:T.warningDim},
                  {l:"O’chirildi", v:korzina.filter(k=>k.korzinaReason==="ochildi").length+" ta", c:T.danger, bg:T.dangerDim},
                ].map((s,i)=>(
                  <div key={i} style={{ background:s.bg, borderRadius:9, padding:"10px 14px" }}>
                    <div style={{ fontSize:10, color:s.c, fontWeight:700, marginBottom:4 }}>{s.l.toUpperCase()}</div>
                    <div style={{ fontSize:18, fontWeight:900, color:T.text }}>{s.v}</div>
                  </div>
                ))}
              </div>
            )}
            <table style={{ width:"100%", borderCollapse:"collapse" }}>
              <THead cols={["Tovar","Turi","Soni","Sabab","Sana","Arxiv sanasi","Amal"]} />
              <tbody>
                {korzina.length===0 ? (
                  <tr><td colSpan={7} style={{ padding:32, textAlign:"center", color:T.muted, fontSize:13 }}>Arxiv bo’sh</td></tr>
                ) : [...korzina].reverse().map((r,i)=>{
                  const reasonColor = r.korzinaReason==="tolandi"?T.success:r.korzinaReason==="qaytdi"?T.warning:T.danger;
                  const reasonBg    = r.korzinaReason==="tolandi"?T.successDim:r.korzinaReason==="qaytdi"?T.warningDim:T.dangerDim;
                  const reasonLabel = r.korzinaReason==="tolandi"?"✓ To'landi":r.korzinaReason==="qaytdi"?"↩ Qaytdi":"🗑 O'chirildi";
                  return (
                    <tr key={r.id+""+(r.korzinaDate||i)} style={{ borderBottom:`1px solid ${T.border}`, opacity:0.85 }}>
                      <td style={{ padding:"10px 14px", fontSize:13, color:T.text }}>{r.itemName}</td>
                      <td style={{ padding:"10px 14px" }}><Badge>{r.itemType==="zapchast"?"Zapchast":"Aksessuar"}</Badge></td>
                      <td style={{ padding:"10px 14px", fontSize:13, fontWeight:700, color:T.muted }}>{r.qty} ta</td>
                      <td style={{ padding:"10px 14px" }}>
                        <span style={{ fontSize:11, color:reasonColor, background:reasonBg, padding:"3px 9px", borderRadius:6, fontWeight:600 }}>{reasonLabel}</span>
                      </td>
                      <td style={{ padding:"10px 14px", fontSize:12, color:T.muted }}>{r.date}</td>
                      <td style={{ padding:"10px 14px", fontSize:12, color:T.muted }}>{r.korzinaDate||"—"}</td>
                      <td style={{ padding:"10px 14px" }}>
                        <Btn small style={{ background:T.brandDim, color:T.brand, border:`1px solid ${T.brand}44` }}
                          onClick={()=>setConfirmRestore({rec:r})}>
                          ↑ Tiklash
                        </Btn>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
            {korzina.length>0 && (
              <div style={{ padding:"10px 16px", borderTop:`1px solid ${T.border}`, display:"flex", justifyContent:"flex-end" }}>
                <button onClick={()=>{ if(window.confirm("Arxivni to'liq tozalash? Bu amalni qaytarib bo'lmaydi!")) saveKorzina([]); }} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:7, color:T.muted, cursor:"pointer", padding:"5px 12px", fontSize:12 }}>Arxivni tozalash</button>
              </div>
            )}

            {/* Restore confirm modal */}
            {confirmRestore && (
              <div style={{ position:"fixed", inset:0, zIndex:700, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center" }}>
                <div style={{ background:T.surface, border:`1px solid ${T.brand}44`, borderRadius:16, padding:26, width:400, textAlign:"center" }}>
                  <div style={{ width:50, height:50, borderRadius:"50%", background:T.brandDim, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 14px" }}>
                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={T.brand} strokeWidth="2.5" strokeLinecap="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-3.18"/></svg>
                  </div>
                  <div style={{ fontSize:14, fontWeight:700, color:T.text, marginBottom:8 }}>Faol yozuvlarga tiklash</div>
                  <div style={{ background:T.card, borderRadius:9, padding:"10px 14px", marginBottom:10, textAlign:"left" }}>
                    <div style={{ fontSize:13, fontWeight:700, color:T.text }}>{confirmRestore.rec.itemName}</div>
                    <div style={{ display:"flex", gap:12, marginTop:5, flexWrap:"wrap" }}>
                      <span style={{ fontSize:12, color:T.muted }}>Soni: <strong style={{ color:T.warning }}>{confirmRestore.rec.qty} ta</strong></span>
                      <span style={{ fontSize:12, color:T.muted }}>Sana: {confirmRestore.rec.date}</span>
                    </div>
                  </div>
                  {(confirmRestore.rec.korzinaReason==="qaytdi" || confirmRestore.rec.korzinaReason==="ochildi") && (
                    <div style={{ background:T.warningDim, border:`1px solid rgba(245,158,11,0.3)`, borderRadius:8, padding:"8px 14px", marginBottom:12, fontSize:12, color:T.warning }}>
                      ⚠ Tovar inventardan yana {confirmRestore.rec.qty} ta kamayadi
                    </div>
                  )}
                  <div style={{ fontSize:12, color:T.muted, marginBottom:18 }}>
                    Yozuv faol ro'yxatga qaytariladi va kutuvda bo'ladi.
                  </div>
                  <div style={{ display:"flex", gap:10 }}>
                    <button onClick={()=>setConfirmRestore(null)} style={{ flex:1, padding:"9px", borderRadius:8, background:T.card, border:`1px solid ${T.border}`, color:T.text, fontSize:13, cursor:"pointer" }}>Bekor</button>
                    <button onClick={()=>restoreFromKorzina(confirmRestore.rec)} style={{ flex:1, padding:"9px", borderRadius:8, background:T.brand, border:"none", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer" }}>Ha, tiklash ↑</button>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}
      </Card>

      {/* ── QISMAN TO'LASH MODAL ── */}
      {partialModal && (
        <div style={{ position:"fixed", inset:0, zIndex:600, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <div style={{ background:T.surface, border:`1px solid ${T.info}44`, borderRadius:16, padding:26, width:400, textAlign:"center" }}>
            <div style={{ width:48, height:48, borderRadius:"50%", background:T.infoDim, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 14px" }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={T.info} strokeWidth="2"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>
            </div>
            <div style={{ fontSize:14, fontWeight:700, color:T.text, marginBottom:6 }}>Qisman to’lash</div>
            <div style={{ background:T.card, borderRadius:9, padding:"10px 14px", marginBottom:14 }}>
              <div style={{ fontSize:13, fontWeight:700, color:T.text }}>{partialModal.rec.itemName} × {partialModal.rec.qty} ta</div>
              <div style={{ display:"flex", justifyContent:"space-between", marginTop:6, flexWrap:"wrap", gap:8 }}>
                <span style={{ fontSize:12, color:T.muted }}>Jami: <strong style={{ color:T.text }}>{fmt(partialModal.rec.price*partialModal.rec.qty)} so’m</strong></span>
                {(partialModal.rec.partialPaid||0)>0 && <span style={{ fontSize:12, color:T.success }}>Avval to’landi: {fmt(partialModal.rec.partialPaid)} so’m</span>}
                <span style={{ fontSize:12, color:T.warning, fontWeight:700 }}>Qoldi: {fmt((partialModal.rec.price*partialModal.rec.qty)-(partialModal.rec.partialPaid||0))} so’m</span>
              </div>
            </div>
            <div style={{ textAlign:"left", marginBottom:12 }}>
              <div style={{ fontSize:11, color:T.muted, marginBottom:5, fontWeight:500 }}>HOZIR TO’LANGAN SUMMA (so’m) *</div>
              <input type="number" value={partialAmt} onChange={e=>setPartialAmt(e.target.value)} placeholder="0" autoFocus
                style={{ width:"100%", background:T.surface, border:`1px solid ${T.info}`, borderRadius:9, padding:"10px 14px", color:T.text, fontSize:15, fontWeight:700, outline:"none", boxSizing:"border-box" }} />
            </div>
            {+partialAmt>0 && (
              <div style={{ background:T.infoDim, borderRadius:8, padding:"8px 14px", marginBottom:14, textAlign:"left" }}>
                <div style={{ fontSize:12, color:T.info }}>
                  To'lanadi: <strong>{fmt(+partialAmt)} so’m</strong>
                  {" · "}Qoladi: <strong style={{ color:T.warning }}>{fmt(Math.max(0,(partialModal.rec.price*partialModal.rec.qty)-(partialModal.rec.partialPaid||0)-(+partialAmt)))} so’m</strong>
                </div>
                {+partialAmt>=(partialModal.rec.price*partialModal.rec.qty)-(partialModal.rec.partialPaid||0) && (
                  <div style={{ fontSize:11, color:T.success, marginTop:4 }}>✓ To’liq to’lanadi — arxivga o’tadi</div>
                )}
              </div>
            )}
            <div style={{ display:"flex", gap:10 }}>
              <button onClick={()=>{setPartialModal(null);setPartialAmt("");}} style={{ flex:1, padding:"9px", borderRadius:8, background:T.card, border:`1px solid ${T.border}`, color:T.text, fontSize:13, cursor:"pointer" }}>Bekor</button>
              <button onClick={addPartialPayment} style={{ flex:1, padding:"9px", borderRadius:8, background:T.info, border:"none", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer" }}>Saqlash</button>
            </div>
          </div>
        </div>
      )}

      {/* ── TASDIQLASH MODALLARI ── */}
      {/* Bekor qilish */}
      {confirmBekor && (
        <div style={{ position:"fixed", inset:0, zIndex:600, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <div style={{ background:T.surface, border:`1px solid ${T.danger}44`, borderRadius:16, padding:26, width:360, textAlign:"center" }}>
            <div style={{ width:48, height:48, borderRadius:"50%", background:T.dangerDim, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 14px" }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={T.danger} strokeWidth="2.5"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6"/><path d="M10 11v6M14 11v6"/></svg>
            </div>
            <div style={{ fontSize:14, fontWeight:700, color:T.text, marginBottom:6 }}>Yozuvni o’chirish</div>
            <div style={{ fontSize:13, color:T.muted, marginBottom:6 }}>«{confirmBekor.rec.itemName}» ({confirmBekor.rec.qty} ta) yozuvi o’chiriladi va tovar omborga qaytariladi.</div>
            <div style={{ fontSize:12, color:T.danger, marginBottom:18 }}>Bu amalni qaytarib bo’lmaydi!</div>
            <div style={{ display:"flex", gap:10 }}>
              <button onClick={()=>setConfirmBekor(null)} style={{ flex:1, padding:"9px", borderRadius:8, background:T.card, border:`1px solid ${T.border}`, color:T.text, fontSize:13, cursor:"pointer" }}>Bekor</button>
              <button onClick={()=>deleteR(confirmBekor.rec)} style={{ flex:1, padding:"9px", borderRadius:8, background:T.danger, border:"none", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer" }}>Ha, o’chir</button>
            </div>
          </div>
        </div>
      )}

      {/* To'landi tasdiqlash */}
      {confirmTolandi && (
        <div style={{ position:"fixed", inset:0, zIndex:600, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <div style={{ background:T.surface, border:`1px solid ${T.success}44`, borderRadius:16, padding:26, width:380, textAlign:"center" }}>
            <div style={{ width:48, height:48, borderRadius:"50%", background:T.successDim, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 14px" }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={T.success} strokeWidth="2.5" strokeLinecap="round"><polyline points="20 6 9 17 4 12"/></svg>
            </div>
            <div style={{ fontSize:14, fontWeight:700, color:T.text, marginBottom:6 }}>Usta pul to’ladimi?</div>
            <div style={{ fontSize:13, color:T.muted, marginBottom:6 }}>
              «{confirmTolandi.rec.itemName}» — {confirmTolandi.rec.qty} ta uchun to'lov qabul qilindi deb belgilanadi.
            </div>
            <div style={{ fontSize:12, color:T.success, background:T.successDim, padding:"6px 14px", borderRadius:8, marginBottom:18 }}>
              {ustaCard} → {confirmTolandi.rec.itemName} · {confirmTolandi.rec.qty} ta
            </div>
            <div style={{ display:"flex", gap:10 }}>
              <button onClick={()=>setConfirmTolandi(null)} style={{ flex:1, padding:"9px", borderRadius:8, background:T.card, border:`1px solid ${T.border}`, color:T.text, fontSize:13, cursor:"pointer" }}>Bekor</button>
              <button onClick={()=>doTolandi(confirmTolandi.rec)} style={{ flex:1, padding:"9px", borderRadius:8, background:T.success, border:"none", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer" }}>Ha, to’landi ✓</button>
            </div>
          </div>
        </div>
      )}

      {/* Qaytdi tasdiqlash */}
      {confirmQaytdi && (
        <div style={{ position:"fixed", inset:0, zIndex:600, background:"rgba(0,0,0,0.82)", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <div style={{ background:T.surface, border:`1px solid ${T.warning}44`, borderRadius:16, padding:26, width:380, textAlign:"center" }}>
            <div style={{ width:48, height:48, borderRadius:"50%", background:T.warningDim, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 14px" }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={T.warning} strokeWidth="2.5"><path d="M3 12h18M9 6l-6 6 6 6"/></svg>
            </div>
            <div style={{ fontSize:14, fontWeight:700, color:T.text, marginBottom:6 }}>Tovar qaytdimi?</div>
            <div style={{ fontSize:13, color:T.muted, marginBottom:6 }}>
              «{confirmQaytdi.rec.itemName}» ({confirmQaytdi.rec.qty} ta) omborga qaytariladi va yozuv o'chiriladi.
            </div>
            <div style={{ fontSize:12, color:T.warning, background:T.warningDim, padding:"6px 14px", borderRadius:8, marginBottom:18 }}>
              {confirmQaytdi.rec.qty} ta tovar inventarga qaytadi
            </div>
            <div style={{ display:"flex", gap:10 }}>
              <button onClick={()=>setConfirmQaytdi(null)} style={{ flex:1, padding:"9px", borderRadius:8, background:T.card, border:`1px solid ${T.border}`, color:T.text, fontSize:13, cursor:"pointer" }}>Bekor</button>
              <button onClick={()=>doQaytdi(confirmQaytdi.rec)} style={{ flex:1, padding:"9px", borderRadius:8, background:T.warning, border:"none", color:"#000", fontSize:13, fontWeight:700, cursor:"pointer" }}>Ha, qaytdi ↩</button>
            </div>
          </div>
        </div>
      )}

      {editRec && false && <div/>}
    </div>
  );
}
const USTA_PERIODS = [{k:"bugun",l:"Bugun"},{k:"hafta",l:"Hafta"},{k:"oy",l:"Bu oy"},{k:"chorak",l:"Chorak"},{k:"yarim",l:"Yarim yil"},{k:"yil",l:"Bu yil"},{k:"hammasi",l:"Hammasi"}];

function UstalarPage({ parts, setParts, accessories, setAccessories, setSales }) {
  const [modal, setModal] = useState(false);
  const [itemSearch, setItemSearch] = useState("");
  const [showSana, setShowSana] = useState(false);
  const [showIzoh, setShowIzoh] = useState(false);
  const [ustaCard, setUstaCard] = useState(null);
  const [ustaModal, setUstaModal] = useState(false);
  const [ustaForm, setUstaForm] = useState({name:"", note:""});
  const [editUstaName, setEditUstaName] = useState(null); // null = add, string = edit
  const [deleteUstaConfirm, setDeleteUstaConfirm] = useState(null); // o'chiriladigan usta nomi
  const [savedUstas, setSavedUstas] = useState(()=>{ try{const s=localStorage.getItem("shox_savedUstas");return s?JSON.parse(s):[]}catch{return [];} });

  // AI savedUstas ga yozganda real-time yangilanish
  useEffect(()=>{
    const onSaved = () => {
      try{ const s=localStorage.getItem("shox_savedUstas"); if(s) setSavedUstas(JSON.parse(s)); }catch{}
    };
    window.addEventListener("shox_savedUstas_updated", onSaved);
    return ()=>window.removeEventListener("shox_savedUstas_updated", onSaved);
  },[]);
  const saveSavedUstas = u => { setSavedUstas(u); try{localStorage.setItem("shox_savedUstas",JSON.stringify(u));}catch{}; };
  const addUsta = () => {
    if(!ustaForm.name.trim()) return;
    const newName = ustaForm.name.trim();
    if(editUstaName) {
      // Edit mode: rename in savedUstas and in records
      saveSavedUstas(savedUstas.map(u=>u.name===editUstaName?{...u,name:newName,note:ustaForm.note}:u));
      saveRec(records.map(r=>r.ustaName===editUstaName?{...r,ustaName:newName}:r));
      if(ustaCard===editUstaName) setUstaCard(newName);
    } else {
      if(!savedUstas.find(u=>u.name===newName)) saveSavedUstas([...savedUstas,{id:uid(),name:newName,note:ustaForm.note}]);
    }
    setUstaForm({name:"",note:""});
    setEditUstaName(null);
    setUstaModal(false);
  };
  const deleteUsta = (name) => {
    // Ustani savedUstas dan o'chirish
    saveSavedUstas(savedUstas.filter(u => u.name !== name));
    // Ustaning barcha yozuvlarini o'chirish va tovarlarni inventarga qaytarish
    const ustaRecs = records.filter(r => r.ustaName === name);
    ustaRecs.forEach(r => {
      if(r.itemType === "zapchast") setParts(p => p.map(x => x.id===r.itemId ? {...x, count: x.count+(r.qty||0)} : x));
      else setAccessories(a => a.map(x => x.id===r.itemId ? {...x, count: x.count+(r.qty||0)} : x));
    });
    saveRec(records.filter(r => r.ustaName !== name));
    if(ustaCard === name) setUstaCard(null);
    setDeleteUstaConfirm(null);
    showToast("✅ " + name + " o\'chirildi. Tovarlar inventarga qaytdi.");
  };
  const [records, setRecords] = useState(()=>{ try{const s=localStorage.getItem("shox_ustaRecords");return s?JSON.parse(s):[]}catch{return [];} });

  // AI give_to_usta localStorage ga yozganda — real-time yangilanish
  useEffect(()=>{
    const onStorage = (e) => {
      if(e.key==="shox_ustaRecords" && e.newValue){
        try{ setRecords(JSON.parse(e.newValue)); }catch{}
      }
    };
    // Same-tab uchun: custom event
    const onCustom = () => {
      try{ const s=localStorage.getItem("shox_ustaRecords"); if(s) setRecords(JSON.parse(s)); }catch{}
    };
    window.addEventListener("storage", onStorage);
    window.addEventListener("shox_ustaRecords_updated", onCustom);
    return ()=>{ window.removeEventListener("storage", onStorage); window.removeEventListener("shox_ustaRecords_updated", onCustom); };
  },[]);
  const [search, setSearch] = useState("");
  const [filterUsta, setFilterUsta] = useState("Hammasi");
  const [period, setPeriod] = useState("hammasi");
  const [calMode, setCalMode] = useState(false);
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [formItemType, setFormItemType] = useState("zapchast");
  const [form, setForm] = useState({ ustaName:"", itemType:"zapchast", itemId:"", qty:"1", price:"", date:today(), note:"" });
  const sf = k => v => setForm(f=>({...f,[k]:v}));

  const saveRec = r => { setRecords(r); try{localStorage.setItem("shox_ustaRecords",JSON.stringify(r));}catch{} };

  // Period filter
  const inPeriod = (dateStr) => {
    const d = new Date(dateStr||today());
    const n = new Date(); n.setHours(0,0,0,0);
    if(calMode) {
      if(dateFrom&&dateTo) return d>=new Date(dateFrom)&&d<=new Date(dateTo+"T23:59:59");
      if(dateFrom) return d>=new Date(dateFrom);
      if(dateTo)   return d<=new Date(dateTo+"T23:59:59");
      return true;
    }
    if(period==="hammasi") return true;
    if(period==="bugun")   return dateStr===today();
    if(period==="hafta")   { const w=new Date(n); w.setDate(w.getDate()-7); return d>=w; }
    if(period==="oy")      return d.getMonth()===n.getMonth()&&d.getFullYear()===n.getFullYear();
    if(period==="chorak")  { const q=Math.floor(n.getMonth()/3); return d>=new Date(n.getFullYear(),q*3,1)&&d<=new Date(n.getFullYear(),q*3+3,0); }
    if(period==="yarim")   { const h=n.getMonth()<6?0:6; return d>=new Date(n.getFullYear(),h,1)&&d<=new Date(n.getFullYear(),h+6,0); }
    if(period==="yil")     return d.getFullYear()===n.getFullYear();
    return true;
  };
  const periodLabel = () => {
    if(calMode) { if(dateFrom&&dateTo) return `${dateFrom}  -  ${dateTo}`; return "Sana"; }
    return USTA_PERIODS.find(p=>p.k===period)?.l||period;
  };

  const allItemsForForm = formItemType==="zapchast"
    ? parts.map(p=>({id:p.id,name:p.name,count:p.count,buyPrice:p.buyPrice,sellPrice:p.sellPrice}))
    : accessories.map(a=>({id:a.id,name:a.name,count:a.count,buyPrice:a.buyPrice,sellPrice:a.sellPrice}));
  const selectedItem = allItemsForForm.find(i=>i.id===form.itemId);

  const addRecord = () => {
    const ustaName = form.ustaName || ustaCard;
    if(!ustaName||!form.itemId||!form.qty) return;
    const item = selectedItem; if(!item) return;
    const qty = +form.qty;
    const price = +form.price || item.sellPrice;
    const newRec = {id:uid(), ustaName, itemId:form.itemId, itemName:item.name, itemType:formItemType, qty, price, buyPrice:item.buyPrice, profit:(price-item.buyPrice)*qty, date:form.date, note:form.note};
    saveRec([...records, newRec]);
    if(formItemType==="zapchast") setParts(prev=>prev.map(p=>p.id===form.itemId?{...p,count:Math.max(0,p.count-qty)}:p));
    else setAccessories(prev=>prev.map(a=>a.id===form.itemId?{...a,count:Math.max(0,a.count-qty)}:a));
    setSales(prev=>[...prev,{id:uid(),date:form.date,name:item.name,qty,price:price*qty,profit:(price-item.buyPrice)*qty,type:"usta",source:ustaName}]);
    setForm({ustaName:"",itemType:"zapchast",itemId:"",qty:"1",price:"",date:today(),note:""});
    setModal(false);
  };

  const deleteRec = (rec) => {
    saveRec(records.filter(r=>r.id!==rec.id));
    if(rec.itemType==="zapchast") setParts(prev=>prev.map(p=>p.id===rec.itemId?{...p,count:p.count+rec.qty}:p));
    else setAccessories(prev=>prev.map(a=>a.id===rec.itemId?{...a,count:a.count+rec.qty}:a));
  };

  // Filtered records
  const filtRec = records.filter(r=>{
    const q = search.toLowerCase();
    return inPeriod(r.date) &&
      (filterUsta==="Hammasi"||r.ustaName===filterUsta) &&
      (!q||(r.ustaName||"").toLowerCase().includes(q)||(r.itemName||"").toLowerCase().includes(q));
  }).sort((a,b)=>b.date.localeCompare(a.date));

  // Stats
  const periodTotals = {};
  filtRec.forEach(r=>{ periodTotals[r.ustaName]=(periodTotals[r.ustaName]||{qty:0,total:0,profit:0}); periodTotals[r.ustaName].qty+=r.qty; periodTotals[r.ustaName].total+=r.price*r.qty; periodTotals[r.ustaName].profit+=r.profit||0; });
  const allUstaNames = ["Hammasi",...Array.from(new Set(records.map(r=>r.ustaName)))];

  return (
    <div>
      {/* ── TOP PERIOD FILTER ── */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:14, flexWrap:"wrap", gap:10 }}>
        <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
          <div style={{ display:"flex", gap:5, flexWrap:"wrap", alignItems:"center" }}>
            {USTA_PERIODS.map(p=>(
              <button key={p.k} onClick={()=>{setPeriod(p.k);setCalMode(false);}} style={{ padding:"6px 12px", borderRadius:8, fontSize:12, cursor:"pointer", background:!calMode&&period===p.k?T.brand:T.card, color:!calMode&&period===p.k?"#fff":T.muted, border:`1px solid ${!calMode&&period===p.k?T.brand:T.border}`, fontWeight:!calMode&&period===p.k?600:400 }}>{p.l}</button>
            ))}
            <button onClick={()=>setCalMode(v=>!v)} style={{ padding:"6px 12px", borderRadius:8, fontSize:12, cursor:"pointer", display:"flex", alignItems:"center", gap:5, background:calMode?T.infoDim:T.card, color:calMode?T.info:T.muted, border:`1px solid ${calMode?T.info:T.border}` }}>
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
              Sana tanlash
            </button>
          </div>
          {calMode && (
            <div style={{ display:"flex", alignItems:"center", gap:8, background:T.card, border:`1px solid ${T.info}44`, borderRadius:9, padding:"9px 14px", flexWrap:"wrap" }}>
              <span style={{ fontSize:12, color:T.muted }}>Dan:</span>
              <input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"5px 10px", color:T.text, fontSize:12, outline:"none" }} />
              <span style={{ color:T.muted }}>—</span>
              <span style={{ fontSize:12, color:T.muted }}>Gacha:</span>
              <input type="date" value={dateTo} onChange={e=>setDateTo(e.target.value)} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:7, padding:"5px 10px", color:T.text, fontSize:12, outline:"none" }} />
              {(dateFrom||dateTo) && <button onClick={()=>{setDateFrom("");setDateTo("");}} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:6, color:T.muted, cursor:"pointer", padding:"3px 8px", fontSize:11 }}>× Tozalash</button>}
              {dateFrom&&dateTo && <span style={{ fontSize:11, color:T.info, background:T.infoDim, padding:"3px 10px", borderRadius:6, fontWeight:600 }}>{Math.round((new Date(dateTo)-new Date(dateFrom))/(1000*60*60*24))+1} kun</span>}
            </div>
          )}
        </div>
      </div>

      {/* ── PERIOD STATS ── */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:12, marginBottom:20 }}>
        {[
          {label:`${periodLabel()}  -  ustalar`, val:Object.keys(periodTotals).length+" ta", color:T.brand, bg:T.brandDim},
          {label:`${periodLabel()}  -  berilgan`, val:filtRec.reduce((s,r)=>s+r.qty,0)+" dona", color:T.warning, bg:T.warningDim},
          {label:`${periodLabel()}  -  aylanma`, val:fmt(filtRec.reduce((s,r)=>s+(r.price*r.qty||0),0))+" so'm", color:T.success, bg:T.successDim},
          {label:`${periodLabel()}  -  foyda`, val:fmt(filtRec.reduce((s,r)=>s+(r.profit||0),0))+" so'm", color:T.info, bg:T.infoDim},
        ].map((c,i)=>(
          <div key={i} style={{ background:c.bg, border:`1px solid ${c.color}33`, borderRadius:12, padding:"14px 16px" }}>
            <div style={{ fontSize:10, color:c.color, fontWeight:700, marginBottom:5 }}>{c.label.toUpperCase()}</div>
            <div style={{ fontSize:18, fontWeight:900, color:T.text }}>{c.val}</div>
          </div>
        ))}
      </div>

      {/* ── USTALAR KARTOCHKALAR JADVAL ── */}
      <div style={{ marginBottom:12 }}>
        {/* Toolbar: search + Usta qo'shish */}
        <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:16 }}>
          <SearchBar value={search} onChange={setSearch} placeholder="Usta ismi bo'yicha..." />
          <Btn variant="primary" onClick={()=>{setUstaForm({name:"",note:""});setUstaModal(true);}}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/><circle cx="12" cy="7" r="4"/><line x1="19" y1="8" x2="19" y2="14"/><line x1="22" y1="11" x2="16" y2="11"/></svg>
            Usta qo'shish
          </Btn>
        </div>

        {/* All-time unique ustalar — savedUstas + records merged */}
        {(() => {
          const allUstalarMap = {};
          // Add saved ustas (even if no records yet)
          savedUstas.forEach(u => { if(!allUstalarMap[u.name]) allUstalarMap[u.name]={total:0,qty:0,profit:0,count:0,lastDate:"",note:u.note}; });
          // Add from records
          records.forEach(r => {
            if(!allUstalarMap[r.ustaName]) allUstalarMap[r.ustaName]={total:0,qty:0,profit:0,count:0,lastDate:"",note:""};
            allUstalarMap[r.ustaName].total  += r.price*r.qty;
            allUstalarMap[r.ustaName].qty    += r.qty;
            allUstalarMap[r.ustaName].profit += r.profit||0;
            allUstalarMap[r.ustaName].count  += 1;
            if(r.date>allUstalarMap[r.ustaName].lastDate) allUstalarMap[r.ustaName].lastDate=r.date;
          });
          // Period filtered
          const periodMap = {};
          filtRec.forEach(r => {
            if(!periodMap[r.ustaName]) periodMap[r.ustaName]={total:0,qty:0,profit:0,count:0};
            periodMap[r.ustaName].total  += r.price*r.qty;
            periodMap[r.ustaName].qty    += r.qty;
            periodMap[r.ustaName].profit += r.profit||0;
            periodMap[r.ustaName].count  += 1;
          });

          const ustaList = Object.entries(allUstalarMap)
            .filter(([name])=>!search||name.toLowerCase().includes(search.toLowerCase()))
            .sort((a,b)=>b[1].total-a[1].total);

          if(ustaList.length===0) return (
            <div style={{ padding:60, textAlign:"center", color:T.muted, fontSize:14 }}>
              <div style={{ fontSize:40, marginBottom:12 }}>👨‍🔧</div>
              Hali usta qo'shilmagan. "Usta qo'shish" tugmasidan boshlang.
            </div>
          );

          return (
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
              {ustaList.map(([name, allStat])=>{
                const pStat = periodMap[name] || {total:0,qty:0,profit:0,count:0};
                const lastRec = records.filter(r=>r.ustaName===name).sort((a,b)=>b.date.localeCompare(a.date))[0];
                return (
                  <div key={name} onClick={()=>setUstaCard(name)}
                    style={{ background:T.card, border:`1px solid ${T.border}`, borderRadius:12, padding:"14px 16px", cursor:"pointer", height:76, display:"flex", alignItems:"center", justifyContent:"space-between", boxSizing:"border-box" }}
                    onMouseEnter={e=>{e.currentTarget.style.border=`1px solid ${T.brand}`;e.currentTarget.style.background=T.subtle;}}
                    onMouseLeave={e=>{e.currentTarget.style.border=`1px solid ${T.border}`;e.currentTarget.style.background=T.card;}}>
                    {/* Left: avatar + info */}
                    <div style={{ display:"flex", alignItems:"center", gap:10, minWidth:0, flex:1 }}>
                      <div style={{ width:38, height:38, borderRadius:10, background:`linear-gradient(135deg,${T.brand},#0F4A9C)`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:16, fontWeight:900, color:"#fff", flexShrink:0 }}>
                        {name[0]?.toUpperCase()}
                      </div>
                      <div style={{ minWidth:0 }}>
                        <div style={{ fontSize:14, fontWeight:800, color:T.text, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{name}</div>
                        <div style={{ fontSize:11, color:T.muted, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                          {allStat.count>0 ? `${allStat.count} ta · ${fmt(allStat.total)} so'm` : "Tovar berilmagan"}
                        </div>
                      </div>
                    </div>
                    {/* Right: edit + arrow */}
                    <div style={{ display:"flex", alignItems:"center", gap:6, flexShrink:0 }}>
                      <div onClick={e=>e.stopPropagation()}>
                        <button title="Tahrirlash" onClick={()=>{ setUstaForm({name,note:savedUstas.find(u=>u.name===name)?.note||""}); setEditUstaName(name); setUstaModal(true); }} style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:6, color:T.muted, cursor:"pointer", padding:"4px 8px", fontSize:12 }}>✎</button>
                        <button title="O'chirishirish" onClick={()=>setDeleteUstaConfirm(name)} style={{ background:"rgba(239,68,68,0.12)", border:"1px solid rgba(239,68,68,0.3)", borderRadius:6, color:"#ef4444", cursor:"pointer", padding:"4px 8px", fontSize:12 }}>🗑</button>
                      </div>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={T.muted} strokeWidth="2"><path d="M9 18l6-6-6-6"/></svg>
                    </div>
                  </div>
                );
              })}
            </div>
          );
        })()}
      </div>

      {/* ── USTA TO'LIQ OYNASI ── */}
      {ustaCard && (()=>{
        const allURec = records.filter(r=>r.ustaName===ustaCard).sort((a,b)=>b.date.localeCompare(a.date));

        return (
          <div style={{ position:"fixed", inset:0, zIndex:100, background:T.bg, display:"flex", flexDirection:"column", overflow:"hidden" }}>
            {/* Header */}
            <div style={{ background:T.surface, borderBottom:`1px solid ${T.border}`, padding:"14px 24px", display:"flex", alignItems:"center", justifyContent:"space-between", flexShrink:0 }}>
              <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                <button onClick={()=>setUstaCard(null)} style={{ background:T.card, border:`1px solid ${T.border}`, borderRadius:9, color:T.muted, cursor:"pointer", padding:"7px 12px", fontSize:13, display:"flex", alignItems:"center", gap:6 }}>
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>
                  Orqaga
                </button>
                <div style={{ width:42, height:42, borderRadius:12, background:`linear-gradient(135deg,${T.brand},#0F4A9C)`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:18, fontWeight:900, color:"#fff" }}>
                  {ustaCard[0]?.toUpperCase()}
                </div>
                <div>
                  <div style={{ fontSize:17, fontWeight:900, color:T.text }}>{ustaCard}</div>
                  <div style={{ fontSize:11, color:T.muted }}>{allURec.length} ta yozuv · Oxirgi: {allURec[0]?.date||"—"}</div>
                </div>
              </div>
              <Btn variant="primary" onClick={()=>{setForm(f=>({...f,ustaName:ustaCard,itemId:"",qty:"1",price:"",note:"",date:today()}));setFormItemType("zapchast");setItemSearch("");setShowSana(false);setShowIzoh(false);setModal(true);}}>
                + Tovar berish
              </Btn>
            </div>

            {/* Content */}
            <UstaDetailContent
              ustaCard={ustaCard} allURec={allURec}
              records={records} saveRec={saveRec}
              setParts={setParts} setAccessories={setAccessories}
              parts={parts} accessories={accessories}
            />
          </div>
        );
      })()}

      {/* ── MODAL (Tovar berish) ── */}
      <Modal open={modal} onClose={()=>setModal(false)} title={`Tovar berish${ustaCard?"  -  "+ustaCard:""}`}>
        {(() => {
          // Filtered items with search
          const allI = formItemType==="zapchast"
            ? parts.map(p=>({id:p.id,name:p.name,count:p.count,buyPrice:p.buyPrice,sellPrice:p.sellPrice}))
            : accessories.map(a=>({id:a.id,name:a.name,count:a.count,buyPrice:a.buyPrice,sellPrice:a.sellPrice}));
          const q = itemSearch.toLowerCase();
          const searchFiltered = allI.filter(i=>i.count>0 && (!q || i.name.toLowerCase().includes(q) || i.name.replace(/\s/g,"").toLowerCase().includes(q.replace(/\s/g,""))));
          const selItem = allI.find(i=>i.id===form.itemId);
          const effectivePrice = +form.price || selItem?.sellPrice || 0;
          const jami = effectivePrice * +form.qty;

          return (
            <div style={{ display:"flex", flexDirection:"column", gap:11 }}>
              {/* Type toggle */}
              <div style={{ display:"flex", gap:6 }}>
                {[{k:"zapchast",l:"Zapchast"},{k:"aksessuar",l:"Aksessuar"}].map(t=>(
                  <button key={t.k} onClick={()=>{setFormItemType(t.k);sf("itemId")("");setItemSearch("");}} style={{ flex:1, padding:"7px", borderRadius:8, cursor:"pointer", background:formItemType===t.k?T.brand:T.surface, color:formItemType===t.k?"#fff":T.muted, border:`1px solid ${formItemType===t.k?T.brand:T.border}`, fontSize:13, fontWeight:formItemType===t.k?600:400 }}>{t.l}</button>
                ))}
              </div>

              {/* Search */}
              <div style={{ position:"relative" }}>
                <div style={{ display:"flex", alignItems:"center", gap:8, background:T.surface, border:`1px solid ${T.border}`, borderRadius:9, padding:"8px 12px" }}>
                  <svg width="13" height="13" viewBox="0 0 16 16" fill="none"><circle cx="6.5" cy="6.5" r="5" stroke={T.muted} strokeWidth="1.5"/><line x1="10.5" y1="10.5" x2="14" y2="14" stroke={T.muted} strokeWidth="1.5" strokeLinecap="round"/></svg>
                  <input value={itemSearch} onChange={e=>setItemSearch(e.target.value)} placeholder="Tovar qidirish (harf, raqam)..." style={{ background:"none", border:"none", outline:"none", color:T.text, fontSize:13, flex:1 }} />
                  {itemSearch && <button onClick={()=>setItemSearch("")} style={{ background:"none", border:"none", color:T.muted, cursor:"pointer", fontSize:16, lineHeight:1 }}>×</button>}
                </div>
                {/* Dropdown results */}
                {itemSearch && (
                  <div style={{ position:"absolute", top:"calc(100% + 4px)", left:0, right:0, background:T.card, border:`1px solid ${T.borderStrong}`, borderRadius:10, zIndex:10, maxHeight:200, overflowY:"auto", boxShadow:"0 8px 24px rgba(0,0,0,0.4)" }}>
                    {searchFiltered.length===0
                      ? <div style={{ padding:"12px 16px", color:T.muted, fontSize:12 }}>Tovar topilmadi</div>
                      : searchFiltered.map(i=>(
                        <div key={i.id} onClick={()=>{sf("itemId")(i.id);sf("price")(String(i.sellPrice));setItemSearch("");}} style={{ padding:"10px 14px", cursor:"pointer", display:"flex", justifyContent:"space-between", alignItems:"center", borderBottom:`1px solid ${T.border}` }}
                          onMouseEnter={e=>e.currentTarget.style.background=T.surface}
                          onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                          <div>
                            <div style={{ fontSize:13, color:T.text, fontWeight:500 }}>{i.name}</div>
                            <div style={{ fontSize:11, color:T.muted }}>Mavjud: <span style={{ color:stockColor(i.count) }}>{i.count} ta</span></div>
                          </div>
                          <div style={{ fontSize:12, color:T.success, fontWeight:700 }}>{fmt(i.sellPrice)}</div>
                        </div>
                      ))
                    }
                  </div>
                )}
              </div>

              {/* Selected item display */}
              {selItem && (
                <div style={{ background:T.brandDim, border:`1px solid ${T.brand}44`, borderRadius:9, padding:"10px 14px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                  <div>
                    <div style={{ fontSize:13, fontWeight:700, color:T.text }}>{selItem.name}</div>
                    <div style={{ fontSize:11, color:T.muted }}>Mavjud: <span style={{ color:stockColor(selItem.count) }}>{selItem.count} ta</span></div>
                  </div>
                  <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                    <div style={{ fontSize:13, color:T.success, fontWeight:700 }}>{fmt(selItem.sellPrice)} so’m</div>
                    <button onClick={()=>sf("itemId")("")} style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:6, color:T.muted, cursor:"pointer", padding:"3px 8px", fontSize:12 }}>×</button>
                  </div>
                </div>
              )}

              {/* Miqdor + (optional) Narx */}
              <div style={{ display:"grid", gridTemplateColumns: "1fr 1fr", gap:10 }}>
                <div>
                  <div style={{ fontSize:11, color:T.muted, marginBottom:5, fontWeight:500 }}>MIQDOR *</div>
                  <input value={form.qty} onChange={e=>sf("qty")(e.target.value)} type="number" min="1" style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:14, fontWeight:700, outline:"none", boxSizing:"border-box" }} />
                </div>
                <div>
                  <div style={{ fontSize:11, color:T.muted, marginBottom:5, fontWeight:500, display:"flex", justifyContent:"space-between" }}>
                    <span>NARX (so’m)</span>
                    <span style={{ fontSize:10, color:T.brand, cursor:"pointer" }} onClick={()=>selItem&&sf("price")("")}>
                      {form.price ? "× Tozalash" : `Auto: ${fmt(selItem?.sellPrice||0)}`}
                    </span>
                  </div>
                  <input value={form.price} onChange={e=>sf("price")(e.target.value)} type="number" placeholder={selItem?String(selItem.sellPrice):"0"} style={{ width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box" }} />
                </div>
              </div>

              {/* Jami preview */}
              {selItem && +form.qty>0 && (
                <div style={{ background:T.successDim, border:`1px solid ${T.success}33`, borderRadius:8, padding:"9px 14px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                  <span style={{ fontSize:12, color:T.success, fontWeight:600 }}>JAMI</span>
                  <span style={{ fontSize:16, fontWeight:900, color:T.success }}>{fmt(jami)} so’m</span>
                </div>
              )}

              {/* Collapsible: Sana */}
              <div>
                <button onClick={()=>setShowSana(v=>!v)} style={{ background:"none", border:"none", color:T.muted, cursor:"pointer", fontSize:12, display:"flex", alignItems:"center", gap:5, padding:0 }}>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={{ transform:showSana?"rotate(90deg)":"rotate(0)", transition:"0.15s" }}><path d="M9 18l6-6-6-6"/></svg>
                  Sana {showSana?"":"(bugun)"}
                </button>
                {showSana && (
                  <input type="date" value={form.date} onChange={e=>sf("date")(e.target.value)} style={{ marginTop:6, width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box" }} />
                )}
              </div>

              {/* Collapsible: Izoh */}
              <div>
                <button onClick={()=>setShowIzoh(v=>!v)} style={{ background:"none", border:"none", color:T.muted, cursor:"pointer", fontSize:12, display:"flex", alignItems:"center", gap:5, padding:0 }}>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={{ transform:showIzoh?"rotate(90deg)":"rotate(0)", transition:"0.15s" }}><path d="M9 18l6-6-6-6"/></svg>
                  Izoh {showIzoh?"":"(ixtiyoriy)"}
                </button>
                {showIzoh && (
                  <input value={form.note} onChange={e=>sf("note")(e.target.value)} placeholder="Remont uchun, almashtirish uchun..." style={{ marginTop:6, width:"100%", background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"8px 12px", color:T.text, fontSize:13, outline:"none", boxSizing:"border-box" }} />
                )}
              </div>

              {/* Actions */}
              <div style={{ display:"flex", gap:10, marginTop:4 }}>
                <Btn variant="primary" onClick={addRecord} style={{ flex:1 }}>Berish ✓</Btn>
                <Btn onClick={()=>setModal(false)} style={{ flex:1 }}>Bekor</Btn>
              </div>
            </div>
          );
        })()}
      </Modal>
      {/* ── USTA QO'SHISH / TAHRIRLASH MODAL ── */}
      {/* ── USTANI O'CHIRISH CONFIRMATION ── */}
      {deleteUstaConfirm && (
        <div style={{ position:"fixed", inset:0, zIndex:9999, background:"rgba(0,0,0,0.65)", display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
          <div style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:16, padding:28, maxWidth:380, width:"100%", boxShadow:"0 20px 60px rgba(0,0,0,0.4)" }}>
            {/* Icon */}
            <div style={{ textAlign:"center", marginBottom:16 }}>
              <div style={{ width:60, height:60, background:"rgba(239,68,68,0.12)", borderRadius:"50%", display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 12px", fontSize:28 }}>🗑</div>
              <div style={{ fontSize:17, fontWeight:800, color:T.text, marginBottom:6 }}>Ustani o'chirish</div>
              <div style={{ fontSize:13, color:T.muted, lineHeight:1.5 }}>
                <span style={{ color:"#ef4444", fontWeight:700 }}>{deleteUstaConfirm}</span> ni o'chirishni tasdiqlaysizmi?
              </div>
            </div>
            {/* Warning box */}
            <div style={{ background:"rgba(239,68,68,0.08)", border:"1px solid rgba(239,68,68,0.25)", borderRadius:10, padding:"10px 14px", marginBottom:20 }}>
              <div style={{ fontSize:12, color:"#ef4444", fontWeight:600, marginBottom:4 }}>⚠️ Diqqat!</div>
              <div style={{ fontSize:12, color:T.muted, lineHeight:1.5 }}>
                • Ustaning barcha yozuvlari o'chiriladi<br/>
                • Berilgan tovarlar inventarga qaytariladi<br/>
                • Bu amalni ortga qaytarib bo'lmaydi
              </div>
            </div>
            {/* Buttons */}
            <div style={{ display:"flex", gap:10 }}>
              <button onClick={()=>setDeleteUstaConfirm(null)} style={{ flex:1, padding:"11px 0", borderRadius:10, background:T.bg, border:`1px solid ${T.border}`, color:T.text, cursor:"pointer", fontSize:14, fontWeight:600 }}>
                Bekor
              </button>
              <button onClick={()=>deleteUsta(deleteUstaConfirm)} style={{ flex:1, padding:"11px 0", borderRadius:10, background:"#ef4444", border:"none", color:"#fff", cursor:"pointer", fontSize:14, fontWeight:700 }}>
                🗑 O'chirish
              </button>
            </div>
          </div>
        </div>
      )}

      <Modal open={ustaModal} onClose={()=>{setUstaModal(false);setEditUstaName(null);}} title={editUstaName ? "Ustani tahrirlash" : "Yangi usta qo'shish"}>
        <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
          {!editUstaName && <div style={{ background:T.brandDim, border:`1px solid ${T.brand}33`, borderRadius:8, padding:"9px 14px", fontSize:12, color:T.brand }}>
            Usta qo'shilgach uning kartochkasiga bosib to'liq statistikasini ko'rishingiz mumkin
          </div>}
          <Inp label="Usta ismi *" value={ustaForm.name} onChange={v=>setUstaForm(f=>({...f,name:v}))} placeholder="Ibrohim usta, Sardor..." />
          <Inp label="Izoh (ixtiyoriy)" value={ustaForm.note} onChange={v=>setUstaForm(f=>({...f,note:v}))} placeholder="Qo'shimcha ma'lumot..." />
          <div style={{ display:"flex", gap:10, marginTop:4 }}>
            <Btn variant="primary" onClick={addUsta} style={{ flex:1 }}>{editUstaName?"Saqlash ✓":"Qo'shish"}</Btn>
            <Btn onClick={()=>{setUstaModal(false);setEditUstaName(null);}} style={{ flex:1 }}>Bekor</Btn>
          </div>
        </div>
      </Modal>
    </div>
  );
}
// ── STATISTIKA ─────────────────────────────────────────────────────────────────
const STAT_PERIODS = [
  {k:"bugun",l:"Bugun"},{k:"hafta",l:"Hafta"},{k:"oy",l:"Bu oy"},
  {k:"chorak",l:"Chorak"},{k:"yarim",l:"Yarim yil"},{k:"yil",l:"Bu yil"},{k:"hammasi",l:"Hammasi"}
];

function CustomTooltip({active,payload,label}){
  if(!active||!payload?.length)return null;
  return(<div style={{background:T.card,border:`1px solid ${T.border}`,borderRadius:9,padding:"10px 14px",fontSize:12}}>
    <div style={{fontWeight:700,color:T.text,marginBottom:5}}>{label}</div>
    {payload.map((p,i)=><div key={i} style={{color:p.color||p.fill,marginTop:2}}>{p.name}: {p.value}K som</div>)}
  </div>);
}

class StatsErrorBoundary extends React.Component {
  constructor(props){super(props);this.state={error:null};}
  static getDerivedStateFromError(e){return{error:e};}
  render(){
    if(this.state.error) return(
      <div style={{padding:40,textAlign:"center"}}>
        <div style={{fontSize:32,marginBottom:12}}>⚠️</div>
        <div style={{fontSize:15,fontWeight:700,color:"#ef4444",marginBottom:8}}>Statistika yuklashda xato</div>
        <div style={{fontSize:12,color:"#888",marginBottom:16,fontFamily:"monospace"}}>{this.state.error?.message}</div>
        <button onClick={()=>this.setState({error:null})} style={{padding:"8px 20px",borderRadius:8,background:"#1A6FD4",border:"none",color:"#fff",cursor:"pointer"}}>Qayta urinish</button>
      </div>
    );
    return this.props.children;
  }
}


// ── STATISTIKA SUB-COMPONENTS ────────────────────────────────────────────────


// ── GLOBAL CONFIG HOOK ──────────────────────────────────────────────────────
function useShoxConfig() {
  const DEFAULT_CONFIG = {
    partTypes:    ["Ekran (AMOLED Original)","Ekran (AMOLED Copy A)","Ekran (LCD Original)","Ekran (LCD Copy)","Ekran + rama komplekt","Sensor (touch shisha)","Batareya (Original)","Batareya (Copy)","Orqa qopqoq (Original)","Orqa qopqoq (Copy)","O'rta rama (middle frame)","Kamera asosiy (rear)","Kamera old (front/selfie)","Kamera ultra wide","Kamera linzasi (steklo)","Dinamik (loudspeaker)","Quloqchin (earpiece)","Mikrofon","Zaryad ulagich (USB-C)","Zaryad platasi (sub board)","Barmoq izi sensori","Vibro motor","Tugma (power)","Tugma (volume)","SIM лоток","Boshqa"],
    partBrands:   ["Apple","Samsung","Xiaomi","Huawei","Oppo","Vivo","Realme","Nokia","Boshqa"],
    accCategories:["Chexol","Kabel","Quloqchin","Zaryadlovchi","Qo'riqlovchi shisha","Power bank","Bluetooth kolonka","Selfie tayoq","Boshqa"],
    priceSegments:[
      {label:"Arzon",    min:0,      max:50000},
      {label:"Qulay",    min:50000,  max:150000},
      {label:"O'rta",    min:150000, max:300000},
      {label:"Qimmat",   min:300000, max:600000},
      {label:"Premium",  min:600000, max:99999999},
    ],
    defaultPeriod:"oy",
    topN:10,
    lowStockThreshold:5,
  };

  const [config, setConfig] = React.useState(()=>{
    try{
      const s=localStorage.getItem("shox_config");
      if(s){
        const saved=JSON.parse(s);
        return {...DEFAULT_CONFIG,...saved,
          priceSegments:saved.priceSegments||DEFAULT_CONFIG.priceSegments};
      }
    }catch{}
    return DEFAULT_CONFIG;
  });

  const saveConfig = (newCfg) => {
    setConfig(newCfg);
    try{localStorage.setItem("shox_config",JSON.stringify(newCfg));}catch{}
  };

  const addItem = (field,val) => {
    val=val.trim();
    if(!val||config[field].includes(val)) return false;
    saveConfig({...config,[field]:[...config[field],val]});
    return true;
  };

  const removeItem = (field,val) => {
    saveConfig({...config,[field]:config[field].filter(x=>x!==val)});
  };

  const renameItem = (field,oldVal,newVal) => {
    newVal=newVal.trim();
    if(!newVal||config[field].includes(newVal)) return false;
    saveConfig({...config,[field]:config[field].map(x=>x===oldVal?newVal:x)});
    return true;
  };

  const updateSegment = (i,field,val) => {
    const segs=[...config.priceSegments];
    segs[i]={...segs[i],[field]:+val};
    saveConfig({...config,priceSegments:segs});
  };

  const addSegment = () => {
    const last=config.priceSegments[config.priceSegments.length-1];
    const newSeg={label:"Yangi",min:last?last.max:0,max:(last?last.max:0)+100000};
    saveConfig({...config,priceSegments:[...config.priceSegments,newSeg]});
  };

  const removeSegment = (i) => {
    if(config.priceSegments.length<=2) return;
    const segs=config.priceSegments.filter((_,j)=>j!==i);
    saveConfig({...config,priceSegments:segs});
  };

  const resetToDefault = () => { saveConfig(DEFAULT_CONFIG); };

  return {config,saveConfig,addItem,removeItem,renameItem,updateSegment,addSegment,removeSegment,resetToDefault};
}

