    // Sensor/Touch
    "sensor":"sensor touch","тачскрин":"touchscreen","tachskrin":"sensor",
    "takchskrin":"sensor","touch":"touch sensor","sensorcha":"sensor",
    // SIM/Lоток
    "lotok":"sim lotok","лоток":"sim lotok","sim lotok":"sim lotok",
    "simka":"sim karta","simkarta":"sim karta","сим":"sim",
