    "power bank":"power bank","пауэрбанк":"power bank","zaryadlovchi batareya":"power bank",
    "kolonochka":"bluetooth kolonka","blyutuz kolonka":"bluetooth kolonka",
    "zashhitnoe steklo":"himoya shisha","plenka":"himoya shisha","защита":"himoya shisha",
